fn make_linear_mesh(n: u32) -> NavMesh {
    let mut mesh = NavMesh::new();
    for i in 0..n {
        let x = i as f32 * 2.0;
        let mut neighbors = Vec::new();
        if i > 0 {
            neighbors.push(NavPolyId(i - 1));
        }
        if i < n - 1 {
            neighbors.push(NavPolyId(i + 1));
        }
        mesh.add_poly(NavPoly {
            id: NavPolyId(i),
            vertices: vec![
                Vec2::new(x, 0.0),
                Vec2::new(x + 2.0, 0.0),
                Vec2::new(x + 2.0, 2.0),
                Vec2::new(x, 2.0),
            ],
            neighbors,
            cost: 1.0,
            layer: 0,
        });
    }
    mesh
}

