//! Basic pathfinding example.

use raasta::{GridPos, NavGrid};

fn main() {
    // Create a 20x20 grid
    let mut grid = NavGrid::new(20, 20, 1.0);

    // Add some walls
    for y in 0..15 {
        grid.set_walkable(10, y, false);
    }
    for x in 5..20 {
        grid.set_walkable(x, 15, false);
    }

    // Find a path
    let start = GridPos::new(0, 0);
    let goal = GridPos::new(19, 19);

    match grid.find_path(start, goal) {
        Some(path) => {
            println!("Path found! {} steps", path.len());
            for (i, pos) in path.iter().enumerate() {
                let w = grid.grid_to_world(*pos);
                println!(
                    "  [{i}] grid({}, {}) -> world({:.1}, {:.1})",
                    pos.x, pos.y, w.x, w.y
                );
            }
        }
        None => println!("No path found!"),
    }
}

//! Agent — ties position, velocity, path following, and steering together.

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::follow::PathFollower;
use crate::steer::{Obstacle, SteerOutput, avoid_obstacles};

/// A navigation agent with position, velocity, and optional path following.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Agent {
    pub position: Vec2,
    pub velocity: Vec2,
    pub max_speed: f32,
    pub max_force: f32,
    follower: Option<PathFollower>,
}

impl Agent {
    /// Create a new agent at the given position.
    #[must_use]
    #[cfg_attr(feature = "logging", tracing::instrument)]
    pub fn new(position: Vec2, max_speed: f32, max_force: f32) -> Self {
        Self {
            position,
            velocity: Vec2::ZERO,
            max_speed,
            max_force,
            follower: None,
        }
    }

    /// Assign a path for this agent to follow.
    #[cfg_attr(feature = "logging", tracing::instrument(skip(self)))]
    pub fn set_path(&mut self, follower: PathFollower) {
        self.follower = Some(follower);
    }

    /// Clear the current path.
    #[cfg_attr(feature = "logging", tracing::instrument(skip(self)))]
    pub fn clear_path(&mut self) {
        self.follower = None;
    }

    /// Whether the agent has an active (unfinished) path.
    #[must_use]
    #[cfg_attr(feature = "logging", tracing::instrument(skip(self)))]
    pub fn has_path(&self) -> bool {
        self.follower.as_ref().is_some_and(|f| !f.is_finished())
    }

    /// Reference to the path follower, if any.
    #[must_use]
    pub fn follower(&self) -> Option<&PathFollower> {
        self.follower.as_ref()
    }

    /// Update the agent for one tick.
    ///
    /// Computes path-following steering, applies velocity, and moves the agent.
    /// Pass `dt` as the time step (seconds). Returns the steering output used.
    pub fn update(&mut self, dt: f32, obstacles: &[Obstacle]) -> SteerOutput {
        // Path following steering
        let path_steer = match self.follower.as_mut() {
            Some(f) if !f.is_finished() => f.steer(self.position, self.max_speed),
            _ => SteerOutput::default(),
        };

        // Obstacle avoidance
        let avoid_steer = if !obstacles.is_empty() && self.velocity.length_squared() > f32::EPSILON
        {
            let look_ahead = self.max_speed * 2.0;
            avoid_obstacles(
                self.position,
                self.velocity,
                obstacles,
                look_ahead,
                self.max_force,
            )
        } else {
            SteerOutput::default()
        };

        // Combine forces: path following + avoidance
        let combined = path_steer.velocity + avoid_steer.velocity;

        // Truncate to max force
        let combined_len = combined.length();
        let force = if combined_len > self.max_force {
            combined * (self.max_force / combined_len)
        } else {
            combined
        };

        // Direct velocity steering — set velocity from force direction
        // (rather than accumulating force, which causes overshoot)
        if force.length() > f32::EPSILON {
            self.velocity = force;
        } else {
            self.velocity = Vec2::ZERO;
        }

        // Clamp to max speed
        let speed = self.velocity.length();
        if speed > self.max_speed {
            self.velocity = self.velocity / speed * self.max_speed;
        }

        // Move
        self.position += self.velocity * dt;

        SteerOutput::from_vec2(force)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn agent_creation() {
        let a = Agent::new(Vec2::ZERO, 5.0, 10.0);
        assert_eq!(a.position, Vec2::ZERO);
        assert_eq!(a.velocity, Vec2::ZERO);
        assert!(!a.has_path());
    }

    #[test]
    fn agent_set_path() {
        let mut a = Agent::new(Vec2::ZERO, 5.0, 10.0);
        let f = PathFollower::new(vec![Vec2::new(10.0, 0.0)], 0.5, 2.0);
        a.set_path(f);
        assert!(a.has_path());
    }

    #[test]
    fn agent_clear_path() {
        let mut a = Agent::new(Vec2::ZERO, 5.0, 10.0);
        a.set_path(PathFollower::new(vec![Vec2::new(10.0, 0.0)], 0.5, 2.0));
        a.clear_path();
        assert!(!a.has_path());
    }

    #[test]
    fn agent_moves_toward_target() {
        let mut a = Agent::new(Vec2::ZERO, 5.0, 10.0);
        a.set_path(PathFollower::new(vec![Vec2::new(10.0, 0.0)], 0.5, 2.0));

        for _ in 0..100 {
            a.update(0.1, &[]);
        }

        // Should have moved toward (10, 0)
        assert!(a.position.x > 5.0);
    }

    #[test]
    fn agent_reaches_target() {
        let mut a = Agent::new(Vec2::ZERO, 10.0, 20.0);
        a.set_path(PathFollower::new(vec![Vec2::new(5.0, 0.0)], 0.5, 2.0));

        for _ in 0..200 {
            a.update(0.05, &[]);
            if !a.has_path() {
                break;
            }
        }

        assert!(a.position.distance(Vec2::new(5.0, 0.0)) < 1.0);
    }

    #[test]
    fn agent_no_path_stays_still() {
        let mut a = Agent::new(Vec2::new(3.0, 3.0), 5.0, 10.0);
        a.update(0.1, &[]);
        // No path — no force — stays still (velocity starts at zero)
        assert!(a.position.distance(Vec2::new(3.0, 3.0)) < f32::EPSILON);
    }

    #[test]
    fn agent_avoids_obstacle() {
        let mut a = Agent::new(Vec2::ZERO, 5.0, 10.0);
        a.set_path(PathFollower::new(vec![Vec2::new(20.0, 0.0)], 0.5, 2.0));

        let obstacle = Obstacle {
            center: Vec2::new(5.0, 0.0),
            radius: 2.0,
        };

        // Run for a while with obstacle avoidance
        for _ in 0..200 {
            a.update(0.05, &[obstacle]);
        }

        // Should have moved past the obstacle (x > 5) and deviated laterally
        assert!(a.position.x > 5.0);
    }

    #[test]
    fn agent_speed_clamped() {
        let mut a = Agent::new(Vec2::ZERO, 5.0, 100.0);
        a.set_path(PathFollower::new(vec![Vec2::new(100.0, 0.0)], 0.5, 2.0));

        // Big force, small max_speed — should clamp
        for _ in 0..10 {
            a.update(0.1, &[]);
        }
        assert!(a.velocity.length() <= 5.0 + f32::EPSILON);
    }

    #[test]
    fn agent_serde_roundtrip() {
        let mut a = Agent::new(Vec2::new(1.0, 2.0), 5.0, 10.0);
        a.set_path(PathFollower::new(vec![Vec2::new(10.0, 0.0)], 0.5, 2.0));

        let json = serde_json::to_string(&a).unwrap();
        let deserialized: Agent = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.position, Vec2::new(1.0, 2.0));
        assert!(deserialized.has_path());
    }

    #[test]
    fn agent_multi_waypoint() {
        let mut a = Agent::new(Vec2::ZERO, 10.0, 20.0);
        a.set_path(PathFollower::new(
            vec![
                Vec2::new(5.0, 0.0),
                Vec2::new(5.0, 5.0),
                Vec2::new(10.0, 5.0),
            ],
            1.0,
            2.0,
        ));

        for _ in 0..1000 {
            a.update(0.02, &[]);
            if !a.has_path() {
                break;
            }
        }

        // Should be near the final waypoint
        assert!(a.position.distance(Vec2::new(10.0, 5.0)) < 3.0);
    }
}

//! Path request batching — queue and process pathfinding requests with per-frame budgets.

use std::cmp::Ordering;
use std::collections::BinaryHeap;

use serde::{Deserialize, Serialize};

use crate::grid::{GridPos, NavGrid};
use crate::incremental::{IncrementalGridPath, IncrementalStatus};
use crate::path::PathResult;

#[cfg(feature = "logging")]
use tracing::instrument;

/// Unique identifier for a batched path request.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct PathRequestId(pub u32);

/// Priority level for a path request (lower number = higher priority).
#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Serialize, Deserialize)]
pub struct RequestPriority(pub u32);

/// A queued path request with priority.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct QueuedRequest {
    /// Unique request ID.
    pub id: PathRequestId,
    /// Start grid position.
    pub start: GridPos,
    /// Goal grid position.
    pub goal: GridPos,
    /// Priority (lower = processed first).
    pub priority: RequestPriority,
}

/// Internal entry for the priority queue.
struct PendingEntry {
    id: PathRequestId,
    priority: RequestPriority,
}

impl PartialEq for PendingEntry {
    fn eq(&self, other: &Self) -> bool {
        self.priority == other.priority
    }
}

impl Eq for PendingEntry {}

impl PartialOrd for PendingEntry {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for PendingEntry {
    fn cmp(&self, other: &Self) -> Ordering {
        // Reversed: lower priority number = higher heap priority
        other.priority.cmp(&self.priority)
    }
}

/// A completed path result with its request ID.
#[derive(Debug, Clone)]
pub struct BatchedResult {
    /// The request ID this result belongs to.
    pub id: PathRequestId,
    /// The computed path result.
    pub result: PathResult,
}

/// Batched path request processor.
///
/// Queues pathfinding requests with priorities and processes them
/// within a per-frame iteration budget. Higher-priority requests
/// are processed first. Each request uses incremental (time-sliced)
/// A* so it can be spread across multiple frames.
///
/// # Example
///
/// ```ignore
/// let mut batcher = PathBatcher::new();
///
/// // Queue requests
/// batcher.enqueue(GridPos::new(0, 0), GridPos::new(99, 99), RequestPriority(0), &grid);
/// batcher.enqueue(GridPos::new(10, 10), GridPos::new(50, 50), RequestPriority(1), &grid);
///
/// // Each frame, process with budget
/// let completed = batcher.process(&grid, 200);
/// for result in &completed {
///     println!("Request {} completed: {:?}", result.id.0, result.result.status);
/// }
/// ```
#[derive(Debug)]
pub struct PathBatcher {
    /// Priority queue of pending request IDs.
    pending: BinaryHeap<PendingEntry>,
    /// Active queries being computed (request_id -> incremental query).
    active: Vec<(PathRequestId, IncrementalGridPath)>,
    /// Queued requests waiting to become active.
    queued: Vec<QueuedRequest>,
    /// Maximum concurrent active queries.
    max_active: usize,
    /// Next request ID.
    next_id: u32,
}

// Manual Debug for PendingEntry since it's not derived
impl std::fmt::Debug for PendingEntry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("PendingEntry")
            .field("id", &self.id)
            .field("priority", &self.priority)
            .finish()
    }
}

impl PathBatcher {
    /// Create a new batcher with default settings.
    ///
    /// `max_active` defaults to 4, limiting how many queries can be computed concurrently.
    /// Remaining queued requests wait until an active slot opens.
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn new() -> Self {
        Self {
            pending: BinaryHeap::new(),
            active: Vec::new(),
            queued: Vec::new(),
            max_active: 4,
            next_id: 0,
        }
    }

    /// Create a batcher with a custom concurrent query limit.
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn with_max_active(max_active: usize) -> Self {
        Self {
            pending: BinaryHeap::new(),
            active: Vec::new(),
            queued: Vec::new(),
            max_active: max_active.max(1),
            next_id: 0,
        }
    }

    /// Queue a new pathfinding request.
    ///
    /// Returns the request ID. The request will be processed when
    /// `process()` is called, in priority order.
    ///
    /// Returns `None` if start or goal is unwalkable.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    pub fn enqueue(
        &mut self,
        start: GridPos,
        goal: GridPos,
        priority: RequestPriority,
        grid: &NavGrid,
    ) -> Option<PathRequestId> {
        // Validate start/goal
        if !grid.is_walkable(start.x, start.y) || !grid.is_walkable(goal.x, goal.y) {
            return None;
        }

        let id = PathRequestId(self.next_id);
        self.next_id += 1;

        self.queued.push(QueuedRequest {
            id,
            start,
            goal,
            priority,
        });

        self.pending.push(PendingEntry { id, priority });

        Some(id)
    }

    /// Cancel a pending request. Returns `true` if the request was found and removed.
    pub fn cancel(&mut self, id: PathRequestId) -> bool {
        // Remove from queued
        if let Some(pos) = self.queued.iter().position(|r| r.id == id) {
            self.queued.swap_remove(pos);
            return true;
        }
        // Remove from active
        if let Some(pos) = self.active.iter().position(|(rid, _)| *rid == id) {
            self.active.swap_remove(pos);
            return true;
        }
        false
    }

    /// Number of pending + active requests.
    #[must_use]
    pub fn request_count(&self) -> usize {
        self.queued.len() + self.active.len()
    }

    /// Number of currently active (being computed) queries.
    #[must_use]
    pub fn active_count(&self) -> usize {
        self.active.len()
    }

    /// Number of queued (waiting) requests.
    #[must_use]
    pub fn queued_count(&self) -> usize {
        self.queued.len()
    }

    /// Process queued requests within an iteration budget.
    ///
    /// `max_iterations` is the total A* node expansion budget for this frame,
    /// distributed among active queries. Higher-priority queries get budget first.
    ///
    /// Returns a list of completed results from this frame.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    pub fn process(&mut self, grid: &NavGrid, max_iterations: u32) -> Vec<BatchedResult> {
        // Promote queued requests to active
        self.promote_queued(grid);

        if self.active.is_empty() {
            return Vec::new();
        }

        let mut completed = Vec::new();
        let mut remaining_budget = max_iterations;

        // Distribute budget: give each active query a fair share
        let per_query = (remaining_budget / self.active.len() as u32).max(1);

        let mut i = 0;
        while i < self.active.len() {
            if remaining_budget == 0 {
                break;
            }

            let budget = per_query.min(remaining_budget);
            let (id, ref mut query) = self.active[i];
            let status = query.step(grid, budget);
            remaining_budget = remaining_budget.saturating_sub(budget);

            match status {
                IncrementalStatus::Found | IncrementalStatus::NotFound => {
                    let result = query.to_path_result(grid);
                    completed.push(BatchedResult { id, result });
                    self.active.swap_remove(i);
                    // Don't increment i — swap_remove moved the last element here
                }
                IncrementalStatus::InProgress => {
                    i += 1;
                }
            }
        }

        // Try to promote more queued requests if slots opened
        self.promote_queued(grid);

        completed
    }

    /// Promote highest-priority queued requests to active.
    fn promote_queued(&mut self, grid: &NavGrid) {
        while self.active.len() < self.max_active {
            // Find highest priority queued request
            let entry = match self.pending.pop() {
                Some(e) => e,
                None => break,
            };

            // Find and remove from queued list
            let pos = match self.queued.iter().position(|r| r.id == entry.id) {
                Some(p) => p,
                None => continue, // Was cancelled
            };
            let request = self.queued.swap_remove(pos);

            // Create incremental query
            if let Some(query) = IncrementalGridPath::new(grid, request.start, request.goal) {
                self.active.push((request.id, query));
            }
            // If query creation fails (shouldn't happen since we validated), skip silently
        }
    }

    /// Clear all pending and active requests.
    pub fn clear(&mut self) {
        self.pending.clear();
        self.active.clear();
        self.queued.clear();
    }
}

impl Default for PathBatcher {
    fn default() -> Self {
        Self::new()
    }
}

