        let cost = wind_to_movement_cost([-100.0, 0.0], [1.0, 0.0]);
        assert!((cost - 2.0).abs() < 0.01);
        // Extreme tailwind clamps to 0.5
        let cost = wind_to_movement_cost([100.0, 0.0], [1.0, 0.0]);
        assert!((cost - 0.5).abs() < 0.01);
    }

