//! Path corridor — sliding window over navmesh polygon paths with local replanning.

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::mesh::{NavMesh, NavPolyId};
use crate::smooth::{extract_portals, funnel_portals};

#[cfg(feature = "logging")]
use tracing::instrument;

/// A path corridor — a sequence of navmesh polygons from start to goal
/// with position tracking and local replanning support.
///
/// The corridor maintains the current polygon sequence and the agent's
/// position within it. When the world changes, `replan_local()` can
/// update just the affected section without recomputing the entire path.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PathCorridor {
    /// The polygon sequence from current position to goal.
    polys: Vec<NavPolyId>,
    /// Current agent position.
    position: Vec2,
    /// Goal position.
    goal: Vec2,
    /// Index of the polygon the agent is currently in.
    current_idx: usize,
}

impl PathCorridor {
    /// Create a new corridor from a polygon path.
    ///
    /// `position` should be inside `polys[0]`, `goal` inside the last polygon.
    /// Returns `None` if the polygon list is empty.
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn new(polys: Vec<NavPolyId>, position: Vec2, goal: Vec2) -> Option<Self> {
        if polys.is_empty() {
            return None;
        }
        Some(Self {
            polys,
            position,
            goal,
            current_idx: 0,
        })
    }

    /// Create a corridor by pathfinding on the navmesh.
    ///
    /// Returns `None` if no path exists or positions are off-mesh.
    #[cfg_attr(feature = "logging", instrument(skip(mesh)))]
    #[must_use]
    pub fn find(mesh: &NavMesh, position: Vec2, goal: Vec2) -> Option<Self> {
        let polys = mesh.find_path(position, goal)?;
        Self::new(polys, position, goal)
    }

    /// The polygon sequence.
    #[must_use]
    pub fn polys(&self) -> &[NavPolyId] {
        &self.polys
    }

    /// Current agent position.
    #[must_use]
    pub fn position(&self) -> Vec2 {
        self.position
    }

    /// Goal position.
    #[must_use]
    pub fn goal(&self) -> Vec2 {
        self.goal
    }

    /// Index of the current polygon in the corridor.
    #[must_use]
    pub fn current_index(&self) -> usize {
        self.current_idx
    }

    /// Number of polygons remaining in the corridor (including current).
    #[must_use]
    pub fn remaining_polys(&self) -> usize {
        self.polys.len().saturating_sub(self.current_idx)
    }

    /// Whether the agent has reached the final polygon.
    #[must_use]
    pub fn is_at_end(&self) -> bool {
        self.current_idx >= self.polys.len().saturating_sub(1)
    }

    /// Move the agent to a new position, advancing through the corridor.
    ///
    /// Checks if the new position is in a later polygon in the corridor
    /// and advances `current_idx` accordingly.
    #[cfg_attr(feature = "logging", instrument(skip(self, mesh)))]
    pub fn move_position(&mut self, mesh: &NavMesh, new_position: Vec2) {
        self.position = new_position;

        // Check if we've moved to a later polygon in the corridor
        // Search forward from current position (most likely case)
        for i in self.current_idx..self.polys.len() {
            if let Some(poly) = mesh.get_poly(self.polys[i])
                && poly.contains_point(new_position)
            {
                self.current_idx = i;
                return;
            }
        }

        // If not found forward, check all polys (agent might have been pushed back)
        for i in 0..self.current_idx {
            if let Some(poly) = mesh.get_poly(self.polys[i])
                && poly.contains_point(new_position)
            {
                self.current_idx = i;
                return;
            }
        }
        // If position isn't in any corridor poly, keep current_idx unchanged
    }

    /// Trim the corridor — remove polygons the agent has already passed.
    ///
    /// Reduces memory and keeps the corridor focused on remaining path.
    pub fn trim_passed(&mut self) {
        if self.current_idx > 0 {
            self.polys.drain(..self.current_idx);
            self.current_idx = 0;
        }
    }

    /// Locally replan the corridor from the current position.
    ///
    /// Use when the world has changed (obstacles added/removed) and the
    /// existing corridor may be invalid. Replans from current position
    /// to the goal, replacing the remaining corridor.
    ///
    /// Returns `true` if replanning succeeded, `false` if no path exists.
    #[cfg_attr(feature = "logging", instrument(skip(self, mesh)))]
    pub fn replan(&mut self, mesh: &NavMesh) -> bool {
        if let Some(new_polys) = mesh.find_path(self.position, self.goal) {
            self.polys = new_polys;
            self.current_idx = 0;
            true
        } else {
            false
        }
    }

    /// Replan only the section from the current position to a specific
    /// polygon further along the corridor.
    ///
    /// This is cheaper than a full replan when only a local section is
    /// invalidated. Falls back to full replan if local replanning fails.
    ///
    /// Returns `true` if replanning succeeded.
    #[cfg_attr(feature = "logging", instrument(skip(self, mesh)))]
    pub fn replan_local(&mut self, mesh: &NavMesh, rejoin_idx: usize) -> bool {
        let rejoin_idx = rejoin_idx.min(self.polys.len().saturating_sub(1));
        if rejoin_idx <= self.current_idx {
            return self.replan(mesh);
        }

        // Find the centroid of the rejoin polygon as a local goal
        let rejoin_poly_id = self.polys[rejoin_idx];
        let rejoin_target = match mesh.get_poly(rejoin_poly_id) {
            Some(p) => p.centroid(),
            None => return self.replan(mesh),
        };

        // Pathfind from current position to rejoin point
        if let Some(local_path) = mesh.find_path(self.position, rejoin_target) {
            // Splice: replace polys[current_idx..rejoin_idx] with local_path
            let tail: Vec<NavPolyId> = self.polys[rejoin_idx..].to_vec();
            self.polys.truncate(self.current_idx);
            self.polys.extend(local_path);
            // Avoid duplicate if local_path ends at rejoin_poly
            if self.polys.last() == Some(&rejoin_poly_id) && tail.first() == Some(&rejoin_poly_id) {
                self.polys.pop();
            }
            self.polys.extend(tail);
            true
        } else {
            self.replan(mesh)
        }
    }

    /// Compute a smooth path through the corridor using the funnel algorithm.
    ///
    /// Returns world-space waypoints with agent radius clearance.
    #[cfg_attr(feature = "logging", instrument(skip(self, mesh)))]
    #[must_use]
    pub fn smooth_path(&self, mesh: &NavMesh, agent_radius: f32) -> Vec<Vec2> {
        let remaining = &self.polys[self.current_idx..];
        if remaining.is_empty() {
            return vec![self.position];
        }
        if remaining.len() == 1 {
            return vec![self.position, self.goal];
        }

        match extract_portals(mesh, remaining, self.position, self.goal) {
            Some(portals) if !portals.is_empty() => funnel_portals(&portals, agent_radius),
            _ => vec![self.position, self.goal],
        }
    }

    /// Change the goal. Triggers a full replan.
    ///
    /// Returns `true` if a path to the new goal was found.
    #[cfg_attr(feature = "logging", instrument(skip(self, mesh)))]
    pub fn set_goal(&mut self, mesh: &NavMesh, new_goal: Vec2) -> bool {
        self.goal = new_goal;
        self.replan(mesh)
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::mesh::{NavMesh, NavPoly, NavPolyId};

    fn make_three_poly_mesh() -> NavMesh {
        let mut mesh = NavMesh::new();
        // Three squares in a row sharing edges
        mesh.add_poly(NavPoly {
            id: NavPolyId(0),
            vertices: vec![
                Vec2::new(0.0, 0.0),
                Vec2::new(10.0, 0.0),
                Vec2::new(10.0, 10.0),
                Vec2::new(0.0, 10.0),
            ],
            neighbors: vec![NavPolyId(1)],
            cost: 1.0,
            layer: 0,
        });
        mesh.add_poly(NavPoly {
            id: NavPolyId(1),
            vertices: vec![
                Vec2::new(10.0, 0.0),
                Vec2::new(20.0, 0.0),
                Vec2::new(20.0, 10.0),
                Vec2::new(10.0, 10.0),
            ],
            neighbors: vec![NavPolyId(0), NavPolyId(2)],
            cost: 1.0,
            layer: 0,
        });
        mesh.add_poly(NavPoly {
            id: NavPolyId(2),
            vertices: vec![
                Vec2::new(20.0, 0.0),
                Vec2::new(30.0, 0.0),
                Vec2::new(30.0, 10.0),
                Vec2::new(20.0, 10.0),
            ],
            neighbors: vec![NavPolyId(1)],
            cost: 1.0,
            layer: 0,
        });
        mesh
    }

    #[test]
    fn corridor_create() {
        let corridor = PathCorridor::new(
            vec![NavPolyId(0), NavPolyId(1), NavPolyId(2)],
            Vec2::new(5.0, 5.0),
            Vec2::new(25.0, 5.0),
        );
        assert!(corridor.is_some());
        let c = corridor.unwrap();
        assert_eq!(c.polys().len(), 3);
        assert_eq!(c.current_index(), 0);
        assert!(!c.is_at_end());
    }

    #[test]
    fn corridor_empty() {
        assert!(PathCorridor::new(vec![], Vec2::ZERO, Vec2::ONE).is_none());
    }

    #[test]
    fn corridor_find() {
        let mesh = make_three_poly_mesh();
        let corridor = PathCorridor::find(&mesh, Vec2::new(5.0, 5.0), Vec2::new(25.0, 5.0));
        assert!(corridor.is_some());
        let c = corridor.unwrap();
        assert_eq!(c.polys().len(), 3);
    }

    #[test]
    fn corridor_move_position() {
        let mesh = make_three_poly_mesh();
        let mut c = PathCorridor::new(
            vec![NavPolyId(0), NavPolyId(1), NavPolyId(2)],
            Vec2::new(5.0, 5.0),
            Vec2::new(25.0, 5.0),
        )
        .unwrap();

        assert_eq!(c.current_index(), 0);

        // Move to middle polygon
        c.move_position(&mesh, Vec2::new(15.0, 5.0));
        assert_eq!(c.current_index(), 1);

        // Move to last polygon
        c.move_position(&mesh, Vec2::new(25.0, 5.0));
        assert_eq!(c.current_index(), 2);
        assert!(c.is_at_end());
    }

    #[test]
    fn corridor_trim() {
        let mut c = PathCorridor::new(
            vec![NavPolyId(0), NavPolyId(1), NavPolyId(2)],
            Vec2::new(15.0, 5.0),
            Vec2::new(25.0, 5.0),
        )
        .unwrap();
        c.current_idx = 1;

        c.trim_passed();
        assert_eq!(c.polys().len(), 2);
        assert_eq!(c.current_index(), 0);
        assert_eq!(c.polys()[0], NavPolyId(1));
    }

    #[test]
    fn corridor_replan() {
        let mesh = make_three_poly_mesh();
        let mut c = PathCorridor::find(&mesh, Vec2::new(5.0, 5.0), Vec2::new(25.0, 5.0)).unwrap();
        assert!(c.replan(&mesh));
        assert_eq!(c.polys().len(), 3);
    }

    #[test]
    fn corridor_set_goal() {
        let mesh = make_three_poly_mesh();
        let mut c = PathCorridor::find(&mesh, Vec2::new(5.0, 5.0), Vec2::new(25.0, 5.0)).unwrap();
        // Change goal to poly 1
        assert!(c.set_goal(&mesh, Vec2::new(15.0, 5.0)));
        assert_eq!(c.polys().len(), 2);
    }

    #[test]
    fn corridor_remaining() {
        let c = PathCorridor::new(
            vec![NavPolyId(0), NavPolyId(1), NavPolyId(2)],
            Vec2::new(5.0, 5.0),
            Vec2::new(25.0, 5.0),
        )
        .unwrap();
        assert_eq!(c.remaining_polys(), 3);
    }

    #[test]
    fn corridor_serde_roundtrip() {
        let c = PathCorridor::new(
            vec![NavPolyId(0), NavPolyId(1)],
            Vec2::new(5.0, 5.0),
            Vec2::new(15.0, 5.0),
        )
        .unwrap();
        let json = serde_json::to_string(&c).unwrap();
        let deserialized: PathCorridor = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.polys().len(), 2);
    }

    #[test]
    fn corridor_single_poly() {
        let c = PathCorridor::new(vec![NavPolyId(0)], Vec2::new(5.0, 5.0), Vec2::new(8.0, 8.0))
            .unwrap();
        assert!(c.is_at_end());
        assert_eq!(c.remaining_polys(), 1);
    }
}

//! Crowd simulation — density-aware movement on top of RVO/ORCA.

use hisab::Vec2;

#[cfg(feature = "logging")]
use tracing::instrument;

use crate::rvo::{RvoAgent, RvoSimulation};

/// Crowd simulation with density-aware velocity damping.
///
/// Wraps an [`RvoSimulation`] and adds a density grid that tracks agent
/// concentrations. Agents in high-density areas have their preferred
/// velocities scaled down to prevent crushing and create natural flow.
#[derive(Debug, Clone)]
pub struct CrowdSimulation {
    rvo: RvoSimulation,
    /// Density grid cell size in world units.
    density_cell_size: f32,
    /// Maximum comfortable agents per density cell.
    max_density: f32,
    /// Persistent density map — reused each step to avoid per-frame allocation.
    density_cache: std::collections::HashMap<(i32, i32), f32>,
}

impl CrowdSimulation {
    /// Create a new crowd simulation.
    ///
    /// - `time_horizon`: ORCA look-ahead time
    /// - `density_cell_size`: spatial grid cell size for density tracking
    /// - `max_density`: agents per cell before velocity damping kicks in
    #[must_use]
    pub fn new(time_horizon: f32, density_cell_size: f32, max_density: f32) -> Self {
        Self {
            rvo: RvoSimulation::new(time_horizon),
            density_cell_size,
            max_density,
            density_cache: std::collections::HashMap::new(),
        }
    }

    /// Add an agent and return its index.
    pub fn add_agent(&mut self, agent: RvoAgent) -> usize {
        self.rvo.add_agent(agent)
    }

    /// Number of agents.
    #[must_use]
    pub fn agent_count(&self) -> usize {
        self.rvo.agent_count()
    }

    /// Get an agent by index.
    #[must_use]
    pub fn agent(&self, idx: usize) -> &RvoAgent {
        self.rvo.agent(idx)
    }

    /// Mutable access to an agent.
    pub fn agent_mut(&mut self, idx: usize) -> &mut RvoAgent {
        self.rvo.agent_mut(idx)
    }

    /// Set the preferred velocity for an agent.
    pub fn set_preferred_velocity(&mut self, idx: usize, velocity: Vec2) {
        self.rvo.set_preferred_velocity(idx, velocity);
    }

    /// Step the simulation by `dt` seconds.
    ///
    /// Computes a density map, damps preferred velocities in crowded areas,
    /// then runs the RVO step.
    #[cfg_attr(feature = "logging", instrument(skip(self), fields(agents = self.agent_count())))]
    pub fn step(&mut self, dt: f32) {
        let n = self.agent_count();
        if n == 0 {
            return;
        }

        // Rebuild density map in-place (reuse allocation)
        self.rebuild_density();

        // Damp preferred velocities based on local density
        for i in 0..n {
            let cell = self.density_cell(self.rvo.agent(i).position);
            let local_density = self.density_cache.get(&cell).copied().unwrap_or(0.0);
            let damping = if local_density > self.max_density {
                self.max_density / local_density
            } else {
                1.0
            };
            let pref = self.rvo.agent(i).preferred_velocity;
            self.rvo.set_preferred_velocity(i, pref * damping);
        }

        self.rvo.step(dt);
    }

    /// Compute the density at a specific world position.
    ///
    /// Uses the cached density from the last `step()` call. Call `step()`
    /// first to ensure up-to-date values.
    #[must_use]
    pub fn density_at(&self, position: Vec2) -> f32 {
        let cell = self.density_cell(position);
        self.density_cache.get(&cell).copied().unwrap_or(0.0)
    }

    fn density_cell(&self, position: Vec2) -> (i32, i32) {
        (
            (position.x / self.density_cell_size).floor() as i32,
            (position.y / self.density_cell_size).floor() as i32,
        )
    }

    /// Clear and refill the density cache without allocating a new HashMap.
    fn rebuild_density(&mut self) {
        // Clear values but keep allocated buckets
        for v in self.density_cache.values_mut() {
            *v = 0.0;
        }
        for i in 0..self.agent_count() {
            let cell = self.density_cell(self.rvo.agent(i).position);
            *self.density_cache.entry(cell).or_insert(0.0) += 1.0;
        }
        // Remove cells that are now zero (agents moved away)
        self.density_cache.retain(|_, v| *v > 0.0);
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn crowd_basic() {
        let mut sim = CrowdSimulation::new(3.0, 2.0, 4.0);
        let a = sim.add_agent(RvoAgent::new(Vec2::ZERO, 0.5, 2.0));
        let b = sim.add_agent(RvoAgent::new(Vec2::new(10.0, 0.0), 0.5, 2.0));

        sim.set_preferred_velocity(a, Vec2::new(1.0, 0.0));
        sim.set_preferred_velocity(b, Vec2::new(-1.0, 0.0));

        assert_eq!(sim.agent_count(), 2);

        for _ in 0..10 {
            sim.step(0.1);
        }

        assert!(sim.agent(a).position.x > 0.0);
    }

    #[test]
    fn density_damping() {
        let mut sim = CrowdSimulation::new(3.0, 2.0, 2.0);

        // Pack 5 agents into a small area (max_density = 2)
        for i in 0..5 {
            let idx = sim.add_agent(RvoAgent::new(Vec2::new(0.1 * i as f32, 0.0), 0.1, 5.0));
            sim.set_preferred_velocity(idx, Vec2::new(5.0, 0.0));
        }

        // Step to populate density cache and apply damping
        sim.step(0.1);

        // Density at origin should be > max_density
        let d = sim.density_at(Vec2::ZERO);
        assert!(d > 2.0);
    }

    #[test]
    fn density_at_empty() {
        let sim = CrowdSimulation::new(3.0, 2.0, 4.0);
        assert!((sim.density_at(Vec2::ZERO) - 0.0).abs() < f32::EPSILON);
    }

    #[test]
    fn crowd_empty_step() {
        let mut sim = CrowdSimulation::new(3.0, 2.0, 4.0);
        sim.step(0.1); // Should not panic
    }

    #[test]
    fn crowd_single_agent() {
        let mut sim = CrowdSimulation::new(3.0, 2.0, 4.0);
        let a = sim.add_agent(RvoAgent::new(Vec2::ZERO, 0.5, 5.0));
        sim.set_preferred_velocity(a, Vec2::new(3.0, 0.0));
        sim.step(1.0);
        assert!((sim.agent(a).position.x - 3.0).abs() < 0.5);
    }

    #[test]
    fn crowd_crossing() {
        let mut sim = CrowdSimulation::new(3.0, 3.0, 5.0);

        // Two groups crossing perpendicular
        for i in 0..5 {
            let idx = sim.add_agent(RvoAgent::new(Vec2::new(-10.0, i as f32 - 2.0), 0.5, 2.0));
            sim.set_preferred_velocity(idx, Vec2::new(1.0, 0.0));
        }
        for i in 0..5 {
            let idx = sim.add_agent(RvoAgent::new(Vec2::new(i as f32 - 2.0, -10.0), 0.5, 2.0));
            sim.set_preferred_velocity(idx, Vec2::new(0.0, 1.0));
        }

        for _ in 0..50 {
            sim.step(0.1);
        }

        // All agents should have moved generally toward their targets
        assert!(sim.agent(0).position.x > -10.0);
        assert!(sim.agent(5).position.y > -10.0);
    }
}

//! Debug visualization — geometry output for rendering navmeshes, paths, and flow fields.
//!
//! Produces line segments and points that consumers can render with their
//! own graphics backend. No rendering dependency.

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::grid::{GridPos, NavGrid};
use crate::mesh::NavMesh;

/// A colored line segment for debug rendering.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct DebugLine {
    pub start: Vec2,
    pub end: Vec2,
    pub color: [f32; 4],
}

/// A colored point for debug rendering.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct DebugPoint {
    pub position: Vec2,
    pub color: [f32; 4],
}

/// Collects debug geometry for visualization.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct DebugDraw {
    pub lines: Vec<DebugLine>,
    pub points: Vec<DebugPoint>,
}

impl DebugDraw {
    #[must_use]
    #[cfg_attr(feature = "logging", tracing::instrument)]
    pub fn new() -> Self {
        Self::default()
    }

    /// Clear all collected geometry.
    #[cfg_attr(feature = "logging", tracing::instrument(skip(self)))]
    pub fn clear(&mut self) {
        self.lines.clear();
        self.points.clear();
    }

    /// Draw a NavMesh as polygon outlines.
    pub fn draw_navmesh(&mut self, mesh: &NavMesh, color: [f32; 4]) {
        for poly in mesh.polys() {
            let n = poly.vertices.len();
            for i in 0..n {
                let j = (i + 1) % n;
                self.lines.push(DebugLine {
                    start: poly.vertices[i],
                    end: poly.vertices[j],
                    color,
                });
            }
            // Mark centroid
            self.points.push(DebugPoint {
                position: poly.centroid(),
                color,
            });
        }
    }

    /// Draw a path as connected line segments.
    pub fn draw_path(&mut self, waypoints: &[Vec2], color: [f32; 4]) {
        for w in waypoints.windows(2) {
            self.lines.push(DebugLine {
                start: w[0],
                end: w[1],
                color,
            });
        }
        for &p in waypoints {
            self.points.push(DebugPoint { position: p, color });
        }
    }

    /// Draw a grid path (converts grid positions to world positions).
    pub fn draw_grid_path(&mut self, grid: &NavGrid, path: &[GridPos], color: [f32; 4]) {
        let world: Vec<Vec2> = path.iter().map(|p| grid.grid_to_world(*p)).collect();
        self.draw_path(&world, color);
    }

    /// Draw the flow field as arrows from each cell center.
    pub fn draw_flow_field(&mut self, grid: &NavGrid, field: &[(i32, i32)], color: [f32; 4]) {
        let arrow_scale = grid.cell_size() * 0.4;
        for y in 0..grid.height() as i32 {
            for x in 0..grid.width() as i32 {
                let idx = (y as usize) * grid.width() + (x as usize);
                let (dx, dy) = field[idx];
                if dx == 0 && dy == 0 {
                    continue;
                }
                let center = grid.grid_to_world(GridPos::new(x, y));
                let dir = Vec2::new(dx as f32, dy as f32).normalize_or_zero();
                let tip = center + dir * arrow_scale;
                self.lines.push(DebugLine {
                    start: center,
                    end: tip,
                    color,
                });
            }
        }
    }

    /// Draw grid walkability — blocked cells as filled squares.
    pub fn draw_grid_walkability(
        &mut self,
        grid: &NavGrid,
        walkable_color: [f32; 4],
        blocked_color: [f32; 4],
    ) {
        let half = grid.cell_size() * 0.4;
        for y in 0..grid.height() as i32 {
            for x in 0..grid.width() as i32 {
                let center = grid.grid_to_world(GridPos::new(x, y));
                let color = if grid.is_walkable(x, y) {
                    walkable_color
                } else {
                    blocked_color
                };
                // Draw cell as a small square (4 lines)
                let corners = [
                    Vec2::new(center.x - half, center.y - half),
                    Vec2::new(center.x + half, center.y - half),
                    Vec2::new(center.x + half, center.y + half),
                    Vec2::new(center.x - half, center.y + half),
                ];
                for i in 0..4 {
                    self.lines.push(DebugLine {
                        start: corners[i],
                        end: corners[(i + 1) % 4],
                        color,
                    });
                }
            }
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::mesh::{NavPoly, NavPolyId};

    #[test]
    fn draw_navmesh_produces_lines() {
        let mut mesh = NavMesh::new();
        mesh.add_poly(NavPoly {
            id: NavPolyId(0),
            vertices: vec![Vec2::ZERO, Vec2::new(1.0, 0.0), Vec2::new(0.5, 1.0)],
            neighbors: vec![],
            cost: 1.0,
            layer: 0,
        });

        let mut dd = DebugDraw::new();
        dd.draw_navmesh(&mesh, [1.0, 0.0, 0.0, 1.0]);

        assert_eq!(dd.lines.len(), 3); // triangle = 3 edges
        assert_eq!(dd.points.len(), 1); // 1 centroid
    }

    #[test]
    fn draw_path_produces_segments() {
        let mut dd = DebugDraw::new();
        let path = vec![Vec2::ZERO, Vec2::new(1.0, 0.0), Vec2::new(2.0, 1.0)];
        dd.draw_path(&path, [0.0, 1.0, 0.0, 1.0]);

        assert_eq!(dd.lines.len(), 2); // 3 points = 2 segments
        assert_eq!(dd.points.len(), 3); // 3 waypoints
    }

    #[test]
    fn draw_grid_path() {
        let grid = NavGrid::new(5, 5, 1.0);
        let path = vec![GridPos::new(0, 0), GridPos::new(1, 1), GridPos::new(2, 2)];

        let mut dd = DebugDraw::new();
        dd.draw_grid_path(&grid, &path, [0.0, 0.0, 1.0, 1.0]);

        assert_eq!(dd.lines.len(), 2);
        assert_eq!(dd.points.len(), 3);
    }

    #[test]
    fn draw_flow_field_produces_arrows() {
        let grid = NavGrid::new(3, 3, 1.0);
        let field = grid.flow_field(GridPos::new(2, 2));

        let mut dd = DebugDraw::new();
        dd.draw_flow_field(&grid, &field, [1.0, 1.0, 0.0, 1.0]);

        // 8 cells with directions (all except goal (2,2))
        assert_eq!(dd.lines.len(), 8);
    }

    #[test]
    fn draw_grid_walkability() {
        let mut grid = NavGrid::new(3, 3, 1.0);
        grid.set_walkable(1, 1, false);

        let mut dd = DebugDraw::new();
        dd.draw_grid_walkability(&grid, [0.0, 1.0, 0.0, 0.3], [1.0, 0.0, 0.0, 0.5]);

        // 9 cells × 4 lines each = 36 lines
        assert_eq!(dd.lines.len(), 36);
    }

    #[test]
    fn clear_resets() {
        let mut dd = DebugDraw::new();
        dd.lines.push(DebugLine {
            start: Vec2::ZERO,
            end: Vec2::ONE,
            color: [1.0; 4],
        });
        dd.points.push(DebugPoint {
            position: Vec2::ZERO,
            color: [1.0; 4],
        });
        dd.clear();
        assert!(dd.lines.is_empty());
        assert!(dd.points.is_empty());
    }

    #[test]
    fn empty_mesh_no_output() {
        let mesh = NavMesh::new();
        let mut dd = DebugDraw::new();
        dd.draw_navmesh(&mesh, [1.0; 4]);
        assert!(dd.lines.is_empty());
        assert!(dd.points.is_empty());
    }

    #[test]
    fn debug_draw_serde_roundtrip() {
        let mut dd = DebugDraw::new();
        dd.lines.push(DebugLine {
            start: Vec2::ZERO,
            end: Vec2::ONE,
            color: [1.0, 0.0, 0.0, 1.0],
        });
        dd.points.push(DebugPoint {
            position: Vec2::new(0.5, 0.5),
            color: [0.0, 1.0, 0.0, 1.0],
        });
        let json = serde_json::to_string(&dd).unwrap();
        let deserialized: DebugDraw = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.lines.len(), 1);
        assert_eq!(deserialized.points.len(), 1);
    }
}

//! D\* Lite — incremental replanning for dynamic environments.

use std::cmp::Ordering;
use std::collections::BinaryHeap;

use crate::grid::{GridPos, NavGrid};

#[cfg(feature = "logging")]
use tracing::instrument;

/// D\* Lite incremental pathfinder.
///
/// Searches backwards from goal to start. When the environment changes
/// (cells blocked/unblocked, costs changed), call [`update_cell()`](Self::update_cell)
/// to notify, then [`compute_path()`](Self::compute_path) to incrementally
/// update only the affected nodes.
///
/// More efficient than re-running A\* from scratch when few cells change.
pub struct DStarLite {
    start_idx: usize,
    goal_idx: usize,
    grid_width: usize,
    grid_height: usize,
    allow_diagonal: bool,
    /// g values: cost from node to goal.
    g: Vec<f32>,
    /// rhs values: one-step lookahead.
    rhs: Vec<f32>,
    /// Priority queue.
    open: BinaryHeap<DStarNode>,
    /// Key modifier (increases when start position moves).
    km: f32,
    /// Current start position (can change as agent moves).
    start: GridPos,
    /// Goal position.
    goal: GridPos,
}

#[derive(Clone, Copy)]
struct DStarNode {
    idx: usize,
    key: (f32, f32), // (k1, k2) priority
}

impl PartialEq for DStarNode {
    fn eq(&self, other: &Self) -> bool {
        self.key == other.key
    }
}

impl Eq for DStarNode {}

impl PartialOrd for DStarNode {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for DStarNode {
    fn cmp(&self, other: &Self) -> Ordering {
        // Min-heap: reverse ordering. Compare k1 first, then k2.
        match other.key.0.partial_cmp(&self.key.0) {
            Some(Ordering::Equal) | None => other
                .key
                .1
                .partial_cmp(&self.key.1)
                .unwrap_or(Ordering::Equal),
            Some(ord) => ord,
        }
    }
}

impl DStarLite {
    /// Initialize D\* Lite for a grid from `start` to `goal`.
    ///
    /// Returns `None` if start or goal is outside the grid.
    #[cfg_attr(feature = "logging", instrument(skip(grid)))]
    #[must_use]
    pub fn new(grid: &NavGrid, start: GridPos, goal: GridPos) -> Option<Self> {
        let w = grid.width();
        let h = grid.height();
        let len = w * h;

        let start_idx = index(start.x, start.y, w, h)?;
        let goal_idx = index(goal.x, goal.y, w, h)?;

        let g = vec![f32::INFINITY; len];
        let rhs = vec![f32::INFINITY; len];

        let mut inst = Self {
            start_idx,
            goal_idx,
            grid_width: w,
            grid_height: h,
            allow_diagonal: grid.allow_diagonal,
            g,
            rhs,
            open: BinaryHeap::new(),
            km: 0.0,
            start,
            goal,
        };
        inst.rhs[goal_idx] = 0.0;

        let key = calculate_key(goal_idx, &inst.g, &inst.rhs, start_idx, 0.0, w);
        inst.open.push(DStarNode { idx: goal_idx, key });

        Some(inst)
    }

    /// Compute (or recompute) the shortest path.
    ///
    /// Processes all inconsistent cells so the g-field is fully consistent,
    /// enabling reliable full-path extraction via [`path()`](Self::path).
    ///
    /// Call after [`new()`](Self::new) for initial computation, or after
    /// [`update_cell()`](Self::update_cell) for incremental replanning.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    pub fn compute_path(&mut self, grid: &NavGrid) {
        self.process_queue(grid, false);
    }

    /// Compute the shortest path with early termination.
    ///
    /// Stops as soon as the start node is locally consistent, which is
    /// sufficient for single-step navigation via [`next_step()`](Self::next_step).
    /// For full path extraction, use [`compute_path()`](Self::compute_path)
    /// instead.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    pub fn compute_path_lazy(&mut self, grid: &NavGrid) {
        self.process_queue(grid, true);
    }

    /// Return the next cell to move to from the current start.
    ///
    /// This is the most efficient way to use D\* Lite: call
    /// [`compute_path_lazy()`](Self::compute_path_lazy), take one step with
    /// this method, then call [`set_start()`](Self::set_start) and repeat.
    ///
    /// Returns `None` if no path exists.
    #[must_use]
    pub fn next_step(&self, grid: &NavGrid) -> Option<GridPos> {
        if self.g[self.start_idx] == f32::INFINITY {
            return None;
        }
        if self.start_idx == self.goal_idx {
            return Some(self.goal);
        }

        let sx = (self.start_idx % self.grid_width) as i32;
        let sy = (self.start_idx / self.grid_width) as i32;
        let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];
        let count = grid_neighbors(grid, sx, sy, self.allow_diagonal, &mut neighbors_buf);

        let mut best_idx = None;
        let mut best_cost = f32::INFINITY;
        for &(nx, ny, move_cost) in &neighbors_buf[..count] {
            if let Some(n_idx) = index(nx, ny, self.grid_width, self.grid_height) {
                let cost = move_cost * grid.cost(nx, ny) + self.g[n_idx];
                if cost < best_cost {
                    best_cost = cost;
                    best_idx = Some(n_idx);
                }
            }
        }

        best_idx.map(|idx| {
            GridPos::new(
                (idx % self.grid_width) as i32,
                (idx / self.grid_width) as i32,
            )
        })
    }

    fn process_queue(&mut self, grid: &NavGrid, early_terminate: bool) {
        let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];
        let mut iterations = 0u32;
        let max_iterations = (self.grid_width * self.grid_height * 4) as u32;

        while let Some(top) = self.open.peek() {
            if early_terminate {
                let top_key = top.key;
                let start_key = calculate_key(
                    self.start_idx,
                    &self.g,
                    &self.rhs,
                    self.start_idx,
                    self.km,
                    self.grid_width,
                );
                let g_neq_rhs = self.rhs[self.start_idx] != self.g[self.start_idx];
                if !(key_less(top_key, start_key) || g_neq_rhs) {
                    break;
                }
            }

            iterations += 1;
            if iterations > max_iterations {
                break;
            }

            let u = self.open.pop().expect("peek succeeded so pop must too");
            let u_idx = u.idx;
            let ux = (u_idx % self.grid_width) as i32;
            let uy = (u_idx / self.grid_width) as i32;

            let new_key = calculate_key(
                u_idx,
                &self.g,
                &self.rhs,
                self.start_idx,
                self.km,
                self.grid_width,
            );

            if key_less(u.key, new_key) {
                // Key is outdated: reinsert with updated key.
                self.open.push(DStarNode {
                    idx: u_idx,
                    key: new_key,
                });
            } else if (self.g[u_idx] - self.rhs[u_idx]).abs() <= f32::EPSILON {
                // Locally consistent — stale queue entry, skip.
                continue;
            } else if self.g[u_idx] > self.rhs[u_idx] {
                // Overconsistent.
                self.g[u_idx] = self.rhs[u_idx];
                let count = grid_neighbors(grid, ux, uy, self.allow_diagonal, &mut neighbors_buf);
                for &(nx, ny, _) in &neighbors_buf[..count] {
                    if let Some(n_idx) = index(nx, ny, self.grid_width, self.grid_height) {
                        self.update_vertex(grid, n_idx);
                    }
                }
            } else {
                // Underconsistent.
                self.g[u_idx] = f32::INFINITY;
                // Update u itself.
                self.update_vertex(grid, u_idx);
                let count = grid_neighbors(grid, ux, uy, self.allow_diagonal, &mut neighbors_buf);
                for &(nx, ny, _) in &neighbors_buf[..count] {
                    if let Some(n_idx) = index(nx, ny, self.grid_width, self.grid_height) {
                        self.update_vertex(grid, n_idx);
                    }
                }
            }
        }
    }

    /// Notify that a cell's cost or walkability has changed.
    ///
    /// Call this for each changed cell, then call [`compute_path()`](Self::compute_path)
    /// to replan.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    pub fn update_cell(&mut self, grid: &NavGrid, pos: GridPos) {
        if let Some(idx) = index(pos.x, pos.y, self.grid_width, self.grid_height) {
            self.update_vertex(grid, idx);
            // Also update all neighbors since their paths through this cell changed.
            let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];
            let count = grid_neighbors(grid, pos.x, pos.y, self.allow_diagonal, &mut neighbors_buf);
            for &(nx, ny, _) in &neighbors_buf[..count] {
                if let Some(n_idx) = index(nx, ny, self.grid_width, self.grid_height) {
                    self.update_vertex(grid, n_idx);
                }
            }
        }
    }

    /// Update the start position (when the agent moves).
    ///
    /// Call [`compute_path()`](Self::compute_path) after to update the path.
    pub fn set_start(&mut self, new_start: GridPos) {
        if let Some(new_idx) = index(new_start.x, new_start.y, self.grid_width, self.grid_height) {
            // Increase km by the heuristic distance between old and new start.
            self.km += heuristic(self.start_idx, new_idx, self.grid_width);
            self.start = new_start;
            self.start_idx = new_idx;
        }
    }

    /// Extract the current path from start to goal.
    ///
    /// Returns `None` if no path exists.
    #[must_use]
    pub fn path(&self, grid: &NavGrid) -> Option<Vec<GridPos>> {
        if self.g[self.start_idx] == f32::INFINITY {
            return None;
        }

        let mut path = Vec::new();
        let mut current = self.start_idx;
        let mut visited = vec![false; self.g.len()];
        let max_steps = self.grid_width * self.grid_height;

        for _ in 0..max_steps {
            let cx = (current % self.grid_width) as i32;
            let cy = (current / self.grid_width) as i32;
            path.push(GridPos::new(cx, cy));

            if current == self.goal_idx {
                return Some(path);
            }

            visited[current] = true;

            // Follow the lowest g-cost neighbor.
            let mut best_idx = current;
            let mut best_cost = f32::INFINITY;
            let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];
            let count = grid_neighbors(grid, cx, cy, self.allow_diagonal, &mut neighbors_buf);

            for &(nx, ny, move_cost) in &neighbors_buf[..count] {
                if let Some(n_idx) = index(nx, ny, self.grid_width, self.grid_height) {
                    if visited[n_idx] {
                        continue;
                    }
                    let cost = move_cost * grid.cost(nx, ny) + self.g[n_idx];
                    if cost < best_cost {
                        best_cost = cost;
                        best_idx = n_idx;
                    }
                }
            }

            if best_idx == current {
                return None; // Stuck.
            }
            current = best_idx;
        }

        None
    }

    /// Start position.
    #[must_use]
    pub fn start(&self) -> GridPos {
        self.start
    }

    /// Goal position.
    #[must_use]
    pub fn goal(&self) -> GridPos {
        self.goal
    }

    fn update_vertex(&mut self, grid: &NavGrid, idx: usize) {
        let x = (idx % self.grid_width) as i32;
        let y = (idx / self.grid_width) as i32;

        if idx != self.goal_idx {
            // rhs = min over successors s': c(u,s') + g(s').
            let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];
            let count = grid_neighbors(grid, x, y, self.allow_diagonal, &mut neighbors_buf);

            if !grid.is_walkable(x, y) {
                self.rhs[idx] = f32::INFINITY;
            } else {
                let mut min_rhs = f32::INFINITY;
                for &(nx, ny, move_cost) in &neighbors_buf[..count] {
                    if let Some(n_idx) = index(nx, ny, self.grid_width, self.grid_height) {
                        let cost = move_cost * grid.cost(nx, ny) + self.g[n_idx];
                        if cost < min_rhs {
                            min_rhs = cost;
                        }
                    }
                }
                self.rhs[idx] = min_rhs;
            }
        }

        // Lazy deletion: stale entries in the heap are skipped via key comparison
        // in compute_path, so we simply push a new entry if g != rhs.
        if (self.g[idx] - self.rhs[idx]).abs() > f32::EPSILON {
            let key = calculate_key(
                idx,
                &self.g,
                &self.rhs,
                self.start_idx,
                self.km,
                self.grid_width,
            );
            self.open.push(DStarNode { idx, key });
        }
    }
}

/// Convert (x, y) to a flat index, returning `None` if out of bounds.
#[inline]
fn index(x: i32, y: i32, w: usize, h: usize) -> Option<usize> {
    if x >= 0 && y >= 0 && (x as usize) < w && (y as usize) < h {
        Some(y as usize * w + x as usize)
    } else {
        None
    }
}

/// Octile heuristic between two flat indices.
#[inline]
fn heuristic(a: usize, b: usize, width: usize) -> f32 {
    let ax = (a % width) as f32;
    let ay = (a / width) as f32;
    let bx = (b % width) as f32;
    let by = (b / width) as f32;
    let dx = (ax - bx).abs();
    let dy = (ay - by).abs();
    let (min, max) = if dx < dy { (dx, dy) } else { (dy, dx) };
    max + (std::f32::consts::SQRT_2 - 1.0) * min
}

/// Compare two keys lexicographically: (k1, k2) < (k1', k2').
#[inline]
fn key_less(a: (f32, f32), b: (f32, f32)) -> bool {
    a.0 < b.0 || (a.0 == b.0 && a.1 < b.1)
}

/// Compute the priority key for a node.
#[inline]
fn calculate_key(
    idx: usize,
    g: &[f32],
    rhs: &[f32],
    start_idx: usize,
    km: f32,
    width: usize,
) -> (f32, f32) {
    let min_g_rhs = g[idx].min(rhs[idx]);
    let h = heuristic(start_idx, idx, width);
    (min_g_rhs + h + km, min_g_rhs)
}

/// Compute walkable neighbors into a stack buffer, returning the count.
#[inline]
fn grid_neighbors(
    grid: &NavGrid,
    x: i32,
    y: i32,
    allow_diagonal: bool,
    buf: &mut [(i32, i32, f32); 8],
) -> usize {
    const CARDINAL: [(i32, i32); 4] = [(0, 1), (0, -1), (1, 0), (-1, 0)];
    const DIAGONAL: [(i32, i32); 4] = [(1, 1), (1, -1), (-1, 1), (-1, -1)];

    let mut count = 0;
    for (dx, dy) in CARDINAL {
        let nx = x + dx;
        let ny = y + dy;
        if grid.is_walkable(nx, ny) {
            buf[count] = (nx, ny, 1.0);
            count += 1;
        }
    }
    if allow_diagonal {
        for (dx, dy) in DIAGONAL {
            let nx = x + dx;
            let ny = y + dy;
            if grid.is_walkable(nx, ny)
                && grid.is_walkable(x + dx, y)
                && grid.is_walkable(x, y + dy)
            {
                buf[count] = (nx, ny, std::f32::consts::SQRT_2);
                count += 1;
            }
        }
    }
    count
}

