//! Heightfield-based navmesh baking from 3D geometry.
//!
//! Provides a Recast-inspired pipeline: voxelize 3D triangles into a
//! heightfield, identify walkable surfaces, and generate a 2D navmesh
//! projected onto the XZ plane.

use hisab::{Vec2, Vec3};
use serde::{Deserialize, Serialize};

use crate::mesh::{NavMesh, NavPoly, NavPolyId};

#[cfg(feature = "logging")]
use tracing::instrument;

/// A span in a heightfield column — a vertical range that is solid.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct HeightSpan {
    /// Bottom of the solid span (voxel units).
    pub min_y: u16,
    /// Top of the solid span (voxel units).
    pub max_y: u16,
    /// Whether the top surface is walkable.
    pub walkable: bool,
}

/// Baking configuration for heightfield navmesh generation.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct HeightfieldConfig {
    /// Size of each voxel in world units (XZ plane).
    pub cell_size: f32,
    /// Height of each voxel in world units (Y axis).
    pub cell_height: f32,
    /// Maximum slope angle (radians) considered walkable.
    pub max_slope: f32,
    /// Minimum clearance height (world units) above a walkable surface.
    pub agent_height: f32,
    /// Agent radius (world units) for erosion.
    pub agent_radius: f32,
    /// Minimum region area (in cells) to keep — smaller regions are removed.
    pub min_region_area: usize,
}

impl Default for HeightfieldConfig {
    fn default() -> Self {
        Self {
            cell_size: 0.3,
            cell_height: 0.2,
            max_slope: std::f32::consts::FRAC_PI_4, // 45 degrees
            agent_height: 2.0,
            agent_radius: 0.6,
            min_region_area: 8,
        }
    }
}

/// A heightfield — voxelized representation of 3D geometry.
///
/// Each cell in the XZ grid contains a stack of solid spans representing
/// the vertical extent of geometry at that position.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct Heightfield {
    width: usize,
    depth: usize,
    origin: Vec3,
    cell_size: f32,
    cell_height: f32,
    /// Column-major storage: `spans[z * width + x]` = Vec of spans for that column.
    spans: Vec<Vec<HeightSpan>>,
}

impl Heightfield {
    /// Create an empty heightfield covering the given world bounds.
    #[must_use]
    pub fn new(min: Vec3, max: Vec3, cell_size: f32, cell_height: f32) -> Self {
        let width = ((max.x - min.x) / cell_size).ceil() as usize;
        let depth = ((max.z - min.z) / cell_size).ceil() as usize;
        Self {
            width: width.max(1),
            depth: depth.max(1),
            origin: min,
            cell_size,
            cell_height,
            spans: vec![Vec::new(); width.max(1) * depth.max(1)],
        }
    }

    /// Grid width (number of cells along the X axis).
    #[must_use]
    pub fn width(&self) -> usize {
        self.width
    }

    /// Grid depth (number of cells along the Z axis).
    #[must_use]
    pub fn depth(&self) -> usize {
        self.depth
    }

    /// World-space origin (minimum corner).
    #[must_use]
    pub fn origin(&self) -> Vec3 {
        self.origin
    }

    /// Cell size in world units (XZ plane).
    #[must_use]
    pub fn cell_size(&self) -> f32 {
        self.cell_size
    }

    /// Cell height in world units (Y axis).
    #[must_use]
    pub fn cell_height(&self) -> f32 {
        self.cell_height
    }

    /// Get spans at grid position.
    #[must_use]
    pub fn spans_at(&self, x: usize, z: usize) -> &[HeightSpan] {
        if x < self.width && z < self.depth {
            &self.spans[z * self.width + x]
        } else {
            &[]
        }
    }

    /// Rasterize a single triangle into the heightfield.
    pub fn rasterize_triangle(&mut self, v0: Vec3, v1: Vec3, v2: Vec3) {
        // Compute bounding box in grid coords
        let min_x = ((v0.x.min(v1.x).min(v2.x) - self.origin.x) / self.cell_size).floor() as i32;
        let max_x = ((v0.x.max(v1.x).max(v2.x) - self.origin.x) / self.cell_size).ceil() as i32;
        let min_z = ((v0.z.min(v1.z).min(v2.z) - self.origin.z) / self.cell_size).floor() as i32;
        let max_z = ((v0.z.max(v1.z).max(v2.z) - self.origin.z) / self.cell_size).ceil() as i32;

        let min_x = min_x.max(0) as usize;
        let max_x = (max_x as usize).min(self.width.saturating_sub(1));
        let min_z = min_z.max(0) as usize;
        let max_z = (max_z as usize).min(self.depth.saturating_sub(1));

        for z in min_z..=max_z {
            for x in min_x..=max_x {
                // Cell center in world space
                let cx = self.origin.x + (x as f32 + 0.5) * self.cell_size;
                let cz = self.origin.z + (z as f32 + 0.5) * self.cell_size;

                // Check if cell overlaps triangle (conservative: use point-in-triangle on XZ)
                if !point_in_triangle_xz(cx, cz, v0, v1, v2) {
                    continue;
                }

                // Interpolate Y at this XZ position using barycentric coords
                if let Some(y) = barycentric_y(cx, cz, v0, v1, v2) {
                    let vy = ((y - self.origin.y) / self.cell_height) as u16;
                    self.add_span(x, z, vy, vy.saturating_add(1));
                }
            }
        }
    }

    /// Rasterize multiple triangles (vertex triplets).
    #[cfg_attr(feature = "logging", instrument(skip(self, triangles)))]
    pub fn rasterize_triangles(&mut self, triangles: &[[Vec3; 3]]) {
        for tri in triangles {
            self.rasterize_triangle(tri[0], tri[1], tri[2]);
        }
    }

    /// Rasterize from indexed vertex/index buffers.
    #[cfg_attr(feature = "logging", instrument(skip(self, vertices, indices)))]
    pub fn rasterize_indexed(&mut self, vertices: &[Vec3], indices: &[u32]) {
        for chunk in indices.chunks_exact(3) {
            let i0 = chunk[0] as usize;
            let i1 = chunk[1] as usize;
            let i2 = chunk[2] as usize;
            if i0 < vertices.len() && i1 < vertices.len() && i2 < vertices.len() {
                self.rasterize_triangle(vertices[i0], vertices[i1], vertices[i2]);
            }
        }
    }

    /// Add a span to a column, merging with existing spans if they overlap.
    fn add_span(&mut self, x: usize, z: usize, min_y: u16, max_y: u16) {
        let idx = z * self.width + x;
        let spans = &mut self.spans[idx];

        // Find overlapping or adjacent spans and merge
        let mut new_min = min_y;
        let mut new_max = max_y;
        let mut i = 0;
        while i < spans.len() {
            if spans[i].min_y <= new_max.saturating_add(1)
                && spans[i].max_y >= new_min.saturating_sub(1)
            {
                new_min = new_min.min(spans[i].min_y);
                new_max = new_max.max(spans[i].max_y);
                spans.swap_remove(i);
            } else {
                i += 1;
            }
        }
        spans.push(HeightSpan {
            min_y: new_min,
            max_y: new_max,
            walkable: false,
        });
    }

    /// Mark walkable surfaces based on slope angle.
    ///
    /// A span's top surface is walkable if the triangle normal at that
    /// point has a Y component >= cos(max\_slope).
    pub fn mark_walkable(&mut self, _max_slope: f32) {
        // Simple approach: all top surfaces of spans are potentially walkable.
        // (Real Recast checks triangle normals; we approximate by marking all.
        // Use `mark_walkable_from_triangles` for slope-filtered walkability.)
        for col in &mut self.spans {
            // Sort spans by min_y
            col.sort_by_key(|s| s.min_y);
            for span in col.iter_mut() {
                span.walkable = true;
            }
        }
    }

    /// Mark walkable surfaces using triangle normals for slope filtering.
    #[cfg_attr(feature = "logging", instrument(skip(self, triangles)))]
    pub fn mark_walkable_from_triangles(&mut self, triangles: &[[Vec3; 3]], max_slope: f32) {
        let min_ny = max_slope.cos();

        // First, reset all to non-walkable
        for col in &mut self.spans {
            for span in col.iter_mut() {
                span.walkable = false;
            }
        }

        // For each triangle, compute its normal and mark covered cells
        for tri in triangles {
            let edge1 = tri[1] - tri[0];
            let edge2 = tri[2] - tri[0];
            let normal = edge1.cross(edge2);
            let len = normal.length();
            if len < f32::EPSILON {
                continue;
            }
            let ny = (normal.y / len).abs();
            if ny < min_ny {
                continue; // Too steep
            }

            // Find cells covered by this triangle and mark them walkable
            let min_x = ((tri[0].x.min(tri[1].x).min(tri[2].x) - self.origin.x) / self.cell_size)
                .floor()
                .max(0.0) as usize;
            let max_x = ((tri[0].x.max(tri[1].x).max(tri[2].x) - self.origin.x) / self.cell_size)
                .ceil() as usize;
            let min_z = ((tri[0].z.min(tri[1].z).min(tri[2].z) - self.origin.z) / self.cell_size)
                .floor()
                .max(0.0) as usize;
            let max_z = ((tri[0].z.max(tri[1].z).max(tri[2].z) - self.origin.z) / self.cell_size)
                .ceil() as usize;

            let max_x = max_x.min(self.width.saturating_sub(1));
            let max_z = max_z.min(self.depth.saturating_sub(1));

            for z in min_z..=max_z {
                for x in min_x..=max_x {
                    let cx = self.origin.x + (x as f32 + 0.5) * self.cell_size;
                    let cz = self.origin.z + (z as f32 + 0.5) * self.cell_size;
                    if point_in_triangle_xz(cx, cz, tri[0], tri[1], tri[2]) {
                        // Mark the topmost span in this column as walkable
                        let col = &mut self.spans[z * self.width + x];
                        if let Some(top) = col.last_mut() {
                            top.walkable = true;
                        }
                    }
                }
            }
        }
    }

    /// Filter walkable spans by agent clearance height.
    ///
    /// A walkable span needs at least `agent_height` world units of
    /// empty space above it to the next span.
    pub fn filter_clearance(&mut self, agent_height: f32) {
        let clearance_voxels = (agent_height / self.cell_height).ceil() as u16;

        for col in &mut self.spans {
            col.sort_by_key(|s| s.min_y);
            let len = col.len();
            for i in 0..len {
                if !col[i].walkable {
                    continue;
                }
                // Check clearance to next span above
                if i + 1 < len {
                    let gap = col[i + 1].min_y.saturating_sub(col[i].max_y);
                    if gap < clearance_voxels {
                        col[i].walkable = false;
                    }
                }
                // Top span always has infinite clearance (stays walkable)
            }
        }
    }

    /// Erode walkable areas by agent radius.
    ///
    /// Marks border walkable cells as unwalkable if they are within
    /// `agent_radius` of a non-walkable cell.
    pub fn erode_walkable(&mut self, agent_radius: f32) {
        let radius_cells = (agent_radius / self.cell_size).ceil() as i32;
        if radius_cells <= 0 {
            return;
        }

        // Build a walkable mask
        let len = self.width * self.depth;
        let mut walkable_mask = vec![false; len];
        for z in 0..self.depth {
            for x in 0..self.width {
                let col = &self.spans[z * self.width + x];
                walkable_mask[z * self.width + x] = col.iter().any(|s| s.walkable);
            }
        }

        // Distance-based erosion
        let mut erode = vec![false; len];
        for z in 0..self.depth {
            for x in 0..self.width {
                if !walkable_mask[z * self.width + x] {
                    continue;
                }
                // Check if any non-walkable cell is within radius
                let mut near_edge = false;
                'outer: for dz in -radius_cells..=radius_cells {
                    for dx in -radius_cells..=radius_cells {
                        if dx * dx + dz * dz > radius_cells * radius_cells {
                            continue;
                        }
                        let nx = x as i32 + dx;
                        let nz = z as i32 + dz;
                        if nx < 0 || nz < 0 || nx >= self.width as i32 || nz >= self.depth as i32 {
                            near_edge = true;
                            break 'outer;
                        }
                        if !walkable_mask[nz as usize * self.width + nx as usize] {
                            near_edge = true;
                            break 'outer;
                        }
                    }
                }
                if near_edge {
                    erode[z * self.width + x] = true;
                }
            }
        }

        // Apply erosion
        for z in 0..self.depth {
            for x in 0..self.width {
                if erode[z * self.width + x] {
                    let col = &mut self.spans[z * self.width + x];
                    for span in col.iter_mut() {
                        span.walkable = false;
                    }
                }
            }
        }
    }
}

// ---------------------------------------------------------------------------
// Navmesh generation from heightfield
// ---------------------------------------------------------------------------

/// Bake a 2D NavMesh from a heightfield.
///
/// Extracts walkable regions, traces contours, and generates convex
/// polygons projected onto the XZ plane.
///
/// This is the main entry point for heightfield-based navmesh generation.
#[cfg_attr(feature = "logging", instrument(skip(hf)))]
#[must_use]
pub fn bake_from_heightfield(hf: &Heightfield, config: &HeightfieldConfig) -> NavMesh {
    // Step 1: Build region IDs from walkable cells using flood-fill
    let regions = build_regions(hf, config.min_region_area);

    // Step 2: Trace contours from region boundaries
    let contours = trace_contours(hf, &regions);

    // Step 3: Convert contours to navmesh polygons
    build_navmesh_from_contours(hf, &contours)
}

/// Full pipeline: rasterize triangles and bake a navmesh.
///
/// Convenience function that runs the complete pipeline:
/// rasterize -> mark walkable -> filter clearance -> erode -> bake.
#[cfg_attr(feature = "logging", instrument(skip(triangles)))]
#[must_use]
pub fn bake_navmesh_from_geometry(triangles: &[[Vec3; 3]], config: &HeightfieldConfig) -> NavMesh {
    if triangles.is_empty() {
        return NavMesh::new();
    }

    // Compute bounds
    let mut min = Vec3::new(f32::INFINITY, f32::INFINITY, f32::INFINITY);
    let mut max = Vec3::new(f32::NEG_INFINITY, f32::NEG_INFINITY, f32::NEG_INFINITY);
    for tri in triangles {
        for v in tri {
            min.x = min.x.min(v.x);
            min.y = min.y.min(v.y);
            min.z = min.z.min(v.z);
            max.x = max.x.max(v.x);
            max.y = max.y.max(v.y);
            max.z = max.z.max(v.z);
        }
    }

    // Expand bounds slightly
    min.x -= config.cell_size;
    min.y -= config.cell_height;
    min.z -= config.cell_size;
    max.x += config.cell_size;
    max.y += config.cell_height;
    max.z += config.cell_size;

    let mut hf = Heightfield::new(min, max, config.cell_size, config.cell_height);
    hf.rasterize_triangles(triangles);
    hf.mark_walkable_from_triangles(triangles, config.max_slope);
    hf.filter_clearance(config.agent_height);
    hf.erode_walkable(config.agent_radius);

    bake_from_heightfield(&hf, config)
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/// Point-in-triangle test on XZ plane.
#[inline]
fn point_in_triangle_xz(px: f32, pz: f32, v0: Vec3, v1: Vec3, v2: Vec3) -> bool {
    let d1 = sign_xz(px, pz, v0.x, v0.z, v1.x, v1.z);
    let d2 = sign_xz(px, pz, v1.x, v1.z, v2.x, v2.z);
    let d3 = sign_xz(px, pz, v2.x, v2.z, v0.x, v0.z);
    let has_neg = (d1 < 0.0) || (d2 < 0.0) || (d3 < 0.0);
    let has_pos = (d1 > 0.0) || (d2 > 0.0) || (d3 > 0.0);
    !(has_neg && has_pos)
}

#[inline]
fn sign_xz(px: f32, pz: f32, x1: f32, z1: f32, x2: f32, z2: f32) -> f32 {
    (px - x2) * (z1 - z2) - (x1 - x2) * (pz - z2)
}

/// Interpolate Y coordinate at (px, pz) using barycentric coords on triangle.
#[inline]
fn barycentric_y(px: f32, pz: f32, v0: Vec3, v1: Vec3, v2: Vec3) -> Option<f32> {
    let denom = (v1.z - v2.z) * (v0.x - v2.x) + (v2.x - v1.x) * (v0.z - v2.z);
    if denom.abs() < f32::EPSILON {
        return None;
    }
    let inv = 1.0 / denom;
    let u = ((v1.z - v2.z) * (px - v2.x) + (v2.x - v1.x) * (pz - v2.z)) * inv;
    let v = ((v2.z - v0.z) * (px - v2.x) + (v0.x - v2.x) * (pz - v2.z)) * inv;
    let w = 1.0 - u - v;
    Some(u * v0.y + v * v1.y + w * v2.y)
}

/// Build regions from walkable cells using flood-fill.
/// Returns a grid of region IDs (0 = non-walkable).
fn build_regions(hf: &Heightfield, min_area: usize) -> Vec<u32> {
    let len = hf.width * hf.depth;
    let mut region_ids = vec![0u32; len];
    let mut current_region = 1u32;

    for z in 0..hf.depth {
        for x in 0..hf.width {
            let idx = z * hf.width + x;
            if region_ids[idx] != 0 {
                continue;
            }
            let col = &hf.spans[idx];
            if !col.iter().any(|s| s.walkable) {
                continue;
            }

            // Flood-fill from this cell
            let mut stack = vec![(x, z)];
            let mut area = 0usize;
            region_ids[idx] = current_region;

            while let Some((cx, cz)) = stack.pop() {
                area += 1;
                for (dx, dz) in [(0i32, 1), (0, -1), (1, 0), (-1, 0)] {
                    let nx = cx as i32 + dx;
                    let nz = cz as i32 + dz;
                    if nx < 0 || nz < 0 || nx >= hf.width as i32 || nz >= hf.depth as i32 {
                        continue;
                    }
                    let nx = nx as usize;
                    let nz = nz as usize;
                    let ni = nz * hf.width + nx;
                    if region_ids[ni] != 0 {
                        continue;
                    }
                    if !hf.spans[ni].iter().any(|s| s.walkable) {
                        continue;
                    }
                    region_ids[ni] = current_region;
                    stack.push((nx, nz));
                }
            }

            // Remove small regions
            if area < min_area {
                for rid in region_ids.iter_mut() {
                    if *rid == current_region {
                        *rid = 0;
                    }
                }
            } else {
                current_region += 1;
            }
        }
    }

    region_ids
}

/// Trace contour polygons from region boundaries.
/// Returns a list of contour vertex lists (in XZ grid coords).
fn trace_contours(hf: &Heightfield, regions: &[u32]) -> Vec<Vec<(usize, usize)>> {
    let max_region = regions.iter().copied().max().unwrap_or(0);
    let mut contours = Vec::new();

    for region_id in 1..=max_region {
        // Find boundary cells of this region
        let mut boundary = Vec::new();
        for z in 0..hf.depth {
            for x in 0..hf.width {
                if regions[z * hf.width + x] != region_id {
                    continue;
                }
                // Check if this cell is on the region boundary
                let is_boundary = [(0i32, 1), (0, -1), (1, 0), (-1, 0)]
                    .iter()
                    .any(|&(dx, dz)| {
                        let nx = x as i32 + dx;
                        let nz = z as i32 + dz;
                        if nx < 0 || nz < 0 || nx >= hf.width as i32 || nz >= hf.depth as i32 {
                            return true;
                        }
                        regions[nz as usize * hf.width + nx as usize] != region_id
                    });
                if is_boundary {
                    boundary.push((x, z));
                }
            }
        }

        if !boundary.is_empty() {
            contours.push(boundary);
        }
    }

    contours
}

/// Build navmesh from contour boundaries.
fn build_navmesh_from_contours(hf: &Heightfield, contours: &[Vec<(usize, usize)>]) -> NavMesh {
    let mut mesh = NavMesh::new();
    let mut poly_id = 0u32;

    for contour in contours {
        if contour.len() < 3 {
            continue;
        }

        // Compute convex hull of boundary cells projected to world coords
        let vertices: Vec<Vec2> = compute_convex_hull(
            &contour
                .iter()
                .map(|&(x, z)| {
                    Vec2::new(
                        hf.origin.x + (x as f32 + 0.5) * hf.cell_size,
                        hf.origin.z + (z as f32 + 0.5) * hf.cell_size,
                    )
                })
                .collect::<Vec<_>>(),
        );

        if vertices.len() < 3 {
            continue;
        }

        mesh.add_poly(NavPoly {
            id: NavPolyId(poly_id),
            vertices,
            neighbors: Vec::new(),
            cost: 1.0,
            layer: 0,
        });
        poly_id += 1;
    }

    // Auto-detect neighbors (shared edges)
    detect_neighbors(&mut mesh);

    mesh
}

/// Compute convex hull of 2D points (Andrew's monotone chain).
fn compute_convex_hull(points: &[Vec2]) -> Vec<Vec2> {
    if points.len() < 3 {
        return points.to_vec();
    }

    let mut sorted = points.to_vec();
    sorted.sort_by(|a, b| {
        a.x.partial_cmp(&b.x)
            .unwrap_or(std::cmp::Ordering::Equal)
            .then(a.y.partial_cmp(&b.y).unwrap_or(std::cmp::Ordering::Equal))
    });
    sorted.dedup_by(|a, b| (a.x - b.x).abs() < f32::EPSILON && (a.y - b.y).abs() < f32::EPSILON);

    if sorted.len() < 3 {
        return sorted;
    }

    let mut hull = Vec::with_capacity(sorted.len() * 2);

    // Lower hull
    for &p in &sorted {
        while hull.len() >= 2 {
            let len = hull.len();
            if cross_2d(hull[len - 2], hull[len - 1], p) <= 0.0 {
                hull.pop();
            } else {
                break;
            }
        }
        hull.push(p);
    }

    // Upper hull
    let lower_len = hull.len() + 1;
    for &p in sorted.iter().rev() {
        while hull.len() >= lower_len {
            let len = hull.len();
            if cross_2d(hull[len - 2], hull[len - 1], p) <= 0.0 {
                hull.pop();
            } else {
                break;
            }
        }
        hull.push(p);
    }

    hull.pop(); // Remove last point (same as first)
    hull
}

#[inline]
fn cross_2d(o: Vec2, a: Vec2, b: Vec2) -> f32 {
    (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x)
}

/// Auto-detect neighbors by shared edges.
fn detect_neighbors(mesh: &mut NavMesh) {
    let eps = 1e-3;
    let polys: Vec<(NavPolyId, Vec<Vec2>)> = mesh
        .polys()
        .iter()
        .map(|p| (p.id, p.vertices.clone()))
        .collect();

    // Build neighbor map
    let mut neighbor_map: Vec<Vec<NavPolyId>> = vec![Vec::new(); polys.len()];
    for i in 0..polys.len() {
        for j in (i + 1)..polys.len() {
            if shares_edge(&polys[i].1, &polys[j].1, eps) {
                neighbor_map[i].push(polys[j].0);
                neighbor_map[j].push(polys[i].0);
            }
        }
    }

    // Rebuild mesh with neighbors
    let old_polys: Vec<NavPoly> = mesh.polys().to_vec();
    *mesh = NavMesh::new();
    for (idx, poly) in old_polys.into_iter().enumerate() {
        mesh.add_poly(NavPoly {
            id: poly.id,
            vertices: poly.vertices,
            neighbors: neighbor_map.get(idx).cloned().unwrap_or_default(),
            cost: poly.cost,
            layer: poly.layer,
        });
    }
}

fn shares_edge(a: &[Vec2], b: &[Vec2], eps: f32) -> bool {
    let mut shared = 0;
    for va in a {
        for vb in b {
            if va.distance(*vb) < eps {
                shared += 1;
                if shared >= 2 {
                    return true;
                }
            }
        }
    }
    false
}

#[cfg(test)]
mod tests {
    use super::*;

    fn flat_floor_triangles() -> Vec<[Vec3; 3]> {
        // Two triangles forming a 10x10 flat floor at y=0
        vec![
            [
                Vec3::new(0.0, 0.0, 0.0),
                Vec3::new(10.0, 0.0, 0.0),
                Vec3::new(10.0, 0.0, 10.0),
            ],
            [
                Vec3::new(0.0, 0.0, 0.0),
                Vec3::new(10.0, 0.0, 10.0),
                Vec3::new(0.0, 0.0, 10.0),
            ],
        ]
    }

    #[test]
    fn heightfield_new() {
        let hf = Heightfield::new(Vec3::ZERO, Vec3::new(10.0, 5.0, 10.0), 1.0, 0.5);
        assert_eq!(hf.width(), 10);
        assert_eq!(hf.depth(), 10);
    }

    #[test]
    fn heightfield_rasterize_flat() {
        let tris = flat_floor_triangles();
        let mut hf = Heightfield::new(
            Vec3::new(-1.0, -1.0, -1.0),
            Vec3::new(11.0, 1.0, 11.0),
            1.0,
            0.5,
        );
        hf.rasterize_triangles(&tris);
        // Center cells should have spans
        let spans = hf.spans_at(5, 5);
        assert!(!spans.is_empty());
    }

    #[test]
    fn heightfield_mark_walkable() {
        let tris = flat_floor_triangles();
        let mut hf = Heightfield::new(
            Vec3::new(-1.0, -1.0, -1.0),
            Vec3::new(11.0, 1.0, 11.0),
            1.0,
            0.5,
        );
        hf.rasterize_triangles(&tris);
        hf.mark_walkable(std::f32::consts::FRAC_PI_4);
        // All spans should be walkable (flat floor)
        let spans = hf.spans_at(5, 5);
        assert!(spans.iter().any(|s| s.walkable));
    }

    #[test]
    fn heightfield_filter_clearance() {
        let mut hf = Heightfield::new(Vec3::ZERO, Vec3::new(5.0, 10.0, 5.0), 1.0, 0.5);
        // Add two spans close together (no clearance)
        hf.add_span(2, 2, 0, 1);
        hf.add_span(2, 2, 3, 4); // Only 1 voxel gap
        hf.spans[2 * hf.width + 2].sort_by_key(|s| s.min_y);
        hf.spans[2 * hf.width + 2][0].walkable = true;
        hf.spans[2 * hf.width + 2][1].walkable = true;

        hf.filter_clearance(2.0); // Need 4 voxels clearance at 0.5 cell_height
        let spans = hf.spans_at(2, 2);
        // Bottom span should no longer be walkable (gap too small)
        assert!(!spans[0].walkable);
        // Top span stays walkable (infinite clearance above)
        assert!(spans[1].walkable);
    }

    #[test]
    fn bake_full_pipeline() {
        let tris = flat_floor_triangles();
        let config = HeightfieldConfig {
            cell_size: 1.0,
            cell_height: 0.5,
            max_slope: std::f32::consts::FRAC_PI_4,
            agent_height: 2.0,
            agent_radius: 0.0, // No erosion for simple test
            min_region_area: 1,
        };
        let mesh = bake_navmesh_from_geometry(&tris, &config);
        assert!(mesh.poly_count() > 0);
    }

    #[test]
    fn bake_empty_triangles() {
        let config = HeightfieldConfig::default();
        let mesh = bake_navmesh_from_geometry(&[], &config);
        assert_eq!(mesh.poly_count(), 0);
    }

    #[test]
    fn bake_produces_pathable_mesh() {
        let tris = flat_floor_triangles();
        let config = HeightfieldConfig {
            cell_size: 0.5,
            cell_height: 0.2,
            max_slope: std::f32::consts::FRAC_PI_4,
            agent_height: 2.0,
            agent_radius: 0.0,
            min_region_area: 1,
        };
        let mesh = bake_navmesh_from_geometry(&tris, &config);
        // Should produce a non-empty mesh from the floor geometry
        assert!(mesh.poly_count() > 0);
    }

    #[test]
    fn heightfield_rasterize_indexed() {
        let verts = vec![
            Vec3::new(0.0, 0.0, 0.0),
            Vec3::new(10.0, 0.0, 0.0),
            Vec3::new(10.0, 0.0, 10.0),
            Vec3::new(0.0, 0.0, 10.0),
        ];
        let indices = vec![0, 1, 2, 0, 2, 3];
        let mut hf = Heightfield::new(
            Vec3::new(-1.0, -1.0, -1.0),
            Vec3::new(11.0, 1.0, 11.0),
            1.0,
            0.5,
        );
        hf.rasterize_indexed(&verts, &indices);
        assert!(!hf.spans_at(5, 5).is_empty());
    }

    #[test]
    fn heightfield_config_default() {
        let config = HeightfieldConfig::default();
        assert!(config.cell_size > 0.0);
        assert!(config.agent_height > 0.0);
    }

    #[test]
    fn heightfield_serde_roundtrip() {
        let hf = Heightfield::new(Vec3::ZERO, Vec3::new(5.0, 5.0, 5.0), 1.0, 0.5);
        let json = serde_json::to_string(&hf).expect("serialize heightfield");
        let deserialized: Heightfield =
            serde_json::from_str(&json).expect("deserialize heightfield");
        assert_eq!(deserialized.width(), hf.width());
    }

    #[test]
    fn heightfield_config_serde_roundtrip() {
        let config = HeightfieldConfig::default();
        let json = serde_json::to_string(&config).expect("serialize config");
        let deserialized: HeightfieldConfig =
            serde_json::from_str(&json).expect("deserialize config");
        assert!((deserialized.cell_size - config.cell_size).abs() < f32::EPSILON);
    }

    #[test]
    fn convex_hull_basic() {
        let points = vec![
            Vec2::new(0.0, 0.0),
            Vec2::new(1.0, 0.0),
            Vec2::new(0.5, 0.5),
            Vec2::new(0.0, 1.0),
            Vec2::new(1.0, 1.0),
        ];
        let hull = compute_convex_hull(&points);
        assert_eq!(hull.len(), 4); // Square hull
    }

    #[test]
    fn steep_slope_not_walkable() {
        // Nearly vertical triangle
        let tris = vec![[
            Vec3::new(0.0, 0.0, 0.0),
            Vec3::new(0.0, 10.0, 0.0),
            Vec3::new(0.0, 10.0, 10.0),
        ]];
        let mut hf = Heightfield::new(
            Vec3::new(-1.0, -1.0, -1.0),
            Vec3::new(1.0, 11.0, 11.0),
            1.0,
            0.5,
        );
        hf.rasterize_triangles(&tris);
        hf.mark_walkable_from_triangles(&tris, std::f32::consts::FRAC_PI_4);
        // Vertical triangle should not be walkable
        for z in 0..hf.depth() {
            for x in 0..hf.width() {
                for span in hf.spans_at(x, z) {
                    assert!(!span.walkable, "Vertical surface should not be walkable");
                }
            }
        }
    }
}

//! Hierarchical Pathfinding A* (HPA*).
//!
//! Divides a [`NavGrid`] into rectangular clusters, identifies entrances
//! between adjacent clusters, and builds an abstract graph for fast
//! long-range pathfinding.

use serde::{Deserialize, Serialize};

#[cfg(feature = "logging")]
use tracing::instrument;

use crate::grid::{GridPos, NavGrid};

/// Identifier for a cluster in the grid hierarchy.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct ClusterId {
    /// Cluster column (x / cluster_size).
    pub cx: u32,
    /// Cluster row (y / cluster_size).
    pub cy: u32,
}

/// An entrance between two adjacent clusters.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct Entrance {
    /// Cells on the border — each pair is (cell_in_cluster_a, cell_in_cluster_b).
    pub cells: Vec<(GridPos, GridPos)>,
    /// The two clusters this entrance connects.
    pub cluster_a: ClusterId,
    pub cluster_b: ClusterId,
}

/// Grid clustering for HPA*.
#[derive(Debug, Clone)]
pub struct GridClusters {
    cluster_size: u32,
    clusters_wide: u32,
    clusters_high: u32,
    entrances: Vec<Entrance>,
}

impl GridClusters {
    /// Build clusters and identify entrances for the given grid.
    ///
    /// `cluster_size` is the width/height of each cluster in cells (e.g., 8 or 16).
    #[cfg_attr(feature = "logging", instrument(skip(grid), fields(w = grid.width(), h = grid.height())))]
    #[must_use]
    pub fn build(grid: &NavGrid, cluster_size: u32) -> Self {
        let clusters_wide = (grid.width() as u32).div_ceil(cluster_size);
        let clusters_high = (grid.height() as u32).div_ceil(cluster_size);

        let mut gc = Self {
            cluster_size,
            clusters_wide,
            clusters_high,
            entrances: Vec::new(),
        };

        gc.find_entrances(grid);
        gc
    }

    /// Which cluster a grid position belongs to.
    #[must_use]
    pub fn cluster_of(&self, pos: GridPos) -> ClusterId {
        ClusterId {
            cx: (pos.x as u32) / self.cluster_size,
            cy: (pos.y as u32) / self.cluster_size,
        }
    }

    /// Cluster size in cells.
    #[must_use]
    pub fn cluster_size(&self) -> u32 {
        self.cluster_size
    }

    /// Number of clusters wide.
    #[must_use]
    pub fn clusters_wide(&self) -> u32 {
        self.clusters_wide
    }

    /// Number of clusters high.
    #[must_use]
    pub fn clusters_high(&self) -> u32 {
        self.clusters_high
    }

    /// All identified entrances.
    #[must_use]
    pub fn entrances(&self) -> &[Entrance] {
        &self.entrances
    }

    /// Bounding box of a cluster in grid coordinates (inclusive).
    #[must_use]
    pub fn cluster_bounds(&self, id: ClusterId, grid: &NavGrid) -> (GridPos, GridPos) {
        let min_x = (id.cx * self.cluster_size) as i32;
        let min_y = (id.cy * self.cluster_size) as i32;
        let max_x = ((id.cx + 1) * self.cluster_size) as i32 - 1;
        let max_y = ((id.cy + 1) * self.cluster_size) as i32 - 1;
        (
            GridPos::new(min_x, min_y),
            GridPos::new(
                max_x.min(grid.width() as i32 - 1),
                max_y.min(grid.height() as i32 - 1),
            ),
        )
    }

    /// Scan all adjacent cluster pairs and identify entrances.
    fn find_entrances(&mut self, grid: &NavGrid) {
        // Horizontal borders (between cluster (cx, cy) and (cx+1, cy))
        for cy in 0..self.clusters_high {
            for cx in 0..(self.clusters_wide - 1) {
                let border_x = ((cx + 1) * self.cluster_size) as i32;
                let y_start = (cy * self.cluster_size) as i32;
                let y_end =
                    (((cy + 1) * self.cluster_size) as i32 - 1).min(grid.height() as i32 - 1);

                let cluster_a = ClusterId { cx, cy };
                let cluster_b = ClusterId { cx: cx + 1, cy };

                self.scan_border(
                    grid,
                    border_x - 1,
                    border_x,
                    y_start,
                    y_end,
                    true,
                    cluster_a,
                    cluster_b,
                );
            }
        }

        // Vertical borders (between cluster (cx, cy) and (cx, cy+1))
        for cx in 0..self.clusters_wide {
            for cy in 0..(self.clusters_high - 1) {
                let border_y = ((cy + 1) * self.cluster_size) as i32;
                let x_start = (cx * self.cluster_size) as i32;
                let x_end =
                    (((cx + 1) * self.cluster_size) as i32 - 1).min(grid.width() as i32 - 1);

                let cluster_a = ClusterId { cx, cy };
                let cluster_b = ClusterId { cx, cy: cy + 1 };

                self.scan_border(
                    grid,
                    border_y - 1,
                    border_y,
                    x_start,
                    x_end,
                    false,
                    cluster_a,
                    cluster_b,
                );
            }
        }
    }

    /// Scan a border between two clusters and create entrances from contiguous
    /// runs of walkable cell pairs.
    #[allow(clippy::too_many_arguments)]
    fn scan_border(
        &mut self,
        grid: &NavGrid,
        a_coord: i32,
        b_coord: i32,
        range_start: i32,
        range_end: i32,
        horizontal: bool,
        cluster_a: ClusterId,
        cluster_b: ClusterId,
    ) {
        let mut current_entrance: Vec<(GridPos, GridPos)> = Vec::new();

        for i in range_start..=range_end {
            let (ax, ay, bx, by) = if horizontal {
                (a_coord, i, b_coord, i)
            } else {
                (i, a_coord, i, b_coord)
            };

            if grid.is_walkable(ax, ay) && grid.is_walkable(bx, by) {
                current_entrance.push((GridPos::new(ax, ay), GridPos::new(bx, by)));
            } else if !current_entrance.is_empty() {
                self.entrances.push(Entrance {
                    cells: std::mem::take(&mut current_entrance),
                    cluster_a,
                    cluster_b,
                });
            }
        }

        if !current_entrance.is_empty() {
            self.entrances.push(Entrance {
                cells: current_entrance,
                cluster_a,
                cluster_b,
            });
        }
    }
}

/// A node in the abstract graph — represents one side of an entrance.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct AbstractNodeId(pub u32);

/// An edge in the abstract graph.
#[derive(Debug, Clone)]
struct AbstractEdge {
    to: AbstractNodeId,
    cost: f32,
}

/// Abstract graph for hierarchical pathfinding.
///
/// Nodes are representative cells at cluster entrances.
/// Edges connect entrance pairs (inter-cluster, cost = cell distance)
/// and entrances within the same cluster (intra-cluster, cost = A* path cost).
#[derive(Debug, Clone)]
pub struct AbstractGraph {
    /// Position of each node.
    node_positions: Vec<GridPos>,
    /// Cluster each node belongs to.
    node_clusters: Vec<ClusterId>,
    /// Adjacency list.
    edges: Vec<Vec<AbstractEdge>>,
    /// Cached intra-cluster paths: (node_a, node_b) → grid path.
    /// Keyed with (min_id, max_id) for symmetry.
    path_cache: std::collections::HashMap<(u32, u32), Vec<GridPos>>,
}

impl AbstractGraph {
    /// Build the abstract graph from grid clusters.
    #[cfg_attr(feature = "logging", instrument(skip(grid, clusters)))]
    #[must_use]
    pub fn build(grid: &NavGrid, clusters: &GridClusters) -> Self {
        let mut graph = Self {
            node_positions: Vec::new(),
            node_clusters: Vec::new(),
            edges: Vec::new(),
            path_cache: std::collections::HashMap::new(),
        };

        // For each entrance, pick a representative cell on each side
        // and create two nodes + an inter-cluster edge.
        // We use the middle cell pair of each entrance.
        let mut cluster_nodes: std::collections::HashMap<ClusterId, Vec<AbstractNodeId>> =
            std::collections::HashMap::new();

        for entrance in clusters.entrances() {
            let mid = entrance.cells.len() / 2;
            let (cell_a, cell_b) = entrance.cells[mid];

            let id_a = graph.add_node(cell_a, entrance.cluster_a);
            let id_b = graph.add_node(cell_b, entrance.cluster_b);

            // Inter-cluster edge (adjacent cells, cost = 1.0)
            graph.add_edge(id_a, id_b, 1.0);
            graph.add_edge(id_b, id_a, 1.0);

            cluster_nodes
                .entry(entrance.cluster_a)
                .or_default()
                .push(id_a);
            cluster_nodes
                .entry(entrance.cluster_b)
                .or_default()
                .push(id_b);
        }

        // Intra-cluster edges: for each cluster, connect all its entrance nodes
        // via A* within the cluster bounds. Cache the paths for O(1) refinement.
        for nodes in cluster_nodes.values() {
            for i in 0..nodes.len() {
                for j in (i + 1)..nodes.len() {
                    let pos_a = graph.node_positions[nodes[i].0 as usize];
                    let pos_b = graph.node_positions[nodes[j].0 as usize];

                    if let Some(path) = grid.find_path(pos_a, pos_b) {
                        let cost: f32 = path.windows(2).map(|w| w[0].octile_distance(w[1])).sum();
                        graph.add_edge(nodes[i], nodes[j], cost);
                        graph.add_edge(nodes[j], nodes[i], cost);

                        let key = Self::cache_key(nodes[i], nodes[j]);
                        graph.path_cache.insert(key, path);
                    }
                }
            }
        }

        graph
    }

    /// Number of nodes.
    #[must_use]
    pub fn node_count(&self) -> usize {
        self.node_positions.len()
    }

    /// Number of edges (directed).
    #[must_use]
    pub fn edge_count(&self) -> usize {
        self.edges.iter().map(|e| e.len()).sum()
    }

    /// Position of a node.
    #[must_use]
    pub fn node_position(&self, id: AbstractNodeId) -> GridPos {
        self.node_positions[id.0 as usize]
    }

    /// Cluster of a node.
    #[must_use]
    pub fn node_cluster(&self, id: AbstractNodeId) -> ClusterId {
        self.node_clusters[id.0 as usize]
    }

    fn add_node(&mut self, pos: GridPos, cluster: ClusterId) -> AbstractNodeId {
        let id = AbstractNodeId(self.node_positions.len() as u32);
        self.node_positions.push(pos);
        self.node_clusters.push(cluster);
        self.edges.push(Vec::new());
        id
    }

    fn add_edge(&mut self, from: AbstractNodeId, to: AbstractNodeId, cost: f32) {
        self.edges[from.0 as usize].push(AbstractEdge { to, cost });
    }

    /// Symmetric cache key — always (min, max).
    fn cache_key(a: AbstractNodeId, b: AbstractNodeId) -> (u32, u32) {
        if a.0 <= b.0 { (a.0, b.0) } else { (b.0, a.0) }
    }

    /// Find a path on the abstract graph using A*.
    ///
    /// Temporarily inserts `start` and `goal` as nodes, connects them to
    /// entrance nodes in their respective clusters, runs A* on the abstract
    /// graph, then refines through intra-cluster A* paths on the base grid.
    ///
    /// Returns `None` if no path exists.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid, clusters)))]
    #[must_use]
    pub fn find_path(
        &self,
        grid: &NavGrid,
        clusters: &GridClusters,
        start: GridPos,
        goal: GridPos,
    ) -> Option<Vec<GridPos>> {
        if !grid.is_walkable(start.x, start.y) || !grid.is_walkable(goal.x, goal.y) {
            return None;
        }
        if start == goal {
            return Some(vec![start]);
        }

        let start_cluster = clusters.cluster_of(start);
        let goal_cluster = clusters.cluster_of(goal);

        // Same cluster — just use base A*
        if start_cluster == goal_cluster {
            return grid.find_path(start, goal);
        }

        // Build temporary extended graph with start/goal inserted
        let n = self.node_positions.len();
        let start_id = AbstractNodeId(n as u32);
        let goal_id = AbstractNodeId((n + 1) as u32);

        // Collect edges for temporary nodes
        let mut start_edges: Vec<AbstractEdge> = Vec::new();
        let mut goal_edges_incoming: Vec<(AbstractNodeId, f32)> = Vec::new();

        for i in 0..n {
            let node_id = AbstractNodeId(i as u32);
            let node_cluster = self.node_clusters[i];
            let node_pos = self.node_positions[i];

            // Connect start to nodes in its cluster
            if node_cluster == start_cluster
                && let Some(path) = grid.find_path(start, node_pos)
            {
                let cost: f32 = path.windows(2).map(|w| w[0].octile_distance(w[1])).sum();
                start_edges.push(AbstractEdge { to: node_id, cost });
            }

            // Connect nodes in goal's cluster to goal
            if node_cluster == goal_cluster
                && let Some(path) = grid.find_path(node_pos, goal)
            {
                let cost: f32 = path.windows(2).map(|w| w[0].octile_distance(w[1])).sum();
                goal_edges_incoming.push((node_id, cost));
            }
        }

        // A* on abstract graph with temporary nodes
        let total_nodes = n + 2;
        let mut g_score = vec![f32::INFINITY; total_nodes];
        let mut came_from: Vec<Option<u32>> = vec![None; total_nodes];
        let mut closed = vec![false; total_nodes];

        g_score[start_id.0 as usize] = 0.0;
        let mut open = std::collections::BinaryHeap::new();

        let h = start.octile_distance(goal);
        open.push(std::cmp::Reverse((OrderedFloat(h), start_id.0)));

        while let Some(std::cmp::Reverse((OrderedFloat(_f), current_raw))) = open.pop() {
            let current = current_raw as usize;

            if current_raw == goal_id.0 {
                // Reconstruct abstract path
                let abstract_path = self.reconstruct_abstract_path(&came_from, start_id, goal_id);
                return self.refine_path(grid, &abstract_path, start, goal);
            }

            if closed[current] {
                continue;
            }
            closed[current] = true;

            // Get edges for current node
            let edges: &[AbstractEdge] = if current_raw == start_id.0 {
                &start_edges
            } else if current_raw == goal_id.0 {
                &[]
            } else {
                &self.edges[current]
            };

            for edge in edges {
                let next = edge.to.0 as usize;
                if closed[next] {
                    continue;
                }
                let tentative_g = g_score[current] + edge.cost;
                if tentative_g < g_score[next] {
                    g_score[next] = tentative_g;
                    came_from[next] = Some(current_raw);
                    let next_pos = if edge.to == goal_id {
                        goal
                    } else {
                        self.node_positions[next]
                    };
                    let h = next_pos.octile_distance(goal);
                    open.push(std::cmp::Reverse((
                        OrderedFloat(tentative_g + h),
                        edge.to.0,
                    )));
                }
            }

            // Also check goal edges from current node
            if current_raw != start_id.0 && current_raw != goal_id.0 {
                for &(node_id, cost) in &goal_edges_incoming {
                    if node_id.0 as usize == current {
                        let next = goal_id.0 as usize;
                        if !closed[next] {
                            let tentative_g = g_score[current] + cost;
                            if tentative_g < g_score[next] {
                                g_score[next] = tentative_g;
                                came_from[next] = Some(current_raw);
                                let h = goal.octile_distance(goal); // 0
                                open.push(std::cmp::Reverse((
                                    OrderedFloat(tentative_g + h),
                                    goal_id.0,
                                )));
                            }
                        }
                    }
                }
            }
        }

        None
    }

    fn reconstruct_abstract_path(
        &self,
        came_from: &[Option<u32>],
        start_id: AbstractNodeId,
        goal_id: AbstractNodeId,
    ) -> Vec<AbstractNodeId> {
        let mut path = Vec::new();
        let mut current = goal_id.0;
        loop {
            path.push(AbstractNodeId(current));
            if current == start_id.0 {
                break;
            }
            match came_from[current as usize] {
                Some(prev) => current = prev,
                None => break,
            }
        }
        path.reverse();
        path
    }

    /// Refine an abstract path into a full grid path.
    ///
    /// Uses cached intra-cluster paths for known node pairs (O(1) lookup).
    /// Only calls A* for start/goal connections to entrance nodes.
    fn refine_path(
        &self,
        grid: &NavGrid,
        abstract_path: &[AbstractNodeId],
        start: GridPos,
        goal: GridPos,
    ) -> Option<Vec<GridPos>> {
        if abstract_path.len() < 2 {
            return grid.find_path(start, goal);
        }

        let n = self.node_positions.len() as u32;
        let mut full_path: Vec<GridPos> = Vec::new();

        for w in abstract_path.windows(2) {
            let is_temp_a = w[0].0 >= n;
            let is_temp_b = w[1].0 >= n;

            let segment = if !is_temp_a && !is_temp_b {
                // Both are permanent nodes — check cache first
                let key = Self::cache_key(w[0], w[1]);
                if let Some(cached) = self.path_cache.get(&key) {
                    // Cache stores A→B; if we need B→A, reverse it
                    if key.0 == w[0].0 {
                        cached.clone()
                    } else {
                        let mut rev = cached.clone();
                        rev.reverse();
                        rev
                    }
                } else {
                    // Inter-cluster edge (adjacent cells) — direct step
                    let from_pos = self.node_positions[w[0].0 as usize];
                    let to_pos = self.node_positions[w[1].0 as usize];
                    vec![from_pos, to_pos]
                }
            } else {
                // Temporary node (start or goal) — A* on base grid
                let from_pos = if is_temp_a {
                    start
                } else {
                    self.node_positions[w[0].0 as usize]
                };
                let to_pos = if is_temp_b {
                    goal
                } else {
                    self.node_positions[w[1].0 as usize]
                };
                grid.find_path(from_pos, to_pos)?
            };

            if full_path.is_empty() {
                full_path.extend_from_slice(&segment);
            } else if segment.len() > 1 {
                full_path.extend_from_slice(&segment[1..]);
            }
        }

        Some(full_path)
    }
}

/// Wrapper for f32 ordering in BinaryHeap (min-heap via Reverse).
#[derive(Debug, Clone, Copy, PartialEq)]
struct OrderedFloat(f32);

impl Eq for OrderedFloat {}

impl PartialOrd for OrderedFloat {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for OrderedFloat {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        self.0
            .partial_cmp(&other.0)
            .unwrap_or(std::cmp::Ordering::Equal)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn cluster_of_basic() {
        let grid = NavGrid::new(20, 20, 1.0);
        let gc = GridClusters::build(&grid, 8);

        assert_eq!(
            gc.cluster_of(GridPos::new(0, 0)),
            ClusterId { cx: 0, cy: 0 }
        );
        assert_eq!(
            gc.cluster_of(GridPos::new(7, 7)),
            ClusterId { cx: 0, cy: 0 }
        );
        assert_eq!(
            gc.cluster_of(GridPos::new(8, 0)),
            ClusterId { cx: 1, cy: 0 }
        );
        assert_eq!(
            gc.cluster_of(GridPos::new(16, 16)),
            ClusterId { cx: 2, cy: 2 }
        );
    }

    #[test]
    fn cluster_dimensions() {
        let grid = NavGrid::new(20, 20, 1.0);
        let gc = GridClusters::build(&grid, 8);

        assert_eq!(gc.cluster_size(), 8);
        assert_eq!(gc.clusters_wide(), 3); // ceil(20/8) = 3
        assert_eq!(gc.clusters_high(), 3);
    }

    #[test]
    fn entrances_open_grid() {
        let grid = NavGrid::new(16, 16, 1.0);
        let gc = GridClusters::build(&grid, 8);

        // 2x2 clusters, open grid: should have entrances on all internal borders
        assert!(!gc.entrances().is_empty());

        // Each border should produce exactly 1 entrance (fully open = 1 contiguous run)
        // 1 horizontal border + 1 vertical border = 2 borders total for 2x2
        // Horizontal: cluster(0,0)↔(1,0) and cluster(0,1)↔(1,1) = 2
        // Vertical: cluster(0,0)↔(0,1) and cluster(1,0)↔(1,1) = 2
        assert_eq!(gc.entrances().len(), 4);
    }

    #[test]
    fn entrances_with_wall() {
        let mut grid = NavGrid::new(16, 16, 1.0);
        // Block half the horizontal border between cluster (0,0) and (1,0)
        for y in 0..4 {
            grid.set_walkable(7, y, false); // left side of border
        }

        let gc = GridClusters::build(&grid, 8);

        // The horizontal border between (0,0)↔(1,0) should be split:
        // y=0..3 blocked, y=4..7 open → 1 entrance (the open part)
        let border_entrances: Vec<_> = gc
            .entrances()
            .iter()
            .filter(|e| {
                e.cluster_a == ClusterId { cx: 0, cy: 0 }
                    && e.cluster_b == ClusterId { cx: 1, cy: 0 }
            })
            .collect();

        assert_eq!(border_entrances.len(), 1);
        // Should have 4 cell pairs (y=4,5,6,7)
        assert_eq!(border_entrances[0].cells.len(), 4);
    }

    #[test]
    fn entrances_fully_blocked_border() {
        let mut grid = NavGrid::new(16, 16, 1.0);
        // Block entire horizontal border between cluster (0,0) and (1,0)
        for y in 0..8 {
            grid.set_walkable(7, y, false);
        }

        let gc = GridClusters::build(&grid, 8);

        let border_entrances: Vec<_> = gc
            .entrances()
            .iter()
            .filter(|e| {
                e.cluster_a == ClusterId { cx: 0, cy: 0 }
                    && e.cluster_b == ClusterId { cx: 1, cy: 0 }
            })
            .collect();

        // Fully blocked — no entrances
        assert!(border_entrances.is_empty());
    }

    #[test]
    fn cluster_bounds() {
        let grid = NavGrid::new(20, 20, 1.0);
        let gc = GridClusters::build(&grid, 8);

        let (min, max) = gc.cluster_bounds(ClusterId { cx: 0, cy: 0 }, &grid);
        assert_eq!(min, GridPos::new(0, 0));
        assert_eq!(max, GridPos::new(7, 7));

        // Last cluster may be smaller
        let (min, max) = gc.cluster_bounds(ClusterId { cx: 2, cy: 2 }, &grid);
        assert_eq!(min, GridPos::new(16, 16));
        assert_eq!(max, GridPos::new(19, 19));
    }

    #[test]
    fn entrance_cells_are_adjacent() {
        let grid = NavGrid::new(16, 16, 1.0);
        let gc = GridClusters::build(&grid, 8);

        for entrance in gc.entrances() {
            for (a, b) in &entrance.cells {
                let dx = (a.x - b.x).abs();
                let dy = (a.y - b.y).abs();
                assert_eq!(
                    dx + dy,
                    1,
                    "entrance cells must be adjacent: ({},{}) ({},{})",
                    a.x,
                    a.y,
                    b.x,
                    b.y
                );
            }
        }
    }

    #[test]
    fn single_cluster_no_entrances() {
        let grid = NavGrid::new(5, 5, 1.0);
        let gc = GridClusters::build(&grid, 8);

        assert_eq!(gc.clusters_wide(), 1);
        assert_eq!(gc.clusters_high(), 1);
        assert!(gc.entrances().is_empty());
    }

    // --- Abstract graph tests ---

    #[test]
    fn abstract_graph_open_grid() {
        let grid = NavGrid::new(16, 16, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        // 4 entrances, each produces 2 nodes = 8 nodes
        assert_eq!(graph.node_count(), 8);
        // Each entrance has 2 inter-cluster edges (bidirectional) = 8
        // Plus intra-cluster edges between nodes in the same cluster
        assert!(graph.edge_count() > 8);
    }

    #[test]
    fn abstract_graph_nodes_are_walkable() {
        let grid = NavGrid::new(16, 16, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        for i in 0..graph.node_count() {
            let pos = graph.node_position(AbstractNodeId(i as u32));
            assert!(
                grid.is_walkable(pos.x, pos.y),
                "abstract node at ({},{}) is not walkable",
                pos.x,
                pos.y
            );
        }
    }

    #[test]
    fn abstract_graph_with_wall() {
        let mut grid = NavGrid::new(16, 16, 1.0);
        // Block entire horizontal border between (0,0)↔(1,0)
        for y in 0..8 {
            grid.set_walkable(7, y, false);
        }
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        // Fewer nodes because one border is fully blocked
        assert!(graph.node_count() < 8);
    }

    #[test]
    fn abstract_graph_intra_cluster_edges() {
        let grid = NavGrid::new(24, 8, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        // 3x1 clusters: 2 horizontal borders, each with 1 entrance
        // Cluster (1,0) has 2 entrance nodes (left and right border)
        // They should be connected with an intra-cluster edge
        assert!(graph.edge_count() > 4); // more than just inter-cluster
    }

    #[test]
    fn abstract_graph_empty_grid() {
        let grid = NavGrid::new(5, 5, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        // Single cluster — no entrances, no nodes
        assert_eq!(graph.node_count(), 0);
        assert_eq!(graph.edge_count(), 0);
    }

    // --- HPA* search tests ---

    #[test]
    fn hpa_cross_cluster_path() {
        let grid = NavGrid::new(32, 32, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        let path = graph.find_path(&grid, &clusters, GridPos::new(0, 0), GridPos::new(31, 31));
        assert!(path.is_some());
        let path = path.unwrap();
        assert_eq!(*path.first().unwrap(), GridPos::new(0, 0));
        assert_eq!(*path.last().unwrap(), GridPos::new(31, 31));

        // Path should be contiguous
        for w in path.windows(2) {
            let dx = (w[1].x - w[0].x).abs();
            let dy = (w[1].y - w[0].y).abs();
            assert!(dx <= 1 && dy <= 1 && (dx + dy) > 0);
        }
    }

    #[test]
    fn hpa_same_cluster_path() {
        let grid = NavGrid::new(32, 32, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        // Both in cluster (0,0)
        let path = graph.find_path(&grid, &clusters, GridPos::new(1, 1), GridPos::new(5, 5));
        assert!(path.is_some());
    }

    #[test]
    fn hpa_same_cell() {
        let grid = NavGrid::new(16, 16, 1.0);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        let path = graph.find_path(&grid, &clusters, GridPos::new(3, 3), GridPos::new(3, 3));
        assert_eq!(path, Some(vec![GridPos::new(3, 3)]));
    }

    #[test]
    fn hpa_blocked_start() {
        let mut grid = NavGrid::new(16, 16, 1.0);
        grid.set_walkable(0, 0, false);
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        assert!(
            graph
                .find_path(&grid, &clusters, GridPos::new(0, 0), GridPos::new(15, 15))
                .is_none()
        );
    }

    #[test]
    fn hpa_with_wall() {
        let mut grid = NavGrid::new(32, 32, 1.0);
        // Wall across the middle with a gap
        for y in 0..30 {
            grid.set_walkable(16, y, false);
        }
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        let path = graph.find_path(&grid, &clusters, GridPos::new(0, 0), GridPos::new(31, 31));
        assert!(path.is_some());
        let path = path.unwrap();
        // All cells should be walkable
        for p in &path {
            assert!(grid.is_walkable(p.x, p.y));
        }
    }

    #[test]
    fn hpa_matches_astar_reachability() {
        let mut grid = NavGrid::new(32, 32, 1.0);
        // Complete wall — no path
        for y in 0..32 {
            grid.set_walkable(16, y, false);
        }
        let clusters = GridClusters::build(&grid, 8);
        let graph = AbstractGraph::build(&grid, &clusters);

        let astar = grid.find_path(GridPos::new(0, 0), GridPos::new(31, 31));
        let hpa = graph.find_path(&grid, &clusters, GridPos::new(0, 0), GridPos::new(31, 31));
        assert_eq!(astar.is_some(), hpa.is_some());
    }
}

//! Incremental (time-sliced) pathfinding — spread A* computation across frames.

use std::collections::BinaryHeap;

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::grid::{GridPos, NavGrid};
use crate::path::{PathResult, PathStatus};

#[cfg(feature = "logging")]
use tracing::instrument;

/// Status of an incremental pathfinding query.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[non_exhaustive]
pub enum IncrementalStatus {
    /// Still computing — call `step()` again.
    InProgress,
    /// Path found.
    Found,
    /// No path exists.
    NotFound,
}

/// An incremental (time-sliced) A* pathfinding query.
///
/// Instead of computing the entire path in one call, this allows
/// spreading the computation across multiple frames with a per-step
/// iteration budget.
///
/// # Example
///
/// ```ignore
/// let mut query = IncrementalGridPath::new(&grid, start, goal);
/// loop {
///     match query.step(&grid, 100) {
///         IncrementalStatus::InProgress => continue, // next frame
///         IncrementalStatus::Found => break,
///         IncrementalStatus::NotFound => break,
///     }
/// }
/// let result = query.result();
/// ```
#[derive(Debug, Clone)]
pub struct IncrementalGridPath {
    start: GridPos,
    goal: GridPos,
    g_score: Vec<f32>,
    came_from: Vec<Option<usize>>,
    closed: Vec<bool>,
    open: BinaryHeap<IncrementalNode>,
    status: IncrementalStatus,
    goal_idx: usize,
    grid_width: usize,
    allow_diagonal: bool,
}

#[derive(Clone, Copy)]
struct IncrementalNode {
    idx: usize,
    f_score: f32,
}

impl std::fmt::Debug for IncrementalNode {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("IncrementalNode")
            .field("idx", &self.idx)
            .field("f_score", &self.f_score)
            .finish()
    }
}

impl PartialEq for IncrementalNode {
    fn eq(&self, other: &Self) -> bool {
        self.f_score == other.f_score
    }
}

impl Eq for IncrementalNode {}

impl PartialOrd for IncrementalNode {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for IncrementalNode {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        other
            .f_score
            .partial_cmp(&self.f_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    }
}

impl IncrementalGridPath {
    /// Create a new incremental pathfinding query.
    ///
    /// Returns `None` if start or goal is outside the grid or unwalkable.
    #[cfg_attr(feature = "logging", instrument(skip(grid)))]
    #[must_use]
    pub fn new(grid: &NavGrid, start: GridPos, goal: GridPos) -> Option<Self> {
        if !grid.is_walkable(start.x, start.y) || !grid.is_walkable(goal.x, goal.y) {
            return None;
        }

        let len = grid.width() * grid.height();
        let grid_width = grid.width();
        let allow_diagonal = grid.allow_diagonal;

        // Compute start/goal indices manually (same as grid.index())
        let start_idx = start.y as usize * grid_width + start.x as usize;
        let goal_idx = goal.y as usize * grid_width + goal.x as usize;

        if start_idx >= len || goal_idx >= len {
            return None;
        }

        let mut g_score = vec![f32::INFINITY; len];
        g_score[start_idx] = 0.0;

        let h = if allow_diagonal {
            start.octile_distance(goal)
        } else {
            start.manhattan_distance(goal) as f32
        };

        let mut open = BinaryHeap::new();
        open.push(IncrementalNode {
            idx: start_idx,
            f_score: h,
        });

        Some(Self {
            start,
            goal,
            g_score,
            came_from: vec![None; len],
            closed: vec![false; len],
            open,
            status: IncrementalStatus::InProgress,
            goal_idx,
            grid_width,
            allow_diagonal,
        })
    }

    /// Advance the pathfinding computation by up to `max_iterations` node expansions.
    ///
    /// Returns the current status. Call repeatedly until not `InProgress`.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    pub fn step(&mut self, grid: &NavGrid, max_iterations: u32) -> IncrementalStatus {
        if self.status != IncrementalStatus::InProgress {
            return self.status;
        }

        let mut iterations = 0u32;
        let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];

        while let Some(current) = self.open.pop() {
            if current.idx == self.goal_idx {
                self.status = IncrementalStatus::Found;
                return self.status;
            }

            if self.closed[current.idx] {
                continue;
            }
            self.closed[current.idx] = true;

            let cx = (current.idx % self.grid_width) as i32;
            let cy = (current.idx / self.grid_width) as i32;

            let count = grid_neighbors_into(grid, cx, cy, &mut neighbors_buf);

            for &(nx, ny, move_cost) in &neighbors_buf[..count] {
                let n_idx = ny as usize * self.grid_width + nx as usize;
                if self.closed[n_idx] {
                    continue;
                }
                let cell_cost = grid.cost(nx, ny);
                let tentative_g = self.g_score[current.idx] + move_cost * cell_cost;

                if tentative_g < self.g_score[n_idx] {
                    self.came_from[n_idx] = Some(current.idx);
                    self.g_score[n_idx] = tentative_g;
                    let np = GridPos::new(nx, ny);
                    let h = if self.allow_diagonal {
                        np.octile_distance(self.goal)
                    } else {
                        np.manhattan_distance(self.goal) as f32
                    };
                    self.open.push(IncrementalNode {
                        idx: n_idx,
                        f_score: tentative_g + h,
                    });
                }
            }

            iterations += 1;
            if iterations >= max_iterations {
                return self.status; // Still InProgress
            }
        }

        // Open set exhausted, no path found
        self.status = IncrementalStatus::NotFound;
        self.status
    }

    /// The start position of this query.
    #[must_use]
    pub fn start(&self) -> GridPos {
        self.start
    }

    /// The goal position of this query.
    #[must_use]
    pub fn goal(&self) -> GridPos {
        self.goal
    }

    /// Get the current status.
    #[must_use]
    pub fn status(&self) -> IncrementalStatus {
        self.status
    }

    /// Retrieve the computed path (only valid after `Found` status).
    ///
    /// Returns `None` if the path hasn't been found yet.
    #[must_use]
    pub fn path(&self) -> Option<Vec<GridPos>> {
        if self.status != IncrementalStatus::Found {
            return None;
        }

        let mut path = Vec::new();
        let mut current = self.goal_idx;
        loop {
            let x = (current % self.grid_width) as i32;
            let y = (current / self.grid_width) as i32;
            path.push(GridPos::new(x, y));
            match self.came_from[current] {
                Some(prev) => current = prev,
                None => break,
            }
        }
        path.reverse();
        Some(path)
    }

    /// Convert to a `PathResult`.
    ///
    /// Converts grid positions to world positions using the grid's coordinate system.
    #[must_use]
    pub fn to_path_result(&self, grid: &NavGrid) -> PathResult {
        match self.status {
            IncrementalStatus::Found => {
                if let Some(grid_path) = self.path() {
                    let waypoints: Vec<Vec2> = grid_path
                        .iter()
                        .map(|&pos| grid.grid_to_world(pos))
                        .collect();
                    PathResult::found(waypoints)
                } else {
                    PathResult::not_found()
                }
            }
            IncrementalStatus::NotFound => PathResult::not_found(),
            IncrementalStatus::InProgress => PathResult {
                status: PathStatus::Pending,
                waypoints: Vec::new(),
                length: 0.0,
            },
        }
    }

    /// Number of nodes expanded so far.
    #[must_use]
    pub fn nodes_expanded(&self) -> usize {
        self.closed.iter().filter(|&&c| c).count()
    }
}

/// Compute walkable neighbors for grid pathfinding.
/// Replicates `NavGrid`'s private `neighbors_into` using public API.
#[inline]
fn grid_neighbors_into(grid: &NavGrid, x: i32, y: i32, buf: &mut [(i32, i32, f32); 8]) -> usize {
    const CARDINAL: [(i32, i32); 4] = [(0, 1), (0, -1), (1, 0), (-1, 0)];
    const DIAGONAL: [(i32, i32); 4] = [(1, 1), (1, -1), (-1, 1), (-1, -1)];

    let mut count = 0;
    for (dx, dy) in CARDINAL {
        let nx = x + dx;
        let ny = y + dy;
        if grid.is_walkable(nx, ny) {
            buf[count] = (nx, ny, 1.0);
            count += 1;
        }
    }
    if grid.allow_diagonal {
        for (dx, dy) in DIAGONAL {
            let nx = x + dx;
            let ny = y + dy;
            if grid.is_walkable(nx, ny)
                && grid.is_walkable(x + dx, y)
                && grid.is_walkable(x, y + dy)
            {
                buf[count] = (nx, ny, std::f32::consts::SQRT_2);
                count += 1;
            }
        }
    }
    count
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn incremental_finds_path() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(9, 9)).unwrap();

        // Step with large budget — should find immediately
        let status = query.step(&grid, 1000);
        assert_eq!(status, IncrementalStatus::Found);

        let path = query.path().unwrap();
        assert_eq!(*path.first().unwrap(), GridPos::new(0, 0));
        assert_eq!(*path.last().unwrap(), GridPos::new(9, 9));
    }

    #[test]
    fn incremental_multi_step() {
        let grid = NavGrid::new(20, 20, 1.0);
        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(19, 19)).unwrap();

        // Step with small budget
        let mut steps = 0;
        loop {
            let status = query.step(&grid, 10);
            steps += 1;
            if status != IncrementalStatus::InProgress {
                break;
            }
        }

        assert!(steps > 1); // Should take multiple steps
        assert_eq!(query.status(), IncrementalStatus::Found);
        assert!(query.path().is_some());
    }

    #[test]
    fn incremental_no_path() {
        let mut grid = NavGrid::new(10, 10, 1.0);
        // Wall off the right side
        for y in 0..10 {
            grid.set_walkable(5, y, false);
        }

        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(9, 9)).unwrap();
        let status = query.step(&grid, 10000);
        assert_eq!(status, IncrementalStatus::NotFound);
        assert!(query.path().is_none());
    }

    #[test]
    fn incremental_unwalkable_start() {
        let mut grid = NavGrid::new(10, 10, 1.0);
        grid.set_walkable(0, 0, false);
        assert!(IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(9, 9)).is_none());
    }

    #[test]
    fn incremental_unwalkable_goal() {
        let mut grid = NavGrid::new(10, 10, 1.0);
        grid.set_walkable(9, 9, false);
        assert!(IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(9, 9)).is_none());
    }

    #[test]
    fn incremental_same_start_goal() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(5, 5), GridPos::new(5, 5)).unwrap();
        let status = query.step(&grid, 1);
        assert_eq!(status, IncrementalStatus::Found);
        let path = query.path().unwrap();
        assert_eq!(path.len(), 1);
    }

    #[test]
    fn incremental_to_path_result_found() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(9, 9)).unwrap();
        query.step(&grid, 10000);

        let result = query.to_path_result(&grid);
        assert_eq!(result.status, PathStatus::Found);
        assert!(!result.waypoints.is_empty());
        assert!(result.length > 0.0);
    }

    #[test]
    fn incremental_to_path_result_pending() {
        let grid = NavGrid::new(50, 50, 1.0);
        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(49, 49)).unwrap();
        query.step(&grid, 1); // Just 1 iteration — still in progress

        let result = query.to_path_result(&grid);
        assert_eq!(result.status, PathStatus::Pending);
    }

    #[test]
    fn incremental_matches_regular_path() {
        let mut grid = NavGrid::new(15, 15, 1.0);
        // Add some obstacles
        grid.set_walkable(5, 3, false);
        grid.set_walkable(5, 4, false);
        grid.set_walkable(5, 5, false);

        let start = GridPos::new(0, 0);
        let goal = GridPos::new(14, 14);

        let regular = grid.find_path(start, goal).unwrap();

        let mut query = IncrementalGridPath::new(&grid, start, goal).unwrap();
        query.step(&grid, 100_000);
        let incremental = query.path().unwrap();

        // Both should find the same path
        assert_eq!(regular, incremental);
    }

    #[test]
    fn incremental_nodes_expanded() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query =
            IncrementalGridPath::new(&grid, GridPos::new(0, 0), GridPos::new(9, 9)).unwrap();
        assert_eq!(query.nodes_expanded(), 0);
        query.step(&grid, 5);
        assert!(query.nodes_expanded() > 0);
    }

    #[test]
    fn incremental_status_serde_roundtrip() {
        let status = IncrementalStatus::InProgress;
        let json = serde_json::to_string(&status).unwrap();
        let deserialized: IncrementalStatus = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized, status);
    }
}

//! Influence maps — overlay grids for danger zones, strategic value, and cost annotations.

use hisab::Vec2;
use serde::{Deserialize, Serialize};

#[cfg(feature = "logging")]
use tracing::instrument;

/// A 2D influence map grid for annotating areas with scalar values.
///
/// Useful for danger zones, strategic value overlays, scent trails,
/// or any spatial cost annotation that affects pathfinding or AI decisions.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct InfluenceMap {
    width: usize,
    height: usize,
    cell_size: f32,
    values: Vec<f32>,
}

impl InfluenceMap {
    /// Create a new influence map initialized to zero.
    #[must_use]
    pub fn new(width: usize, height: usize, cell_size: f32) -> Self {
        Self {
            width,
            height,
            cell_size,
            values: vec![0.0; width * height],
        }
    }

    /// Grid width in cells.
    #[must_use]
    pub fn width(&self) -> usize {
        self.width
    }

    /// Grid height in cells.
    #[must_use]
    pub fn height(&self) -> usize {
        self.height
    }

    /// Cell size in world units.
    #[must_use]
    pub fn cell_size(&self) -> f32 {
        self.cell_size
    }

    /// Get the influence value at grid coordinates.
    #[inline]
    #[must_use]
    pub fn get(&self, x: usize, y: usize) -> f32 {
        self.index(x, y).map(|i| self.values[i]).unwrap_or(0.0)
    }

    /// Set the influence value at grid coordinates.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn set(&mut self, x: usize, y: usize, value: f32) {
        if let Some(i) = self.index(x, y) {
            self.values[i] = value;
        }
    }

    /// Add to the influence value at grid coordinates.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn add(&mut self, x: usize, y: usize, delta: f32) {
        if let Some(i) = self.index(x, y) {
            self.values[i] += delta;
        }
    }

    /// Sample the influence at a world position (nearest cell).
    #[must_use]
    pub fn sample(&self, pos: Vec2) -> f32 {
        let x = (pos.x / self.cell_size) as usize;
        let y = (pos.y / self.cell_size) as usize;
        self.get(x, y)
    }

    /// Apply a circular stamp — add `value` to all cells within `radius` of `center`.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn stamp_circle(&mut self, center: Vec2, radius: f32, value: f32) {
        let min_x = ((center.x - radius) / self.cell_size).floor().max(0.0) as usize;
        let max_x = ((center.x + radius) / self.cell_size)
            .ceil()
            .min(self.width as f32 - 1.0) as usize;
        let min_y = ((center.y - radius) / self.cell_size).floor().max(0.0) as usize;
        let max_y = ((center.y + radius) / self.cell_size)
            .ceil()
            .min(self.height as f32 - 1.0) as usize;
        let r_sq = radius * radius;

        for y in min_y..=max_y {
            for x in min_x..=max_x {
                let cx = (x as f32 + 0.5) * self.cell_size;
                let cy = (y as f32 + 0.5) * self.cell_size;
                let dx = cx - center.x;
                let dy = cy - center.y;
                if dx * dx + dy * dy <= r_sq {
                    self.add(x, y, value);
                }
            }
        }
    }

    /// Decay all values toward zero by `factor` (0.0..1.0).
    /// Each value becomes `value * factor`.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn decay(&mut self, factor: f32) {
        for v in &mut self.values {
            *v *= factor;
        }
    }

    /// Reset all values to zero.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn clear(&mut self) {
        self.values.fill(0.0);
    }

    /// Get the raw values slice.
    #[must_use]
    pub fn values(&self) -> &[f32] {
        &self.values
    }

    /// Maximum value in the map.
    #[must_use]
    pub fn max_value(&self) -> f32 {
        self.values
            .iter()
            .cloned()
            .fold(f32::NEG_INFINITY, f32::max)
    }

    /// Minimum value in the map.
    #[must_use]
    pub fn min_value(&self) -> f32 {
        self.values.iter().cloned().fold(f32::INFINITY, f32::min)
    }

    #[inline]
    fn index(&self, x: usize, y: usize) -> Option<usize> {
        if x < self.width && y < self.height {
            Some(y * self.width + x)
        } else {
            None
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn new_initializes_to_zero() {
        let map = InfluenceMap::new(4, 4, 1.0);
        for &v in map.values() {
            assert!((v).abs() < f32::EPSILON);
        }
    }

    #[test]
    fn get_set() {
        let mut map = InfluenceMap::new(4, 4, 1.0);
        map.set(2, 3, 5.0);
        assert!((map.get(2, 3) - 5.0).abs() < f32::EPSILON);
        assert!((map.get(0, 0)).abs() < f32::EPSILON);
    }

    #[test]
    fn add_accumulates() {
        let mut map = InfluenceMap::new(4, 4, 1.0);
        map.add(1, 1, 3.0);
        map.add(1, 1, 2.0);
        assert!((map.get(1, 1) - 5.0).abs() < f32::EPSILON);
    }

    #[test]
    fn sample_world_position() {
        let mut map = InfluenceMap::new(10, 10, 2.0);
        map.set(1, 1, 7.0);
        // World position (2.5, 2.5) / cell_size 2.0 = cell (1, 1)
        let v = map.sample(Vec2::new(2.5, 2.5));
        assert!((v - 7.0).abs() < f32::EPSILON);
    }

    #[test]
    fn stamp_circle_affects_nearby_cells() {
        let mut map = InfluenceMap::new(10, 10, 1.0);
        map.stamp_circle(Vec2::new(5.0, 5.0), 1.5, 1.0);

        // Center cell should be affected
        assert!(map.get(5, 5) > 0.0);
        // Far corner should not be affected
        assert!((map.get(0, 0)).abs() < f32::EPSILON);
    }

    #[test]
    fn decay_reduces_values() {
        let mut map = InfluenceMap::new(4, 4, 1.0);
        map.set(0, 0, 10.0);
        map.decay(0.5);
        assert!((map.get(0, 0) - 5.0).abs() < f32::EPSILON);
    }

    #[test]
    fn clear_resets_all() {
        let mut map = InfluenceMap::new(4, 4, 1.0);
        map.set(0, 0, 10.0);
        map.set(3, 3, 20.0);
        map.clear();
        for &v in map.values() {
            assert!((v).abs() < f32::EPSILON);
        }
    }

    #[test]
    fn max_min_values() {
        let mut map = InfluenceMap::new(4, 4, 1.0);
        map.set(0, 0, -5.0);
        map.set(1, 1, 10.0);
        map.set(2, 2, 3.0);
        assert!((map.max_value() - 10.0).abs() < f32::EPSILON);
        assert!((map.min_value() - (-5.0)).abs() < f32::EPSILON);
    }

    #[test]
    fn out_of_bounds_returns_zero() {
        let map = InfluenceMap::new(4, 4, 1.0);
        assert!((map.get(10, 10)).abs() < f32::EPSILON);
        assert!((map.get(4, 0)).abs() < f32::EPSILON);
        assert!((map.get(0, 4)).abs() < f32::EPSILON);
    }

    #[test]
    fn serde_roundtrip() {
        let mut map = InfluenceMap::new(3, 3, 2.0);
        map.set(1, 1, 42.0);

        let json = serde_json::to_string(&map).expect("serialize");
        let map2: InfluenceMap = serde_json::from_str(&json).expect("deserialize");

        assert_eq!(map2.width(), 3);
        assert_eq!(map2.height(), 3);
        assert!((map2.cell_size() - 2.0).abs() < f32::EPSILON);
        assert!((map2.get(1, 1) - 42.0).abs() < f32::EPSILON);
    }
}

