    #[test]
    fn navmesh3d_bytes_roundtrip() {
        let mesh = make_ramp_mesh();
        let bytes = mesh.to_bytes();
        let loaded = NavMesh3D::from_bytes(&bytes);
        assert!(loaded.is_some());
        let loaded = loaded.expect("roundtrip should succeed");
        assert_eq!(loaded.poly_count(), mesh.poly_count());

        for (a, b) in mesh.polys().iter().zip(loaded.polys().iter()) {
            assert_eq!(a.id, b.id);
            assert_eq!(a.vertices.len(), b.vertices.len());
            for (va, vb) in a.vertices.iter().zip(b.vertices.iter()) {
                assert!((va.x - vb.x).abs() < f32::EPSILON);
                assert!((va.y - vb.y).abs() < f32::EPSILON);
                assert!((va.z - vb.z).abs() < f32::EPSILON);
            }
            assert_eq!(a.neighbors.len(), b.neighbors.len());
            for (na, nb) in a.neighbors.iter().zip(b.neighbors.iter()) {
                assert_eq!(na, nb);
            }
            assert!((a.cost - b.cost).abs() < f32::EPSILON);
        }
    }

    #[test]
    fn navmesh3d_bytes_empty() {
        let mesh = NavMesh3D::new();
        let bytes = mesh.to_bytes();
        let loaded = NavMesh3D::from_bytes(&bytes).expect("empty mesh roundtrip");
        assert_eq!(loaded.poly_count(), 0);
    }

    #[test]
    fn navmesh3d_bytes_invalid() {
        assert!(NavMesh3D::from_bytes(b"BAAD").is_none());
        assert!(NavMesh3D::from_bytes(&[]).is_none());
        assert!(NavMesh3D::from_bytes(b"RNV3").is_none()); // truncated — no version
    }

    #[test]
    fn navmesh3d_bytes_single_triangle() {
        let mut mesh = NavMesh3D::new();
        mesh.add_poly(NavPoly3D {
            id: NavPolyId(0),
            vertices: vec![
                Vec3::ZERO,
                Vec3::new(10.0, 0.0, 0.0),
                Vec3::new(5.0, 0.0, 10.0),
            ],
            neighbors: vec![],
            cost: 1.0,
        });
        let bytes = mesh.to_bytes();
        let loaded = NavMesh3D::from_bytes(&bytes).expect("single triangle roundtrip");
        assert_eq!(loaded.poly_count(), 1);
        let poly = loaded.get_poly(NavPolyId(0)).expect("poly 0");
        assert_eq!(poly.vertices.len(), 3);
        assert!(poly.neighbors.is_empty());
    }

    #[test]
    fn navmesh3d_bytes_wrong_magic() {
        // RNAV (2D magic) should not parse as 3D
        let mut data = b"RNAV".to_vec();
        data.extend_from_slice(&1u32.to_le_bytes());
        data.extend_from_slice(&0u32.to_le_bytes());
        assert!(NavMesh3D::from_bytes(&data).is_none());
    }
}

//! Multi-layer NavMesh — overlapping navigation surfaces for bridges and buildings.

use std::collections::HashMap;

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::mesh::{NavMesh, NavPolyId};

#[cfg(feature = "logging")]
use tracing::instrument;

/// Identifies a layer in the multi-layer navmesh.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct LayerId(pub u32);

/// A polygon ID scoped to a specific layer.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct LayeredPolyId {
    pub layer: LayerId,
    pub poly: NavPolyId,
}

/// Connection between layers (stairs, elevators, ramps).
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct LayerConnection {
    pub from: LayeredPolyId,
    pub to: LayeredPolyId,
    pub cost: f32,
    pub bidirectional: bool,
}

/// Multi-layer navmesh — multiple overlapping navigation surfaces.
///
/// Each layer is an independent `NavMesh` (e.g., ground floor, second floor,
/// bridge surface). Layers are connected by explicit connections (stairs, etc.).
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct MultiLayerNavMesh {
    layers: HashMap<LayerId, NavMesh>,
    connections: Vec<LayerConnection>,
}

impl MultiLayerNavMesh {
    #[must_use]
    pub fn new() -> Self {
        Self::default()
    }

    /// Add a navigation layer.
    pub fn add_layer(&mut self, id: LayerId, mesh: NavMesh) {
        self.layers.insert(id, mesh);
    }

    /// Remove a layer.
    pub fn remove_layer(&mut self, id: LayerId) -> bool {
        if self.layers.remove(&id).is_some() {
            self.connections
                .retain(|c| c.from.layer != id && c.to.layer != id);
            true
        } else {
            false
        }
    }

    /// Get a layer's navmesh.
    #[must_use]
    pub fn get_layer(&self, id: LayerId) -> Option<&NavMesh> {
        self.layers.get(&id)
    }

    /// Number of layers.
    #[must_use]
    pub fn layer_count(&self) -> usize {
        self.layers.len()
    }

    /// Add a connection between layers.
    pub fn add_connection(&mut self, conn: LayerConnection) {
        self.connections.push(conn);
    }

    /// Get all connections.
    #[must_use]
    pub fn connections(&self) -> &[LayerConnection] {
        &self.connections
    }

    /// Find a path across layers.
    ///
    /// Returns a sequence of `LayeredPolyId`s from start to goal.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    #[must_use]
    pub fn find_path(
        &self,
        start_layer: LayerId,
        start_pos: Vec2,
        goal_layer: LayerId,
        goal_pos: Vec2,
    ) -> Option<Vec<LayeredPolyId>> {
        // Same layer — use local pathfinding
        if start_layer == goal_layer {
            let mesh = self.layers.get(&start_layer)?;
            let poly_path = mesh.find_path(start_pos, goal_pos)?;
            return Some(
                poly_path
                    .into_iter()
                    .map(|p| LayeredPolyId {
                        layer: start_layer,
                        poly: p,
                    })
                    .collect(),
            );
        }

        // Cross-layer A*
        // Build node list
        use std::cmp::Ordering;
        use std::collections::BinaryHeap;

        let mut nodes: Vec<LayeredPolyId> = Vec::new();
        let mut positions: Vec<Vec2> = Vec::new();
        let mut node_map: HashMap<LayeredPolyId, usize> = HashMap::new();

        for (&lid, mesh) in &self.layers {
            for poly in mesh.polys() {
                let lpid = LayeredPolyId {
                    layer: lid,
                    poly: poly.id,
                };
                let idx = nodes.len();
                node_map.insert(lpid, idx);
                nodes.push(lpid);
                positions.push(poly.centroid());
            }
        }

        let n = nodes.len();
        if n == 0 {
            return None;
        }

        // Find start/goal nodes
        let start_mesh = self.layers.get(&start_layer)?;
        let start_poly = start_mesh.find_poly_at(start_pos)?;
        let start_id = LayeredPolyId {
            layer: start_layer,
            poly: start_poly,
        };
        let start_idx = *node_map.get(&start_id)?;

        let goal_mesh = self.layers.get(&goal_layer)?;
        let goal_poly = goal_mesh.find_poly_at(goal_pos)?;
        let goal_id = LayeredPolyId {
            layer: goal_layer,
            poly: goal_poly,
        };
        let goal_idx = *node_map.get(&goal_id)?;

        // Build adjacency
        let mut adj: Vec<Vec<(usize, f32)>> = vec![Vec::new(); n];

        // Local neighbors
        for (&lid, mesh) in &self.layers {
            for poly in mesh.polys() {
                let from = LayeredPolyId {
                    layer: lid,
                    poly: poly.id,
                };
                let fi = node_map[&from];
                for &nid in &poly.neighbors {
                    let to = LayeredPolyId {
                        layer: lid,
                        poly: nid,
                    };
                    if let Some(&ti) = node_map.get(&to) {
                        let cost = positions[fi].distance(positions[ti]) * poly.cost;
                        adj[fi].push((ti, cost));
                    }
                }
            }
        }

        // Layer connections
        for conn in &self.connections {
            if let (Some(&fi), Some(&ti)) = (node_map.get(&conn.from), node_map.get(&conn.to)) {
                adj[fi].push((ti, conn.cost));
                if conn.bidirectional {
                    adj[ti].push((fi, conn.cost));
                }
            }
        }

        // A*
        #[derive(Clone, Copy)]
        struct N {
            idx: usize,
            f: f32,
        }
        impl PartialEq for N {
            fn eq(&self, o: &Self) -> bool {
                self.f == o.f
            }
        }
        impl Eq for N {}
        impl PartialOrd for N {
            fn partial_cmp(&self, o: &Self) -> Option<Ordering> {
                Some(self.cmp(o))
            }
        }
        impl Ord for N {
            fn cmp(&self, o: &Self) -> Ordering {
                o.f.partial_cmp(&self.f).unwrap_or(Ordering::Equal)
            }
        }

        let mut g = vec![f32::INFINITY; n];
        let mut came: Vec<Option<usize>> = vec![None; n];
        let mut closed = vec![false; n];
        let mut open = BinaryHeap::new();

        g[start_idx] = 0.0;
        open.push(N {
            idx: start_idx,
            f: positions[start_idx].distance(positions[goal_idx]),
        });

        while let Some(cur) = open.pop() {
            if cur.idx == goal_idx {
                let mut path = Vec::new();
                let mut c = goal_idx;
                loop {
                    path.push(nodes[c]);
                    match came[c] {
                        Some(p) => c = p,
                        None => break,
                    }
                }
                path.reverse();
                return Some(path);
            }
            if closed[cur.idx] {
                continue;
            }
            closed[cur.idx] = true;

            for &(ni, cost) in &adj[cur.idx] {
                if closed[ni] {
                    continue;
                }
                let tg = g[cur.idx] + cost;
                if tg < g[ni] {
                    g[ni] = tg;
                    came[ni] = Some(cur.idx);
                    open.push(N {
                        idx: ni,
                        f: tg + positions[ni].distance(positions[goal_idx]),
                    });
                }
            }
        }

        None
    }
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::mesh::{NavMesh, NavPoly, NavPolyId};

    /// Build a simple 2-polygon navmesh for testing.
    fn make_simple_mesh() -> NavMesh {
        let mut mesh = NavMesh::new();
        mesh.add_poly(NavPoly {
            id: NavPolyId(0),
            vertices: vec![
                Vec2::new(0.0, 0.0),
                Vec2::new(5.0, 0.0),
                Vec2::new(5.0, 5.0),
                Vec2::new(0.0, 5.0),
            ],
            neighbors: vec![NavPolyId(1)],
            cost: 1.0,
            layer: 0,
        });
        mesh.add_poly(NavPoly {
            id: NavPolyId(1),
            vertices: vec![
                Vec2::new(5.0, 0.0),
                Vec2::new(10.0, 0.0),
                Vec2::new(10.0, 5.0),
                Vec2::new(5.0, 5.0),
            ],
            neighbors: vec![NavPolyId(0)],
            cost: 1.0,
            layer: 0,
        });
        mesh
    }

    #[test]
    fn same_layer_path() {
        let mut ml = MultiLayerNavMesh::new();
        ml.add_layer(LayerId(0), make_simple_mesh());

        let path = ml.find_path(
            LayerId(0),
            Vec2::new(1.0, 1.0),
            LayerId(0),
            Vec2::new(9.0, 1.0),
        );
        assert!(path.is_some());
        let path = path.unwrap();
        assert_eq!(path.len(), 2);
        assert!(path.iter().all(|lp| lp.layer == LayerId(0)));
    }

    #[test]
    fn cross_layer_path_via_connection() {
        let mut ml = MultiLayerNavMesh::new();
        ml.add_layer(LayerId(0), make_simple_mesh());
        ml.add_layer(LayerId(1), make_simple_mesh());

        // Connect layer 0 poly 1 to layer 1 poly 0 (like stairs)
        ml.add_connection(LayerConnection {
            from: LayeredPolyId {
                layer: LayerId(0),
                poly: NavPolyId(1),
            },
            to: LayeredPolyId {
                layer: LayerId(1),
                poly: NavPolyId(0),
            },
            cost: 2.0,
            bidirectional: false,
        });

        let path = ml.find_path(
            LayerId(0),
            Vec2::new(1.0, 1.0),
            LayerId(1),
            Vec2::new(9.0, 1.0),
        );
        assert!(path.is_some());
        let path = path.unwrap();
        // Should traverse: layer0/poly0 -> layer0/poly1 -> layer1/poly0 -> layer1/poly1
        assert!(path.len() >= 3);
        // First node on layer 0, last node on layer 1
        assert_eq!(path.first().unwrap().layer, LayerId(0));
        assert_eq!(path.last().unwrap().layer, LayerId(1));
    }

    #[test]
    fn no_path_without_connection() {
        let mut ml = MultiLayerNavMesh::new();
        ml.add_layer(LayerId(0), make_simple_mesh());
        ml.add_layer(LayerId(1), make_simple_mesh());

        // No connection between layers — path should fail
        let path = ml.find_path(
            LayerId(0),
            Vec2::new(1.0, 1.0),
            LayerId(1),
            Vec2::new(9.0, 1.0),
        );
        assert!(path.is_none());
    }

    #[test]
    fn bidirectional_connection() {
        let mut ml = MultiLayerNavMesh::new();
        ml.add_layer(LayerId(0), make_simple_mesh());
        ml.add_layer(LayerId(1), make_simple_mesh());

        ml.add_connection(LayerConnection {
            from: LayeredPolyId {
                layer: LayerId(0),
                poly: NavPolyId(1),
            },
            to: LayeredPolyId {
                layer: LayerId(1),
                poly: NavPolyId(0),
            },
            cost: 2.0,
            bidirectional: true,
        });

        // Forward: layer 0 -> layer 1
        let fwd = ml.find_path(
            LayerId(0),
            Vec2::new(1.0, 1.0),
            LayerId(1),
            Vec2::new(9.0, 1.0),
        );
        assert!(fwd.is_some());

        // Reverse: layer 1 -> layer 0
        let rev = ml.find_path(
            LayerId(1),
            Vec2::new(1.0, 1.0),
            LayerId(0),
            Vec2::new(9.0, 1.0),
        );
        assert!(rev.is_some());
    }

    #[test]
    fn remove_layer() {
        let mut ml = MultiLayerNavMesh::new();
        ml.add_layer(LayerId(0), make_simple_mesh());
        ml.add_layer(LayerId(1), make_simple_mesh());
        ml.add_connection(LayerConnection {
            from: LayeredPolyId {
                layer: LayerId(0),
                poly: NavPolyId(0),
            },
            to: LayeredPolyId {
                layer: LayerId(1),
                poly: NavPolyId(0),
            },
            cost: 1.0,
            bidirectional: false,
        });

        assert_eq!(ml.layer_count(), 2);
        assert_eq!(ml.connections().len(), 1);

        assert!(ml.remove_layer(LayerId(1)));
        assert_eq!(ml.layer_count(), 1);
        // Connection referencing removed layer should be cleaned up
        assert_eq!(ml.connections().len(), 0);

        // Removing non-existent layer returns false
        assert!(!ml.remove_layer(LayerId(99)));
    }

    #[test]
    fn serde_roundtrip() {
        let mut ml = MultiLayerNavMesh::new();
        ml.add_layer(LayerId(0), make_simple_mesh());
        ml.add_layer(LayerId(1), make_simple_mesh());
        ml.add_connection(LayerConnection {
            from: LayeredPolyId {
                layer: LayerId(0),
                poly: NavPolyId(1),
            },
            to: LayeredPolyId {
                layer: LayerId(1),
                poly: NavPolyId(0),
            },
            cost: 3.0,
            bidirectional: true,
        });

        let json = serde_json::to_string(&ml).unwrap();
        let deserialized: MultiLayerNavMesh = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.layer_count(), 2);
        assert_eq!(deserialized.connections().len(), 1);
        assert!((deserialized.connections()[0].cost - 3.0).abs() < f32::EPSILON);
    }
}

//! Off-mesh links — custom traversal edges for jumps, ladders, teleporters, doors.

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::mesh::NavPolyId;

#[cfg(feature = "logging")]
use tracing::instrument;

/// The type of traversal an off-mesh link represents.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[non_exhaustive]
pub enum LinkType {
    /// A jump between two points (one-way or bidirectional).
    Jump,
    /// A ladder or climbable surface.
    Ladder,
    /// An instant teleporter.
    Teleport,
    /// A door that may be open or closed.
    Door,
    /// Generic custom link.
    Custom,
}

/// Unique identifier for an off-mesh link.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct OffMeshLinkId(pub u32);

/// An off-mesh link connecting two positions on the navmesh.
///
/// Links create additional edges in the navigation graph beyond the
/// polygon adjacency. They can be bidirectional or one-way, and have
/// a traversal cost.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OffMeshLink {
    /// Unique identifier.
    pub id: OffMeshLinkId,
    /// Start position (world space).
    pub start: Vec2,
    /// End position (world space).
    pub end: Vec2,
    /// Polygon containing the start position.
    pub start_poly: NavPolyId,
    /// Polygon containing the end position.
    pub end_poly: NavPolyId,
    /// Traversal cost (added to pathfinding cost).
    pub cost: f32,
    /// Whether this link can be traversed in both directions.
    pub bidirectional: bool,
    /// Type of traversal.
    pub link_type: LinkType,
    /// Whether this link is currently enabled (e.g., door open/closed).
    pub enabled: bool,
}

/// Description of an off-mesh link to add to a registry.
///
/// Groups the parameters for [`OffMeshLinkRegistry::add_link`] into a
/// single struct to keep the API ergonomic.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct OffMeshLinkDesc {
    /// Start position (world space).
    pub start: Vec2,
    /// End position (world space).
    pub end: Vec2,
    /// Polygon containing the start position.
    pub start_poly: NavPolyId,
    /// Polygon containing the end position.
    pub end_poly: NavPolyId,
    /// Traversal cost (added to pathfinding cost). Clamped to >= 0.
    pub cost: f32,
    /// Whether this link can be traversed in both directions.
    pub bidirectional: bool,
    /// Type of traversal.
    pub link_type: LinkType,
}

/// Registry of off-mesh links for a navmesh.
///
/// Manages links and provides query methods for pathfinding integration.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
pub struct OffMeshLinkRegistry {
    links: Vec<OffMeshLink>,
    next_id: u32,
}

impl OffMeshLinkRegistry {
    /// Create an empty registry.
    #[must_use]
    pub fn new() -> Self {
        Self {
            links: Vec::new(),
            next_id: 0,
        }
    }

    /// Add an off-mesh link and return its ID.
    ///
    /// The caller is responsible for ensuring `start_poly` and `end_poly`
    /// are valid polygon IDs in the associated navmesh.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn add_link(&mut self, desc: OffMeshLinkDesc) -> OffMeshLinkId {
        let id = OffMeshLinkId(self.next_id);
        self.next_id += 1;
        self.links.push(OffMeshLink {
            id,
            start: desc.start,
            end: desc.end,
            start_poly: desc.start_poly,
            end_poly: desc.end_poly,
            cost: desc.cost.max(0.0),
            bidirectional: desc.bidirectional,
            link_type: desc.link_type,
            enabled: true,
        });
        id
    }

    /// Remove a link by ID. Returns the removed link, or `None`.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn remove_link(&mut self, id: OffMeshLinkId) -> Option<OffMeshLink> {
        if let Some(pos) = self.links.iter().position(|l| l.id == id) {
            Some(self.links.swap_remove(pos))
        } else {
            None
        }
    }

    /// Enable or disable a link (e.g., open/close a door).
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn set_enabled(&mut self, id: OffMeshLinkId, enabled: bool) {
        if let Some(link) = self.links.iter_mut().find(|l| l.id == id) {
            link.enabled = enabled;
        }
    }

    /// Get a link by ID.
    #[must_use]
    pub fn get_link(&self, id: OffMeshLinkId) -> Option<&OffMeshLink> {
        self.links.iter().find(|l| l.id == id)
    }

    /// Get all links.
    #[must_use]
    pub fn links(&self) -> &[OffMeshLink] {
        &self.links
    }

    /// Get all enabled links originating from (or connected to) a given polygon.
    ///
    /// Returns links where `start_poly == poly_id`, plus bidirectional links
    /// where `end_poly == poly_id`.
    #[must_use]
    pub fn links_from_poly(&self, poly_id: NavPolyId) -> Vec<&OffMeshLink> {
        self.links
            .iter()
            .filter(|l| {
                l.enabled && (l.start_poly == poly_id || (l.bidirectional && l.end_poly == poly_id))
            })
            .collect()
    }

    /// Number of links.
    #[must_use]
    #[inline]
    pub fn link_count(&self) -> usize {
        self.links.len()
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    fn desc(
        start: Vec2,
        end: Vec2,
        start_poly: NavPolyId,
        end_poly: NavPolyId,
        cost: f32,
        bidirectional: bool,
        link_type: LinkType,
    ) -> OffMeshLinkDesc {
        OffMeshLinkDesc {
            start,
            end,
            start_poly,
            end_poly,
            cost,
            bidirectional,
            link_type,
        }
    }

    #[test]
    fn registry_add_remove() {
        let mut reg = OffMeshLinkRegistry::new();
        let id = reg.add_link(desc(
            Vec2::ZERO,
            Vec2::new(10.0, 0.0),
            NavPolyId(0),
            NavPolyId(1),
            5.0,
            true,
            LinkType::Jump,
        ));
        assert_eq!(reg.link_count(), 1);
        assert!(reg.get_link(id).is_some());

        let removed = reg.remove_link(id);
        assert!(removed.is_some());
        assert_eq!(reg.link_count(), 0);
    }

    #[test]
    fn registry_enable_disable() {
        let mut reg = OffMeshLinkRegistry::new();
        let id = reg.add_link(desc(
            Vec2::ZERO,
            Vec2::new(10.0, 0.0),
            NavPolyId(0),
            NavPolyId(1),
            5.0,
            false,
            LinkType::Door,
        ));
        assert!(reg.get_link(id).unwrap().enabled);

        reg.set_enabled(id, false);
        assert!(!reg.get_link(id).unwrap().enabled);

        // Disabled links shouldn't appear in links_from_poly
        assert!(reg.links_from_poly(NavPolyId(0)).is_empty());

        reg.set_enabled(id, true);
        assert_eq!(reg.links_from_poly(NavPolyId(0)).len(), 1);
    }

    #[test]
    fn bidirectional_links() {
        let mut reg = OffMeshLinkRegistry::new();
        reg.add_link(desc(
            Vec2::ZERO,
            Vec2::new(10.0, 0.0),
            NavPolyId(0),
            NavPolyId(1),
            5.0,
            true,
            LinkType::Teleport,
        ));
        // Should appear from both sides
        assert_eq!(reg.links_from_poly(NavPolyId(0)).len(), 1);
        assert_eq!(reg.links_from_poly(NavPolyId(1)).len(), 1);
    }

    #[test]
    fn one_way_links() {
        let mut reg = OffMeshLinkRegistry::new();
        reg.add_link(desc(
            Vec2::ZERO,
            Vec2::new(10.0, 0.0),
            NavPolyId(0),
            NavPolyId(1),
            5.0,
            false,
            LinkType::Jump,
        ));
        // Only from start poly
        assert_eq!(reg.links_from_poly(NavPolyId(0)).len(), 1);
        assert_eq!(reg.links_from_poly(NavPolyId(1)).len(), 0);
    }

    #[test]
    fn link_serde_roundtrip() {
        let mut reg = OffMeshLinkRegistry::new();
        reg.add_link(desc(
            Vec2::new(1.0, 2.0),
            Vec2::new(3.0, 4.0),
            NavPolyId(0),
            NavPolyId(1),
            2.5,
            true,
            LinkType::Ladder,
        ));
        let json = serde_json::to_string(&reg).unwrap();
        let deserialized: OffMeshLinkRegistry = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.link_count(), 1);
    }

    #[test]
    fn remove_nonexistent_link() {
        let mut reg = OffMeshLinkRegistry::new();
        assert!(reg.remove_link(OffMeshLinkId(99)).is_none());
    }

    #[test]
    fn cost_clamped_to_zero() {
        let mut reg = OffMeshLinkRegistry::new();
        let id = reg.add_link(desc(
            Vec2::ZERO,
            Vec2::new(10.0, 0.0),
            NavPolyId(0),
            NavPolyId(1),
            -5.0,
            false,
            LinkType::Custom,
        ));
        assert!(reg.get_link(id).unwrap().cost >= 0.0);
    }
}

//! Parallel pathfinding — multi-threaded batch operations using rayon.
//!
//! Requires the `parallel` feature flag.

use hisab::Vec2;
use rayon::prelude::*;

use crate::grid::{GridPos, NavGrid};
use crate::mesh::{NavMesh, NavPolyId};
use crate::path::PathResult;

#[cfg(feature = "logging")]
use tracing::instrument;

/// Compute multiple grid paths in parallel.
///
/// Each request is a `(start, goal)` pair. Returns results in the same order.
/// Uses rayon's work-stealing thread pool for automatic load balancing.
///
/// # Example
///
/// ```ignore
/// use raasta::parallel::find_paths_parallel;
///
/// let grid = NavGrid::new(100, 100, 1.0);
/// let requests = vec![
///     (GridPos::new(0, 0), GridPos::new(99, 99)),
///     (GridPos::new(10, 10), GridPos::new(50, 50)),
/// ];
/// let results = find_paths_parallel(&grid, &requests);
/// ```
#[cfg_attr(feature = "logging", instrument(skip(grid, requests), fields(count = requests.len())))]
#[must_use]
pub fn find_paths_parallel(
    grid: &NavGrid,
    requests: &[(GridPos, GridPos)],
) -> Vec<Option<Vec<GridPos>>> {
    requests
        .par_iter()
        .map(|&(start, goal)| grid.find_path(start, goal))
        .collect()
}

/// Compute multiple grid paths in parallel, returning `PathResult`s with world coordinates.
#[cfg_attr(feature = "logging", instrument(skip(grid, requests), fields(count = requests.len())))]
#[must_use]
pub fn find_path_results_parallel(
    grid: &NavGrid,
    requests: &[(GridPos, GridPos)],
) -> Vec<PathResult> {
    requests
        .par_iter()
        .map(|&(start, goal)| match grid.find_path(start, goal) {
            Some(path) => {
                let waypoints: Vec<Vec2> = path.iter().map(|&p| grid.grid_to_world(p)).collect();
                PathResult::found(waypoints)
            }
            None => PathResult::not_found(),
        })
        .collect()
}

/// Compute multiple navmesh paths in parallel.
#[cfg_attr(feature = "logging", instrument(skip(mesh, requests), fields(count = requests.len())))]
#[must_use]
pub fn find_mesh_paths_parallel(
    mesh: &NavMesh,
    requests: &[(Vec2, Vec2)],
) -> Vec<Option<Vec<NavPolyId>>> {
    requests
        .par_iter()
        .map(|&(start, goal)| mesh.find_path(start, goal))
        .collect()
}

/// Compute multiple JPS paths in parallel.
#[cfg_attr(feature = "logging", instrument(skip(grid, requests), fields(count = requests.len())))]
#[must_use]
pub fn find_paths_jps_parallel(
    grid: &NavGrid,
    requests: &[(GridPos, GridPos)],
) -> Vec<Option<Vec<GridPos>>> {
    requests
        .par_iter()
        .map(|&(start, goal)| grid.find_path_jps(start, goal))
        .collect()
}

/// Compute multiple Theta* paths in parallel.
#[cfg_attr(feature = "logging", instrument(skip(grid, requests), fields(count = requests.len())))]
#[must_use]
pub fn find_paths_theta_parallel(
    grid: &NavGrid,
    requests: &[(GridPos, GridPos)],
) -> Vec<Option<Vec<GridPos>>> {
    requests
        .par_iter()
        .map(|&(start, goal)| grid.find_path_theta(start, goal))
        .collect()
}

/// Process a batch of grid paths in parallel with a custom algorithm selector.
///
/// The `algorithm` closure receives `(grid, start, goal)` and returns the path.
/// This allows mixing algorithms per-request.
#[must_use]
pub fn find_paths_custom_parallel<F>(
    grid: &NavGrid,
    requests: &[(GridPos, GridPos)],
    algorithm: F,
) -> Vec<Option<Vec<GridPos>>>
where
    F: Fn(&NavGrid, GridPos, GridPos) -> Option<Vec<GridPos>> + Sync,
{
    requests
        .par_iter()
        .map(|&(start, goal)| algorithm(grid, start, goal))
        .collect()
}

/// Parallel flow field computation for multiple goals.
#[cfg_attr(feature = "logging", instrument(skip(grid, goals), fields(count = goals.len())))]
#[must_use]
pub fn flow_fields_parallel(grid: &NavGrid, goals: &[GridPos]) -> Vec<Vec<(i32, i32)>> {
    goals
        .par_iter()
        .map(|&goal| grid.flow_field(goal))
        .collect()
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parallel_grid_paths() {
        let grid = NavGrid::new(20, 20, 1.0);
        let requests = vec![
            (GridPos::new(0, 0), GridPos::new(19, 19)),
            (GridPos::new(0, 0), GridPos::new(10, 10)),
            (GridPos::new(5, 5), GridPos::new(15, 15)),
        ];
        let results = find_paths_parallel(&grid, &requests);
        assert_eq!(results.len(), 3);
        for result in &results {
            assert!(result.is_some());
        }
    }

    #[test]
    fn parallel_grid_paths_mixed() {
        let mut grid = NavGrid::new(20, 20, 1.0);
        for y in 0..20 {
            grid.set_walkable(10, y, false);
        }
        let requests = vec![
            (GridPos::new(0, 0), GridPos::new(5, 5)),   // reachable
            (GridPos::new(0, 0), GridPos::new(15, 15)), // unreachable
        ];
        let results = find_paths_parallel(&grid, &requests);
        assert!(results[0].is_some());
        assert!(results[1].is_none());
    }

    #[test]
    fn parallel_path_results() {
        let grid = NavGrid::new(10, 10, 1.0);
        let requests = vec![(GridPos::new(0, 0), GridPos::new(9, 9))];
        let results = find_path_results_parallel(&grid, &requests);
        assert_eq!(results.len(), 1);
        assert!(results[0].is_found());
        assert!(results[0].length > 0.0);
    }

    #[test]
    fn parallel_mesh_paths() {
        use crate::mesh::{NavMesh, NavPoly, NavPolyId};
        let mut mesh = NavMesh::new();
        mesh.add_poly(NavPoly {
            id: NavPolyId(0),
            vertices: vec![
                Vec2::ZERO,
                Vec2::new(10.0, 0.0),
                Vec2::new(10.0, 10.0),
                Vec2::new(0.0, 10.0),
            ],
            neighbors: vec![NavPolyId(1)],
            cost: 1.0,
            layer: 0,
        });
        mesh.add_poly(NavPoly {
            id: NavPolyId(1),
            vertices: vec![
                Vec2::new(10.0, 0.0),
                Vec2::new(20.0, 0.0),
                Vec2::new(20.0, 10.0),
                Vec2::new(10.0, 10.0),
            ],
            neighbors: vec![NavPolyId(0)],
            cost: 1.0,
            layer: 0,
        });

        let requests = vec![(Vec2::new(5.0, 5.0), Vec2::new(15.0, 5.0))];
        let results = find_mesh_paths_parallel(&mesh, &requests);
        assert!(results[0].is_some());
    }

    #[test]
    fn parallel_jps() {
        let grid = NavGrid::new(20, 20, 1.0);
        let requests = vec![
            (GridPos::new(0, 0), GridPos::new(19, 19)),
            (GridPos::new(0, 0), GridPos::new(10, 10)),
        ];
        let results = find_paths_jps_parallel(&grid, &requests);
        assert_eq!(results.len(), 2);
        for r in &results {
            assert!(r.is_some());
        }
    }

    #[test]
    fn parallel_flow_fields() {
        let grid = NavGrid::new(10, 10, 1.0);
        let goals = vec![GridPos::new(0, 0), GridPos::new(9, 9)];
        let fields = flow_fields_parallel(&grid, &goals);
        assert_eq!(fields.len(), 2);
    }

    #[test]
    fn parallel_empty_requests() {
        let grid = NavGrid::new(10, 10, 1.0);
        let results = find_paths_parallel(&grid, &[]);
        assert!(results.is_empty());
    }

    #[test]
    fn parallel_custom_algorithm() {
        let grid = NavGrid::new(20, 20, 1.0);
        let requests = vec![(GridPos::new(0, 0), GridPos::new(19, 19))];
        let results =
            find_paths_custom_parallel(&grid, &requests, |g, s, goal| g.find_path_jps(s, goal));
        assert!(results[0].is_some());
    }

    #[test]
    fn parallel_many_requests() {
        let grid = NavGrid::new(50, 50, 1.0);
        let requests: Vec<(GridPos, GridPos)> = (0..100)
            .map(|i| (GridPos::new(0, 0), GridPos::new(i % 50, i / 2 % 50)))
            .collect();
        let results = find_paths_parallel(&grid, &requests);
        assert_eq!(results.len(), 100);
    }
}

//! Path request/result types.

use hisab::Vec2;
use serde::{Deserialize, Serialize};

/// Status of a pathfinding request.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[non_exhaustive]
pub enum PathStatus {
    /// Path found successfully.
    Found,
    /// Path could not reach the goal; this is the closest reachable point.
    Partial,
    /// No path exists between start and goal.
    NotFound,
    /// Start or goal is outside navigable area.
    Invalid,
    /// Path computation is still in progress (for async).
    Pending,
}

/// A pathfinding request.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PathRequest {
    /// Start position in world space.
    pub start: Vec2,
    /// Goal position in world space.
    pub goal: Vec2,
}

impl PathRequest {
    #[must_use]
    pub fn new(start: Vec2, goal: Vec2) -> Self {
        Self { start, goal }
    }
}

/// Result of a pathfinding computation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct PathResult {
    pub status: PathStatus,
    /// Waypoints from start to goal in world space.
    pub waypoints: Vec<Vec2>,
    /// Total path length.
    pub length: f32,
}

impl PathResult {
    /// Create a successful path result.
    #[must_use]
    pub fn found(waypoints: Vec<Vec2>) -> Self {
        let length = waypoints.windows(2).map(|w| (w[1] - w[0]).length()).sum();
        Self {
            status: PathStatus::Found,
            waypoints,
            length,
        }
    }

    /// Create a partial path result (closest reachable point to unreachable goal).
    #[must_use]
    pub fn partial(waypoints: Vec<Vec2>) -> Self {
        let length = waypoints.windows(2).map(|w| (w[1] - w[0]).length()).sum();
        Self {
            status: PathStatus::Partial,
            waypoints,
            length,
        }
    }

    /// Create a not-found result.
    #[must_use]
    pub fn not_found() -> Self {
        Self {
            status: PathStatus::NotFound,
            waypoints: Vec::new(),
            length: 0.0,
        }
    }

    /// Create an invalid result.
    #[must_use]
    pub fn invalid() -> Self {
        Self {
            status: PathStatus::Invalid,
            waypoints: Vec::new(),
            length: 0.0,
        }
    }

    /// Whether a path was found.
    #[must_use]
    pub fn is_found(&self) -> bool {
        self.status == PathStatus::Found
    }

    /// Whether the path is partial (closest reachable point to unreachable goal).
    #[must_use]
    pub fn is_partial(&self) -> bool {
        self.status == PathStatus::Partial
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn path_result_found() {
        let r = PathResult::found(vec![Vec2::ZERO, Vec2::new(3.0, 4.0)]);
        assert!(r.is_found());
        assert!((r.length - 5.0).abs() < 0.01);
    }

    #[test]
    fn path_result_partial() {
        let r = PathResult::partial(vec![Vec2::ZERO, Vec2::new(3.0, 4.0)]);
        assert!(r.is_partial());
        assert!(!r.is_found());
        assert!((r.length - 5.0).abs() < 0.01);
    }

    #[test]
    fn path_result_not_found() {
        let r = PathResult::not_found();
        assert!(!r.is_found());
        assert_eq!(r.waypoints.len(), 0);
    }

    #[test]
    fn path_result_invalid() {
        let r = PathResult::invalid();
        assert_eq!(r.status, PathStatus::Invalid);
    }

    #[test]
    fn path_request_new() {
        let req = PathRequest::new(Vec2::new(1.0, 2.0), Vec2::new(3.0, 4.0));
        assert_eq!(req.start, Vec2::new(1.0, 2.0));
        assert_eq!(req.goal, Vec2::new(3.0, 4.0));
    }

    #[test]
    fn path_result_zero_length() {
        let r = PathResult::found(vec![Vec2::new(5.0, 5.0)]);
        assert!((r.length - 0.0).abs() < f32::EPSILON);
    }

    #[test]
    fn path_result_serde_roundtrip() {
        let r = PathResult::found(vec![Vec2::ZERO, Vec2::ONE]);
        let json = serde_json::to_string(&r).unwrap();
        let deserialized: PathResult = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.status, PathStatus::Found);
        assert_eq!(deserialized.waypoints.len(), 2);
    }

    #[test]
    fn path_result_multi_segment_length() {
        // 3-4-5 triangle: (0,0) -> (3,0) -> (3,4)
        let r = PathResult::found(vec![Vec2::ZERO, Vec2::new(3.0, 0.0), Vec2::new(3.0, 4.0)]);
        // Length should be 3 + 4 = 7
        assert!((r.length - 7.0).abs() < 0.01);
    }

    #[test]
    fn path_result_empty_waypoints() {
        let r = PathResult::found(vec![]);
        assert!(r.is_found());
        assert!((r.length - 0.0).abs() < f32::EPSILON);
    }

    #[test]
    fn path_status_serde_roundtrip() {
        let status = PathStatus::Pending;
        let json = serde_json::to_string(&status).unwrap();
        let deserialized: PathStatus = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized, status);
    }
}

//! Reusable pathfinding query objects — pre-allocated scratch buffers for zero-alloc pathfinding.

use std::collections::BinaryHeap;

use crate::grid::{GridPos, NavGrid};

#[cfg(feature = "logging")]
use tracing::instrument;

/// A reusable A* query object with pre-allocated scratch buffers.
///
/// Eliminates per-path heap allocations by reusing buffers across
/// multiple pathfinding queries. Useful for high-throughput scenarios
/// where many paths are computed per frame.
///
/// # Example
///
/// ```ignore
/// let mut query = GridPathQuery::new(&grid);
///
/// // First query
/// let path1 = query.find_path(&grid, GridPos::new(0, 0), GridPos::new(9, 9));
///
/// // Second query — reuses same buffers
/// let path2 = query.find_path(&grid, GridPos::new(1, 1), GridPos::new(8, 8));
/// ```
pub struct GridPathQuery {
    g_score: Vec<f32>,
    came_from: Vec<Option<usize>>,
    closed: Vec<bool>,
    open: BinaryHeap<QueryNode>,
    grid_width: usize,
    grid_height: usize,
}

#[derive(Clone, Copy)]
struct QueryNode {
    idx: usize,
    f_score: f32,
}

impl PartialEq for QueryNode {
    fn eq(&self, other: &Self) -> bool {
        self.f_score == other.f_score
    }
}

impl Eq for QueryNode {}

impl PartialOrd for QueryNode {
    fn partial_cmp(&self, other: &Self) -> Option<std::cmp::Ordering> {
        Some(self.cmp(other))
    }
}

impl Ord for QueryNode {
    fn cmp(&self, other: &Self) -> std::cmp::Ordering {
        other
            .f_score
            .partial_cmp(&self.f_score)
            .unwrap_or(std::cmp::Ordering::Equal)
    }
}

impl GridPathQuery {
    /// Create a new query object sized for the given grid.
    ///
    /// Pre-allocates all scratch buffers. The query can only be used
    /// with grids of the same dimensions.
    #[cfg_attr(feature = "logging", instrument(skip(grid)))]
    #[must_use]
    pub fn new(grid: &NavGrid) -> Self {
        let len = grid.width() * grid.height();
        Self {
            g_score: vec![f32::INFINITY; len],
            came_from: vec![None; len],
            closed: vec![false; len],
            open: BinaryHeap::with_capacity(len / 4),
            grid_width: grid.width(),
            grid_height: grid.height(),
        }
    }

    /// Reset scratch buffers for a new query.
    fn reset(&mut self) {
        self.g_score.fill(f32::INFINITY);
        self.came_from.fill(None);
        self.closed.fill(false);
        self.open.clear();
    }

    /// Find a path using A* with pre-allocated buffers.
    ///
    /// Returns `None` if no path exists or start/goal is unwalkable.
    /// The grid must have the same dimensions as the grid used in `new()`.
    #[cfg_attr(feature = "logging", instrument(skip(self, grid)))]
    #[must_use]
    pub fn find_path(
        &mut self,
        grid: &NavGrid,
        start: GridPos,
        goal: GridPos,
    ) -> Option<Vec<GridPos>> {
        debug_assert_eq!(grid.width(), self.grid_width);
        debug_assert_eq!(grid.height(), self.grid_height);

        if !grid.is_walkable(start.x, start.y) || !grid.is_walkable(goal.x, goal.y) {
            return None;
        }
        if start == goal {
            return Some(vec![start]);
        }

        self.reset();

        let start_idx = self.index(start.x, start.y)?;
        let goal_idx = self.index(goal.x, goal.y)?;

        self.g_score[start_idx] = 0.0;
        let h = if grid.allow_diagonal {
            start.octile_distance(goal)
        } else {
            start.manhattan_distance(goal) as f32
        };
        self.open.push(QueryNode {
            idx: start_idx,
            f_score: h,
        });

        let mut neighbors_buf = [(0i32, 0i32, 0.0f32); 8];

        while let Some(current) = self.open.pop() {
            if current.idx == goal_idx {
                return Some(self.reconstruct_path(goal_idx));
            }

            if self.closed[current.idx] {
                continue;
            }
            self.closed[current.idx] = true;

            let cx = (current.idx % self.grid_width) as i32;
            let cy = (current.idx / self.grid_width) as i32;
            let count = grid_neighbors(grid, cx, cy, &mut neighbors_buf);

            for &(nx, ny, move_cost) in &neighbors_buf[..count] {
                let n_idx = ny as usize * self.grid_width + nx as usize;
                if self.closed[n_idx] {
                    continue;
                }
                let tentative_g = self.g_score[current.idx] + move_cost * grid.cost(nx, ny);

                if tentative_g < self.g_score[n_idx] {
                    self.came_from[n_idx] = Some(current.idx);
                    self.g_score[n_idx] = tentative_g;
                    let np = GridPos::new(nx, ny);
                    let h = if grid.allow_diagonal {
                        np.octile_distance(goal)
                    } else {
                        np.manhattan_distance(goal) as f32
                    };
                    self.open.push(QueryNode {
                        idx: n_idx,
                        f_score: tentative_g + h,
                    });
                }
            }
        }

        None
    }

    #[inline]
    fn index(&self, x: i32, y: i32) -> Option<usize> {
        if x >= 0 && y >= 0 && (x as usize) < self.grid_width && (y as usize) < self.grid_height {
            Some(y as usize * self.grid_width + x as usize)
        } else {
            None
        }
    }

    fn reconstruct_path(&self, goal_idx: usize) -> Vec<GridPos> {
        let mut path = Vec::new();
        let mut current = goal_idx;
        loop {
            let x = (current % self.grid_width) as i32;
            let y = (current / self.grid_width) as i32;
            path.push(GridPos::new(x, y));
            match self.came_from[current] {
                Some(prev) => current = prev,
                None => break,
            }
        }
        path.reverse();
        path
    }
}

/// Compute walkable neighbors using the grid's public API.
#[inline]
fn grid_neighbors(grid: &NavGrid, x: i32, y: i32, buf: &mut [(i32, i32, f32); 8]) -> usize {
    const CARDINAL: [(i32, i32); 4] = [(0, 1), (0, -1), (1, 0), (-1, 0)];
    const DIAGONAL: [(i32, i32); 4] = [(1, 1), (1, -1), (-1, 1), (-1, -1)];

    let mut count = 0;
    for (dx, dy) in CARDINAL {
        let nx = x + dx;
        let ny = y + dy;
        if grid.is_walkable(nx, ny) {
            buf[count] = (nx, ny, 1.0);
            count += 1;
        }
    }
    if grid.allow_diagonal {
        for (dx, dy) in DIAGONAL {
            let nx = x + dx;
            let ny = y + dy;
            if grid.is_walkable(nx, ny)
                && grid.is_walkable(x + dx, y)
                && grid.is_walkable(x, y + dy)
            {
                buf[count] = (nx, ny, std::f32::consts::SQRT_2);
                count += 1;
            }
        }
    }
    count
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn query_finds_path() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query = GridPathQuery::new(&grid);
        let path = query.find_path(&grid, GridPos::new(0, 0), GridPos::new(9, 9));
        assert!(path.is_some());
        let path = path.unwrap();
        assert_eq!(*path.first().unwrap(), GridPos::new(0, 0));
        assert_eq!(*path.last().unwrap(), GridPos::new(9, 9));
    }

    #[test]
    fn query_reusable() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query = GridPathQuery::new(&grid);

        let path1 = query.find_path(&grid, GridPos::new(0, 0), GridPos::new(9, 9));
        assert!(path1.is_some());

        // Reuse for different query
        let path2 = query.find_path(&grid, GridPos::new(0, 0), GridPos::new(5, 5));
        assert!(path2.is_some());
        assert_ne!(path1.unwrap().len(), path2.unwrap().len());
    }

    #[test]
    fn query_matches_regular() {
        let mut grid = NavGrid::new(15, 15, 1.0);
        grid.set_walkable(5, 3, false);
        grid.set_walkable(5, 4, false);

        let start = GridPos::new(0, 0);
        let goal = GridPos::new(14, 14);

        let regular = grid.find_path(start, goal).unwrap();

        let mut query = GridPathQuery::new(&grid);
        let queried = query.find_path(&grid, start, goal).unwrap();

        assert_eq!(regular, queried);
    }

    #[test]
    fn query_no_path() {
        let mut grid = NavGrid::new(10, 10, 1.0);
        for y in 0..10 {
            grid.set_walkable(5, y, false);
        }
        let mut query = GridPathQuery::new(&grid);
        assert!(
            query
                .find_path(&grid, GridPos::new(0, 0), GridPos::new(9, 9))
                .is_none()
        );
    }

    #[test]
    fn query_same_start_goal() {
        let grid = NavGrid::new(10, 10, 1.0);
        let mut query = GridPathQuery::new(&grid);
        let path = query.find_path(&grid, GridPos::new(5, 5), GridPos::new(5, 5));
        assert_eq!(path, Some(vec![GridPos::new(5, 5)]));
    }

    #[test]
    fn query_unwalkable() {
        let mut grid = NavGrid::new(10, 10, 1.0);
        grid.set_walkable(0, 0, false);
        let mut query = GridPathQuery::new(&grid);
        assert!(
            query
                .find_path(&grid, GridPos::new(0, 0), GridPos::new(9, 9))
                .is_none()
        );
    }

    #[test]
    fn query_many_sequential() {
        let grid = NavGrid::new(20, 20, 1.0);
        let mut query = GridPathQuery::new(&grid);

        for i in 0..10 {
            let path = query.find_path(&grid, GridPos::new(0, 0), GridPos::new(i, i));
            assert!(path.is_some());
        }
    }
}

//! RVO/ORCA — Reciprocal Velocity Obstacles for local collision avoidance.
//!
//! Implements the ORCA (Optimal Reciprocal Collision Avoidance) algorithm
//! for multi-agent local avoidance.

use std::collections::HashMap;

use hisab::Vec2;
use serde::{Deserialize, Serialize};

#[cfg(feature = "logging")]
use tracing::instrument;

/// A half-plane constraint: all velocities v where `(v - point) · normal ≥ 0`.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct HalfPlane {
    /// A point on the constraint boundary.
    pub point: Vec2,
    /// Outward normal — velocities on this side are permitted.
    pub normal: Vec2,
}

/// An RVO agent with position, velocity, and radius.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
pub struct RvoAgent {
    pub position: Vec2,
    pub velocity: Vec2,
    pub preferred_velocity: Vec2,
    pub radius: f32,
    pub max_speed: f32,
}

impl RvoAgent {
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn new(position: Vec2, radius: f32, max_speed: f32) -> Self {
        Self {
            position,
            velocity: Vec2::ZERO,
            preferred_velocity: Vec2::ZERO,
            radius,
            max_speed,
        }
    }
}

/// Compute the ORCA half-plane constraint between two agents.
///
/// Returns the half-plane that agent A should respect to avoid
/// collision with agent B within `time_horizon` seconds.
/// Each agent takes half the responsibility (reciprocal).
#[cfg_attr(feature = "logging", instrument)]
#[inline(always)]
#[must_use]
pub fn compute_orca_half_plane(a: &RvoAgent, b: &RvoAgent, time_horizon: f32) -> HalfPlane {
    let relative_pos = b.position - a.position;
    let relative_vel = a.velocity - b.velocity;
    let combined_radius = a.radius + b.radius;
    let dist_sq = relative_pos.length_squared();
    let combined_radius_sq = combined_radius * combined_radius;

    let inv_tau = 1.0 / time_horizon;

    if dist_sq > combined_radius_sq {
        // No collision yet — VO is a truncated cone
        let w = relative_vel - relative_pos * inv_tau;
        let w_len_sq = w.length_squared();
        let dot_product = w.dot(relative_pos);

        if dot_product < 0.0 && dot_product * dot_product > combined_radius_sq * w_len_sq {
            // Project on cutoff circle
            let w_len = w_len_sq.sqrt();
            let unit_w = w / w_len;
            let normal = unit_w;
            let u = unit_w * (combined_radius * inv_tau - w_len);
            HalfPlane {
                point: a.velocity + u * 0.5,
                normal,
            }
        } else {
            // Project on cone legs
            let leg = (dist_sq - combined_radius_sq).max(0.0).sqrt();
            if relative_pos.perp_dot(w) > 0.0 {
                // Left leg
                let direction = Vec2::new(
                    relative_pos.x * leg - relative_pos.y * combined_radius,
                    relative_pos.x * combined_radius + relative_pos.y * leg,
                ) / dist_sq;
                let normal = Vec2::new(direction.y, -direction.x);
                let dot = relative_vel.dot(direction);
                let u = direction * dot - relative_vel;
                HalfPlane {
                    point: a.velocity + u * 0.5,
                    normal,
                }
            } else {
                // Right leg
                let direction = Vec2::new(
                    relative_pos.x * leg + relative_pos.y * combined_radius,
                    -relative_pos.x * combined_radius + relative_pos.y * leg,
                ) / dist_sq;
                let normal = Vec2::new(-direction.y, direction.x);
                let dot = relative_vel.dot(direction);
                let u = direction * dot - relative_vel;
                HalfPlane {
                    point: a.velocity + u * 0.5,
                    normal,
                }
            }
        }
    } else {
        // Already overlapping — push apart immediately
        let inv_dt = 1.0 / 0.001_f32.max(time_horizon * 0.5);
        let w = relative_vel - relative_pos * inv_dt;
        let w_len = w.length();
        if w_len < f32::EPSILON {
            // Exactly overlapping with same velocity — push in arbitrary direction
            return HalfPlane {
                point: a.velocity,
                normal: Vec2::new(1.0, 0.0),
            };
        }
        let unit_w = w / w_len;
        let normal = unit_w;
        let u = unit_w * (combined_radius * inv_dt - w_len);
        HalfPlane {
            point: a.velocity + u * 0.5,
            normal,
        }
    }
}

/// Solve for the optimal velocity given ORCA half-plane constraints.
///
/// Finds the velocity closest to `preferred` that satisfies all half-plane
/// constraints and has magnitude ≤ `max_speed`.
///
/// Uses 2D incremental linear programming: processes constraints one at a
/// time, projecting onto the constraint boundary when violated.
#[cfg_attr(feature = "logging", instrument)]
#[must_use]
pub fn solve_velocity(constraints: &[HalfPlane], preferred: Vec2, max_speed: f32) -> Vec2 {
    // Start with preferred velocity, clamped to max speed
    let mut result = if preferred.length() > max_speed {
        preferred.normalize() * max_speed
    } else {
        preferred
    };

    for (i, constraint) in constraints.iter().enumerate() {
        // Check if current result satisfies this constraint
        if (result - constraint.point).dot(constraint.normal) >= 0.0 {
            continue;
        }

        // Project onto the constraint line
        // The constraint boundary is: point + t * direction, where direction ⊥ normal
        let direction = Vec2::new(-constraint.normal.y, constraint.normal.x);
        let t = (result - constraint.point).dot(direction);
        let projected = constraint.point + direction * t;

        // Clamp to max speed circle
        result = if projected.length() > max_speed {
            projected.normalize() * max_speed
        } else {
            projected
        };

        // Verify all previous constraints still hold; if not, find best point
        // on intersection of violated constraints
        let mut all_satisfied = true;
        for prev in &constraints[..i] {
            if (result - prev.point).dot(prev.normal) < -f32::EPSILON {
                all_satisfied = false;
                break;
            }
        }

        if !all_satisfied {
            // Fallback: find the best velocity on the current constraint line
            // that satisfies all previous constraints
            result = solve_on_line(constraint, &constraints[..i], max_speed);
        }
    }

    result
}

/// Find the best velocity on a constraint line that satisfies all other constraints.
#[inline]
fn solve_on_line(line: &HalfPlane, constraints: &[HalfPlane], max_speed: f32) -> Vec2 {
    let direction = Vec2::new(-line.normal.y, line.normal.x);

    // t range on the line: point + t * direction
    let mut t_min = -max_speed * 2.0;
    let mut t_max = max_speed * 2.0;

    // Intersect with max speed circle
    let a = direction.dot(direction); // always 1 for unit direction, but be safe
    let b = 2.0 * line.point.dot(direction);
    let c = line.point.dot(line.point) - max_speed * max_speed;
    let disc = b * b - 4.0 * a * c;

    if disc < 0.0 {
        // Line doesn't intersect the speed circle — return closest point on circle
        let center_t = -b / (2.0 * a);
        let p = line.point + direction * center_t;
        return if p.length() > f32::EPSILON {
            p.normalize() * max_speed
        } else {
            Vec2::ZERO
        };
    }

    let sqrt_disc = disc.sqrt();
    let circle_t_min = (-b - sqrt_disc) / (2.0 * a);
    let circle_t_max = (-b + sqrt_disc) / (2.0 * a);
    t_min = t_min.max(circle_t_min);
    t_max = t_max.min(circle_t_max);

    // Intersect with each constraint
    for constraint in constraints {
        let denom = direction.dot(constraint.normal);
        let numer = (constraint.point - line.point).dot(constraint.normal);

        if denom.abs() < f32::EPSILON {
            // Parallel — check if on the valid side
            if numer < 0.0 {
                return line.point; // infeasible, return best guess
            }
            continue;
        }

        let t = numer / denom;
        if denom > 0.0 {
            t_min = t_min.max(t);
        } else {
            t_max = t_max.min(t);
        }

        if t_min > t_max {
            return line.point; // infeasible
        }
    }

    // Project preferred direction onto the valid range
    // (just pick the t closest to 0 in the valid range)
    let t = 0.0f32.clamp(t_min, t_max);
    line.point + direction * t
}

/// Spatial hash grid for efficient neighbor queries.
///
/// Maps 2D positions to grid cells so that nearby agents can be found in O(1)
/// per cell rather than scanning all agents.
#[derive(Debug, Clone)]
struct SpatialHash {
    inv_cell_size: f32,
    cells: HashMap<(i32, i32), Vec<usize>>,
}

impl SpatialHash {
    #[must_use]
    fn new(cell_size: f32) -> Self {
        Self {
            inv_cell_size: 1.0 / cell_size,
            cells: HashMap::new(),
        }
    }

    /// Clear all cell contents without deallocating.
    fn clear(&mut self) {
        for v in self.cells.values_mut() {
            v.clear();
        }
    }

    #[inline]
    #[must_use]
    fn cell_key(&self, pos: Vec2) -> (i32, i32) {
        (
            (pos.x * self.inv_cell_size).floor() as i32,
            (pos.y * self.inv_cell_size).floor() as i32,
        )
    }

    #[inline]
    fn insert(&mut self, idx: usize, pos: Vec2) {
        let key = self.cell_key(pos);
        self.cells.entry(key).or_default().push(idx);
    }

    /// Query all agent indices in cells overlapping the given position +/- radius.
    #[inline]
    fn query_neighbors(&self, pos: Vec2, radius: f32, result: &mut Vec<usize>) {
        let min_x = ((pos.x - radius) * self.inv_cell_size).floor() as i32;
        let max_x = ((pos.x + radius) * self.inv_cell_size).floor() as i32;
        let min_y = ((pos.y - radius) * self.inv_cell_size).floor() as i32;
        let max_y = ((pos.y + radius) * self.inv_cell_size).floor() as i32;

        for cy in min_y..=max_y {
            for cx in min_x..=max_x {
                if let Some(cell) = self.cells.get(&(cx, cy)) {
                    result.extend_from_slice(cell);
                }
            }
        }
    }
}

/// SOA (struct-of-arrays) layout for agent data — enables better auto-vectorization.
///
/// Stores agent fields in separate contiguous arrays so that inner loops
/// touching only positions (or only radii, etc.) get cache-friendly access
/// and the compiler can auto-vectorize with SIMD instructions.
#[derive(Debug, Clone, Default)]
struct AgentSoa {
    positions_x: Vec<f32>,
    positions_y: Vec<f32>,
    velocities_x: Vec<f32>,
    velocities_y: Vec<f32>,
    preferred_x: Vec<f32>,
    preferred_y: Vec<f32>,
    radii: Vec<f32>,
    max_speeds: Vec<f32>,
}

impl AgentSoa {
    /// Rebuild SOA arrays from the canonical AOS agent slice.
    fn rebuild(&mut self, agents: &[RvoAgent]) {
        let n = agents.len();
        self.positions_x.resize(n, 0.0);
        self.positions_y.resize(n, 0.0);
        self.velocities_x.resize(n, 0.0);
        self.velocities_y.resize(n, 0.0);
        self.preferred_x.resize(n, 0.0);
        self.preferred_y.resize(n, 0.0);
        self.radii.resize(n, 0.0);
        self.max_speeds.resize(n, 0.0);

        for (i, a) in agents.iter().enumerate() {
            self.positions_x[i] = a.position.x;
            self.positions_y[i] = a.position.y;
            self.velocities_x[i] = a.velocity.x;
            self.velocities_y[i] = a.velocity.y;
            self.preferred_x[i] = a.preferred_velocity.x;
            self.preferred_y[i] = a.preferred_velocity.y;
            self.radii[i] = a.radius;
            self.max_speeds[i] = a.max_speed;
        }
    }
}

/// Multi-agent RVO simulation.
///
/// Manages a set of agents and computes collision-free velocities each tick.
/// Uses a spatial hash grid for efficient neighbor queries, reducing the
/// constraint computation from O(n^2) to O(n*k) where k is the average
/// number of nearby agents.
///
/// Internally uses SOA (struct-of-arrays) caching and pre-allocated work
/// buffers to minimize per-frame allocations and improve cache locality.
#[derive(Debug, Clone)]
pub struct RvoSimulation {
    agents: Vec<RvoAgent>,
    time_horizon: f32,
    neighbor_dist: f32,
    spatial_hash: SpatialHash,
    // Pre-allocated work buffers (avoid per-frame allocation)
    soa: AgentSoa,
    new_velocities: Vec<Vec2>,
    constraint_buf: Vec<HalfPlane>,
    neighbor_buf: Vec<usize>,
}

impl RvoSimulation {
    /// Create a new simulation with the given time horizon.
    ///
    /// Uses a default neighbor distance of `time_horizon * 20.0`, which is
    /// generous enough for most scenarios. For tighter control, use
    /// [`with_neighbor_dist`](Self::with_neighbor_dist).
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn new(time_horizon: f32) -> Self {
        let neighbor_dist = time_horizon * 20.0;
        Self {
            agents: Vec::new(),
            time_horizon,
            neighbor_dist,
            spatial_hash: SpatialHash::new(neighbor_dist),
            soa: AgentSoa::default(),
            new_velocities: Vec::new(),
            constraint_buf: Vec::new(),
            neighbor_buf: Vec::new(),
        }
    }

    /// Create a new simulation with custom neighbor distance for spatial hashing.
    ///
    /// `neighbor_dist` is the maximum distance at which agents interact.
    /// Agents further apart than this are skipped during constraint computation.
    /// A good default is `max_agent_speed * time_horizon * 2.0`.
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn with_neighbor_dist(time_horizon: f32, neighbor_dist: f32) -> Self {
        Self {
            agents: Vec::new(),
            time_horizon,
            neighbor_dist,
            spatial_hash: SpatialHash::new(neighbor_dist),
            soa: AgentSoa::default(),
            new_velocities: Vec::new(),
            constraint_buf: Vec::new(),
            neighbor_buf: Vec::new(),
        }
    }

    /// Add an agent and return its index.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn add_agent(&mut self, agent: RvoAgent) -> usize {
        let idx = self.agents.len();
        self.agents.push(agent);
        idx
    }

    /// Number of agents.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    #[must_use]
    pub fn agent_count(&self) -> usize {
        self.agents.len()
    }

    /// Get an agent by index.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    #[must_use]
    pub fn agent(&self, idx: usize) -> &RvoAgent {
        &self.agents[idx]
    }

    /// Mutable access to an agent.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn agent_mut(&mut self, idx: usize) -> &mut RvoAgent {
        &mut self.agents[idx]
    }

    /// Set the preferred velocity for an agent.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn set_preferred_velocity(&mut self, idx: usize, velocity: Vec2) {
        self.agents[idx].preferred_velocity = velocity;
    }

    /// Step the simulation by `dt` seconds.
    ///
    /// Rebuilds the spatial hash and SOA cache, computes ORCA constraints for
    /// nearby agent pairs, solves for safe velocities, and updates positions.
    ///
    /// Uses pre-allocated buffers to avoid per-frame allocations and SOA layout
    /// for cache-friendly distance checks.
    #[cfg_attr(feature = "logging", instrument(skip(self), fields(agents = self.agents.len())))]
    pub fn step(&mut self, dt: f32) {
        let n = self.agents.len();

        // Reuse velocity buffer across frames
        self.new_velocities.resize(n, Vec2::ZERO);
        self.new_velocities.fill(Vec2::ZERO);

        // Rebuild SOA cache for cache-friendly inner-loop access
        self.soa.rebuild(&self.agents);

        // Rebuild spatial hash
        self.spatial_hash.clear();
        for (i, agent) in self.agents.iter().enumerate() {
            self.spatial_hash.insert(i, agent.position);
        }

        let neighbor_dist_sq = self.neighbor_dist * self.neighbor_dist;

        #[allow(clippy::needless_range_loop)]
        for i in 0..n {
            self.constraint_buf.clear();
            self.neighbor_buf.clear();

            // Query nearby agents via spatial hash
            self.spatial_hash.query_neighbors(
                self.agents[i].position,
                self.neighbor_dist,
                &mut self.neighbor_buf,
            );

            for j_idx in 0..self.neighbor_buf.len() {
                let j = self.neighbor_buf[j_idx];
                if i == j {
                    continue;
                }
                // SOA-based distance check — cache-friendly scalar access
                let dx = self.soa.positions_x[j] - self.soa.positions_x[i];
                let dy = self.soa.positions_y[j] - self.soa.positions_y[i];
                let dist_sq = dx * dx + dy * dy;
                if dist_sq > neighbor_dist_sq {
                    continue;
                }

                let hp =
                    compute_orca_half_plane(&self.agents[i], &self.agents[j], self.time_horizon);
                self.constraint_buf.push(hp);
            }

            self.new_velocities[i] = solve_velocity(
                &self.constraint_buf,
                self.agents[i].preferred_velocity,
                self.agents[i].max_speed,
            );
        }

        // Apply velocities and move
        for (i, agent) in self.agents.iter_mut().enumerate() {
            agent.velocity = self.new_velocities[i];
            agent.position += agent.velocity * dt;
        }
    }
}

