        };
        let json = serde_json::to_string(&b).unwrap();
        let deserialized: SteerBehavior3D = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized, b);
    }

    #[test]
    fn steer_output_3d_speed() {
        let out = SteerOutput3D::new(3.0, 4.0, 0.0);
        assert!((out.speed() - 5.0).abs() < 0.01);
    }

    #[test]
    fn steer_output_3d_serde_roundtrip() {
        let out = SteerOutput3D::new(1.0, 2.0, 3.0);
        let json = serde_json::to_string(&out).unwrap();
        let deserialized: SteerOutput3D = serde_json::from_str(&json).unwrap();
        assert!((deserialized.velocity - out.velocity).length() < f32::EPSILON);
    }
}

//! Tiled NavMesh — streaming and localized re-baking for open worlds.

use std::collections::HashMap;

use hisab::Vec2;
use serde::{Deserialize, Serialize};

use crate::mesh::{NavMesh, NavPolyId};

#[cfg(feature = "logging")]
use tracing::instrument;

/// Identifies a tile by its grid coordinates.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct TileCoord {
    pub x: i32,
    pub y: i32,
}

impl TileCoord {
    #[must_use]
    pub fn new(x: i32, y: i32) -> Self {
        Self { x, y }
    }
}

/// A globally unique polygon ID combining tile coordinate and local polygon index.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct GlobalPolyId {
    pub tile: TileCoord,
    pub local: NavPolyId,
}

/// A tile containing its own local navmesh.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NavTile {
    /// The tile's local navmesh.
    pub mesh: NavMesh,
    /// World-space origin of this tile (bottom-left corner).
    pub origin: Vec2,
}

/// Connection between polygons across tile boundaries.
#[derive(Debug, Clone, Copy, Serialize, Deserialize)]
struct TileConnection {
    from: GlobalPolyId,
    to: GlobalPolyId,
    cost: f32,
}

/// A tiled navmesh for open-world navigation.
///
/// Divides the world into rectangular tiles, each with its own `NavMesh`.
/// Supports streaming (load/unload tiles at runtime) and localized
/// re-baking (only rebuild the affected tile).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TiledNavMesh {
    /// Size of each tile in world units.
    tile_size: f32,
    /// Loaded tiles.
    #[serde(
        serialize_with = "serialize_tile_map",
        deserialize_with = "deserialize_tile_map"
    )]
    tiles: HashMap<TileCoord, NavTile>,
    /// Cross-tile connections (border polygon pairs).
    connections: Vec<TileConnection>,
}

fn serialize_tile_map<S>(
    map: &HashMap<TileCoord, NavTile>,
    serializer: S,
) -> Result<S::Ok, S::Error>
where
    S: serde::Serializer,
{
    use serde::ser::SerializeSeq;
    let mut seq = serializer.serialize_seq(Some(map.len()))?;
    for (k, v) in map {
        seq.serialize_element(&(*k, v))?;
    }
    seq.end()
}

fn deserialize_tile_map<'de, D>(deserializer: D) -> Result<HashMap<TileCoord, NavTile>, D::Error>
where
    D: serde::Deserializer<'de>,
{
    let entries: Vec<(TileCoord, NavTile)> = Vec::deserialize(deserializer)?;
    Ok(entries.into_iter().collect())
}

impl TiledNavMesh {
    /// Create a new tiled navmesh with the given tile size.
    #[cfg_attr(feature = "logging", instrument)]
    #[must_use]
    pub fn new(tile_size: f32) -> Self {
        Self {
            tile_size,
            tiles: HashMap::new(),
            connections: Vec::new(),
        }
    }

    /// Tile size in world units.
    #[must_use]
    pub fn tile_size(&self) -> f32 {
        self.tile_size
    }

    /// Number of loaded tiles.
    #[must_use]
    pub fn tile_count(&self) -> usize {
        self.tiles.len()
    }

    /// Get the tile coordinate for a world position.
    #[must_use]
    pub fn world_to_tile(&self, pos: Vec2) -> TileCoord {
        TileCoord {
            x: (pos.x / self.tile_size).floor() as i32,
            y: (pos.y / self.tile_size).floor() as i32,
        }
    }

    /// Load (insert) a tile. If a tile already exists at this coordinate, it is replaced.
    ///
    /// After loading, call `rebuild_connections()` to update cross-tile connectivity.
    #[cfg_attr(feature = "logging", instrument(skip(self, mesh)))]
    pub fn load_tile(&mut self, coord: TileCoord, mesh: NavMesh) {
        let origin = Vec2::new(
            coord.x as f32 * self.tile_size,
            coord.y as f32 * self.tile_size,
        );
        self.tiles.insert(coord, NavTile { mesh, origin });
    }

    /// Unload (remove) a tile.
    ///
    /// After unloading, call `rebuild_connections()` to update connectivity.
    pub fn unload_tile(&mut self, coord: TileCoord) -> bool {
        let removed = self.tiles.remove(&coord).is_some();
        if removed {
            // Remove connections involving this tile
            self.connections
                .retain(|c| c.from.tile != coord && c.to.tile != coord);
        }
        removed
    }

    /// Check if a tile is loaded.
    #[must_use]
    pub fn has_tile(&self, coord: TileCoord) -> bool {
        self.tiles.contains_key(&coord)
    }

    /// Get a tile's navmesh.
    #[must_use]
    pub fn get_tile(&self, coord: TileCoord) -> Option<&NavTile> {
        self.tiles.get(&coord)
    }

    /// Re-bake a single tile from new boundary geometry.
    ///
    /// Replaces the tile's navmesh with a freshly baked one and rebuilds
    /// only the connections involving this tile and its neighbors.
    /// Much cheaper than `rebuild_connections()` for the full mesh.
    ///
    /// `boundary` is in tile-local coordinates (origin at 0,0).
    #[cfg_attr(feature = "logging", instrument(skip(self, boundary)))]
    pub fn rebake_tile(&mut self, coord: TileCoord, boundary: &[Vec2]) {
        let mesh = NavMesh::bake(boundary);
        self.load_tile(coord, mesh);
        self.rebuild_tile_connections(coord);
    }

    /// Rebuild connections for a single tile and its neighbors.
    ///
    /// Cheaper than full `rebuild_connections()` when only one tile changed.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn rebuild_tile_connections(&mut self, coord: TileCoord) {
        // Remove old connections involving this tile
        self.connections
            .retain(|c| c.from.tile != coord && c.to.tile != coord);

        // Reconnect with all 4 neighbors
        let neighbors = [
            (TileCoord::new(coord.x + 1, coord.y), Border::Right),
            (TileCoord::new(coord.x - 1, coord.y), Border::Left),
            (TileCoord::new(coord.x, coord.y + 1), Border::Top),
            (TileCoord::new(coord.x, coord.y - 1), Border::Bottom),
        ];

        for (neighbor, border) in neighbors {
            if !self.tiles.contains_key(&neighbor) {
                continue;
            }
            match border {
                Border::Right => self.connect_tiles(coord, neighbor, Border::Right),
                Border::Left => self.connect_tiles(neighbor, coord, Border::Right),
                Border::Top => self.connect_tiles(coord, neighbor, Border::Top),
                Border::Bottom => self.connect_tiles(neighbor, coord, Border::Top),
            }
        }
    }

    /// Rebuild cross-tile connections for all loaded tiles.
    ///
    /// Scans border polygons of adjacent tiles and creates connections
    /// between polygons that share vertices near tile boundaries.
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    pub fn rebuild_connections(&mut self) {
        self.connections.clear();

        let coords: Vec<TileCoord> = self.tiles.keys().copied().collect();

        for &coord in &coords {
            // Check right neighbor
            let right = TileCoord::new(coord.x + 1, coord.y);
            if self.tiles.contains_key(&right) {
                self.connect_tiles(coord, right, Border::Right);
            }
            // Check top neighbor
            let top = TileCoord::new(coord.x, coord.y + 1);
            if self.tiles.contains_key(&top) {
                self.connect_tiles(coord, top, Border::Top);
            }
        }
    }

    /// Find a path across tiles from start to goal (world positions).
    ///
    /// Performs a two-level search:
    /// 1. Find start/goal tiles and local polygons
    /// 2. A* across tiles using connections
    ///
    /// Returns the path as a sequence of world-space waypoints (polygon centroids).
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    #[must_use]
    pub fn find_path(&self, start: Vec2, goal: Vec2) -> Option<Vec<Vec2>> {
        let start_tile_coord = self.world_to_tile(start);
        let goal_tile_coord = self.world_to_tile(goal);

        let start_tile = self.tiles.get(&start_tile_coord)?;
        let _goal_tile = self.tiles.get(&goal_tile_coord)?;

        // If same tile, use local pathfinding
        if start_tile_coord == goal_tile_coord {
            let local_start = start - start_tile.origin;
            let local_goal = goal - start_tile.origin;
            let poly_path = start_tile.mesh.find_path(local_start, local_goal)?;
            return Some(
                poly_path
                    .iter()
                    .filter_map(|&id| start_tile.mesh.get_poly(id))
                    .map(|p| p.centroid() + start_tile.origin)
                    .collect(),
            );
        }

        // Cross-tile: simple A* on the global graph
        self.cross_tile_path(start, goal, start_tile_coord, goal_tile_coord)
    }

    /// Cross-tile A* pathfinding on the global polygon graph.
    fn cross_tile_path(
        &self,
        start: Vec2,
        goal: Vec2,
        start_tile: TileCoord,
        goal_tile: TileCoord,
    ) -> Option<Vec<Vec2>> {
        use std::cmp::Ordering;
        use std::collections::BinaryHeap;

        // Build a simple global node list: (tile, local_poly_id) -> global index
        let mut nodes: Vec<GlobalPolyId> = Vec::new();
        let mut node_positions: Vec<Vec2> = Vec::new();
        let mut tile_node_map: HashMap<GlobalPolyId, usize> = HashMap::new();

        for (&coord, tile) in &self.tiles {
            for poly in tile.mesh.polys() {
                let gid = GlobalPolyId {
                    tile: coord,
                    local: poly.id,
                };
                let idx = nodes.len();
                tile_node_map.insert(gid, idx);
                nodes.push(gid);
                node_positions.push(poly.centroid() + tile.origin);
            }
        }

        if nodes.is_empty() {
            return None;
        }

        // Find start and goal nodes
        let st = self.tiles.get(&start_tile)?;
        let local_start = start - st.origin;
        let start_poly = st.mesh.find_poly_at(local_start)?;
        let start_gid = GlobalPolyId {
            tile: start_tile,
            local: start_poly,
        };
        let start_idx = *tile_node_map.get(&start_gid)?;

        let gt = self.tiles.get(&goal_tile)?;
        let local_goal = goal - gt.origin;
        let goal_poly = gt.mesh.find_poly_at(local_goal)?;
        let goal_gid = GlobalPolyId {
            tile: goal_tile,
            local: goal_poly,
        };
        let goal_idx = *tile_node_map.get(&goal_gid)?;

        // Build adjacency: local neighbors + cross-tile connections
        let n = nodes.len();
        let mut adj: Vec<Vec<(usize, f32)>> = vec![Vec::new(); n];

        // Local neighbors
        for (&coord, tile) in &self.tiles {
            for poly in tile.mesh.polys() {
                let gid = GlobalPolyId {
                    tile: coord,
                    local: poly.id,
                };
                let from_idx = tile_node_map[&gid];
                for &neighbor_id in &poly.neighbors {
                    let ngid = GlobalPolyId {
                        tile: coord,
                        local: neighbor_id,
                    };
                    if let Some(&to_idx) = tile_node_map.get(&ngid) {
                        let cost = node_positions[from_idx].distance(node_positions[to_idx]);
                        adj[from_idx].push((to_idx, cost));
                    }
                }
            }
        }

        // Cross-tile connections
        for conn in &self.connections {
            if let (Some(&from_idx), Some(&to_idx)) =
                (tile_node_map.get(&conn.from), tile_node_map.get(&conn.to))
            {
                adj[from_idx].push((to_idx, conn.cost));
                adj[to_idx].push((from_idx, conn.cost));
            }
        }

        // A*
        #[derive(Clone, Copy)]
        struct AStarNode {
            idx: usize,
            f: f32,
        }

        impl PartialEq for AStarNode {
            fn eq(&self, other: &Self) -> bool {
                self.f == other.f
            }
        }

        impl Eq for AStarNode {}

        impl PartialOrd for AStarNode {
            fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
                Some(self.cmp(other))
            }
        }

        impl Ord for AStarNode {
            fn cmp(&self, other: &Self) -> Ordering {
                other.f.partial_cmp(&self.f).unwrap_or(Ordering::Equal)
            }
        }

        let mut g = vec![f32::INFINITY; n];
        let mut came_from: Vec<Option<usize>> = vec![None; n];
        let mut closed = vec![false; n];
        let mut open = BinaryHeap::new();

        g[start_idx] = 0.0;
        let h = node_positions[start_idx].distance(node_positions[goal_idx]);
        open.push(AStarNode {
            idx: start_idx,
            f: h,
        });

        while let Some(current) = open.pop() {
            if current.idx == goal_idx {
                // Reconstruct path
                let mut path = Vec::new();
                let mut cur = goal_idx;
                loop {
                    path.push(node_positions[cur]);
                    match came_from[cur] {
                        Some(prev) => cur = prev,
                        None => break,
                    }
                }
                path.reverse();
                return Some(path);
            }

            if closed[current.idx] {
                continue;
            }
            closed[current.idx] = true;

            for &(ni, cost) in &adj[current.idx] {
                if closed[ni] {
                    continue;
                }
                let tg = g[current.idx] + cost;
                if tg < g[ni] {
                    g[ni] = tg;
                    came_from[ni] = Some(current.idx);
                    let h = node_positions[ni].distance(node_positions[goal_idx]);
                    open.push(AStarNode { idx: ni, f: tg + h });
                }
            }
        }

        None
    }

    /// Connect border polygons between two adjacent tiles.
    fn connect_tiles(&mut self, a: TileCoord, b: TileCoord, border: Border) {
        let tile_a = match self.tiles.get(&a) {
            Some(t) => t,
            None => return,
        };
        let tile_b = match self.tiles.get(&b) {
            Some(t) => t,
            None => return,
        };

        let threshold = self.tile_size * 0.05; // 5% tolerance for border matching

        // Collect polygon data to avoid borrow conflicts
        let polys_a: Vec<(NavPolyId, Vec<Vec2>, Vec2)> = tile_a
            .mesh
            .polys()
            .iter()
            .map(|p| (p.id, p.vertices.clone(), p.centroid() + tile_a.origin))
            .collect();
        let polys_b: Vec<(NavPolyId, Vec<Vec2>, Vec2)> = tile_b
            .mesh
            .polys()
            .iter()
            .map(|p| (p.id, p.vertices.clone(), p.centroid() + tile_b.origin))
            .collect();

        let origin_a = tile_a.origin;
        let origin_b = tile_b.origin;
        let tile_size = self.tile_size;

        let opposite = match border {
            Border::Right => Border::Left,
            Border::Top => Border::Bottom,
            _ => return,
        };

        for (id_a, verts_a, centroid_a) in &polys_a {
            if !is_near_border(verts_a, tile_size, border, threshold) {
                continue;
            }

            for (id_b, verts_b, centroid_b) in &polys_b {
                if !is_near_border(verts_b, tile_size, opposite, threshold) {
                    continue;
                }

                if has_shared_border_vertices(verts_a, origin_a, verts_b, origin_b, threshold) {
                    let cost = centroid_a.distance(*centroid_b);
                    self.connections.push(TileConnection {
                        from: GlobalPolyId {
                            tile: a,
                            local: *id_a,
                        },
                        to: GlobalPolyId {
                            tile: b,
                            local: *id_b,
                        },
                        cost,
                    });
                }
            }
        }
    }
}

#[derive(Debug, Clone, Copy)]
enum Border {
    Right,
    Top,
    Left,
    Bottom,
}

/// Check if any vertex of a polygon is near a tile border.
fn is_near_border(vertices: &[Vec2], tile_size: f32, border: Border, threshold: f32) -> bool {
    for v in vertices {
        match border {
            Border::Right => {
                if (v.x - tile_size).abs() < threshold {
                    return true;
                }
            }
            Border::Left => {
                if v.x.abs() < threshold {
                    return true;
                }
            }
            Border::Top => {
                if (v.y - tile_size).abs() < threshold {
                    return true;
                }
            }
            Border::Bottom => {
                if v.y.abs() < threshold {
                    return true;
                }
            }
        }
    }
    false
}

/// Check if two polygons share vertices near the tile boundary.
fn has_shared_border_vertices(
    verts_a: &[Vec2],
    origin_a: Vec2,
    verts_b: &[Vec2],
    origin_b: Vec2,
    threshold: f32,
) -> bool {
    for va in verts_a {
        let world_a = *va + origin_a;
        for vb in verts_b {
            let world_b = *vb + origin_b;
            if world_a.distance(world_b) < threshold {
                return true;
            }
        }
    }
    false
}

#[cfg(test)]
mod tests {
    use super::*;
    use crate::mesh::NavPoly;

    fn make_tile_mesh() -> NavMesh {
        // Simple square polygon from (0,0) to (10,10)
        let mut mesh = NavMesh::new();
        mesh.add_poly(NavPoly {
            id: NavPolyId(0),
            vertices: vec![
                Vec2::ZERO,
                Vec2::new(10.0, 0.0),
                Vec2::new(10.0, 10.0),
                Vec2::new(0.0, 10.0),
            ],
            neighbors: vec![],
            cost: 1.0,
            layer: 0,
        });
        mesh
    }

    #[test]
    fn tiled_basic() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        assert_eq!(tiled.tile_count(), 1);
        assert!(tiled.has_tile(TileCoord::new(0, 0)));
    }

    #[test]
    fn tiled_world_to_tile() {
        let tiled = TiledNavMesh::new(10.0);
        assert_eq!(
            tiled.world_to_tile(Vec2::new(5.0, 5.0)),
            TileCoord::new(0, 0)
        );
        assert_eq!(
            tiled.world_to_tile(Vec2::new(15.0, 5.0)),
            TileCoord::new(1, 0)
        );
        assert_eq!(
            tiled.world_to_tile(Vec2::new(-5.0, -5.0)),
            TileCoord::new(-1, -1)
        );
    }

    #[test]
    fn tiled_same_tile_path() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        let path = tiled.find_path(Vec2::new(2.0, 2.0), Vec2::new(8.0, 8.0));
        assert!(path.is_some());
    }

    #[test]
    fn tiled_unload() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        assert!(tiled.unload_tile(TileCoord::new(0, 0)));
        assert!(!tiled.has_tile(TileCoord::new(0, 0)));
        assert_eq!(tiled.tile_count(), 0);
    }

    #[test]
    fn tiled_unload_nonexistent() {
        let mut tiled = TiledNavMesh::new(10.0);
        assert!(!tiled.unload_tile(TileCoord::new(0, 0)));
    }

    #[test]
    fn tiled_cross_tile_path() {
        let mut tiled = TiledNavMesh::new(10.0);

        // Two tiles side by side, each with a square polygon
        // Tile (0,0): polygon with vertex at (10,0)-(10,10) on right border
        // Tile (1,0): polygon with vertex at (0,0)-(0,10) on left border (= world 10,0-10,10)
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        tiled.load_tile(TileCoord::new(1, 0), make_tile_mesh());
        tiled.rebuild_connections();

        let path = tiled.find_path(Vec2::new(5.0, 5.0), Vec2::new(15.0, 5.0));
        assert!(path.is_some());
        let path = path.unwrap();
        assert!(path.len() >= 2);
    }

    #[test]
    fn tiled_no_path_unloaded_tile() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        // Goal is in unloaded tile
        assert!(
            tiled
                .find_path(Vec2::new(5.0, 5.0), Vec2::new(25.0, 5.0))
                .is_none()
        );
    }

    #[test]
    fn tiled_serde_roundtrip() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        let json = serde_json::to_string(&tiled).unwrap();
        let deserialized: TiledNavMesh = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.tile_count(), 1);
    }

    #[test]
    fn tile_coord_new() {
        let tc = TileCoord::new(3, -2);
        assert_eq!(tc.x, 3);
        assert_eq!(tc.y, -2);
    }

    #[test]
    fn rebake_tile() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        assert_eq!(
            tiled
                .get_tile(TileCoord::new(0, 0))
                .unwrap()
                .mesh
                .poly_count(),
            1
        );

        // Rebake with a triangle
        tiled.rebake_tile(
            TileCoord::new(0, 0),
            &[Vec2::ZERO, Vec2::new(10.0, 0.0), Vec2::new(5.0, 10.0)],
        );
        assert!(tiled.has_tile(TileCoord::new(0, 0)));
        // Poly count may differ after rebake
        assert!(
            tiled
                .get_tile(TileCoord::new(0, 0))
                .unwrap()
                .mesh
                .poly_count()
                >= 1
        );
    }

    #[test]
    fn rebuild_tile_connections_local() {
        let mut tiled = TiledNavMesh::new(10.0);
        tiled.load_tile(TileCoord::new(0, 0), make_tile_mesh());
        tiled.load_tile(TileCoord::new(1, 0), make_tile_mesh());
        tiled.rebuild_connections();

        // Rebake one tile — connections should still work
        tiled.rebake_tile(
            TileCoord::new(0, 0),
            &[
                Vec2::ZERO,
                Vec2::new(10.0, 0.0),
                Vec2::new(10.0, 10.0),
                Vec2::new(0.0, 10.0),
            ],
        );

        let path = tiled.find_path(Vec2::new(5.0, 5.0), Vec2::new(15.0, 5.0));
        assert!(path.is_some());
    }
}

//! Ear-clipping triangulation of simple polygons.

use hisab::Vec2;

/// Triangulate a simple polygon using the ear-clipping algorithm.
///
/// Input: vertices of a simple (non-self-intersecting) polygon in CCW order.
/// Returns a list of triangle index triples `(i, j, k)` into the input slice.
///
/// Returns an empty vec if the polygon has fewer than 3 vertices.
#[must_use]
pub fn triangulate(vertices: &[Vec2]) -> Vec<(usize, usize, usize)> {
    let n = vertices.len();
    if n < 3 {
        return Vec::new();
    }
    if n == 3 {
        return vec![(0, 1, 2)];
    }

    // Ensure CCW winding — if CW, reverse the index list
    let mut indices: Vec<usize> = (0..n).collect();
    if signed_area(vertices) < 0.0 {
        indices.reverse();
    }

    let mut triangles = Vec::with_capacity(n - 2);
    ear_clip(vertices, &mut indices, &mut triangles);
    triangles
}

/// Triangulate and return the actual triangle vertices (not indices).
#[must_use]
pub fn triangulate_points(vertices: &[Vec2]) -> Vec<[Vec2; 3]> {
    triangulate(vertices)
        .into_iter()
        .map(|(a, b, c)| [vertices[a], vertices[b], vertices[c]])
        .collect()
}

/// Signed area of a polygon (positive = CCW, negative = CW).
#[must_use]
fn signed_area(vertices: &[Vec2]) -> f32 {
    let n = vertices.len();
    let mut area = 0.0f32;
    for i in 0..n {
        let j = (i + 1) % n;
        area += vertices[i].perp_dot(vertices[j]);
    }
    area * 0.5
}

/// Core ear-clipping loop.
fn ear_clip(
    vertices: &[Vec2],
    indices: &mut Vec<usize>,
    triangles: &mut Vec<(usize, usize, usize)>,
) {
    let mut remaining = indices.len();

    // Safety counter to prevent infinite loops on degenerate input
    let mut max_iter = remaining * remaining;

    let mut i = 0;
    while remaining > 3 && max_iter > 0 {
        max_iter -= 1;

        let prev = indices[wrap_idx(i as isize - 1, remaining)];
        let curr = indices[i % remaining];
        let next = indices[(i + 1) % remaining];

        if is_ear(vertices, indices, remaining, prev, curr, next) {
            triangles.push((prev, curr, next));
            indices.remove(i % remaining);
            remaining -= 1;
            // Don't advance i — the next vertex shifted into this slot
            if i >= remaining {
                i = 0;
            }
        } else {
            i = (i + 1) % remaining;
        }
    }

    // Last triangle
    if remaining == 3 {
        triangles.push((indices[0], indices[1], indices[2]));
    }
}

/// Check if vertex `curr` forms an ear (convex + no other vertex inside).
fn is_ear(
    vertices: &[Vec2],
    indices: &[usize],
    remaining: usize,
    prev: usize,
    curr: usize,
    next: usize,
) -> bool {
    let a = vertices[prev];
    let b = vertices[curr];
    let c = vertices[next];

    // Must be convex (CCW turn)
    let cross = (b - a).perp_dot(c - b);
    if cross <= 0.0 {
        return false;
    }

    // No other vertex inside this triangle
    for &idx in &indices[..remaining] {
        if idx == prev || idx == curr || idx == next {
            continue;
        }
        if point_in_triangle(vertices[idx], a, b, c) {
            return false;
        }
    }

    true
}

/// Check if point p is inside triangle (a, b, c) using barycentric coordinates.
#[inline]
fn point_in_triangle(p: Vec2, a: Vec2, b: Vec2, c: Vec2) -> bool {
    let v0 = c - a;
    let v1 = b - a;
    let v2 = p - a;

    let dot00 = v0.dot(v0);
    let dot01 = v0.dot(v1);
    let dot02 = v0.dot(v2);
    let dot11 = v1.dot(v1);
    let dot12 = v1.dot(v2);

    let denom = dot00 * dot11 - dot01 * dot01;
    if denom.abs() < f32::EPSILON {
        return false; // degenerate triangle (zero area)
    }
    let inv_denom = 1.0 / denom;
    let u = (dot11 * dot02 - dot01 * dot12) * inv_denom;
    let v = (dot00 * dot12 - dot01 * dot02) * inv_denom;

    u >= 0.0 && v >= 0.0 && (u + v) <= 1.0
}

/// Wrap an index for circular access.
#[inline]
fn wrap_idx(i: isize, len: usize) -> usize {
    ((i % len as isize) + len as isize) as usize % len
}

/// Merge a set of triangles into larger convex polygons.
///
/// Takes triangles as index triples into a vertex array and greedily merges
/// pairs that share an edge, as long as the result remains convex.
///
/// Returns polygons as lists of vertex indices (CCW order).
#[must_use]
pub fn merge_convex(vertices: &[Vec2], triangles: &[(usize, usize, usize)]) -> Vec<Vec<usize>> {
    if triangles.is_empty() {
        return Vec::new();
    }

    // Start with each triangle as a polygon
    let mut polys: Vec<Option<Vec<usize>>> = triangles
        .iter()
        .map(|&(a, b, c)| Some(vec![a, b, c]))
        .collect();

    // Build edge → polygon index map for shared-edge detection
    // Edge key: (min_vertex, max_vertex) → list of polygon indices
    let mut edge_map: std::collections::HashMap<(usize, usize), Vec<usize>> =
        std::collections::HashMap::new();

    for (pi, poly) in polys.iter().enumerate() {
        if let Some(verts) = poly {
            for i in 0..verts.len() {
                let j = (i + 1) % verts.len();
                let key = edge_key(verts[i], verts[j]);
                edge_map.entry(key).or_default().push(pi);
            }
        }
    }

    // Greedily merge pairs that share an edge
    let mut merged = true;
    while merged {
        merged = false;
        let keys: Vec<(usize, usize)> = edge_map.keys().copied().collect();

        for key in keys {
            let owners = match edge_map.get(&key) {
                Some(o) if o.len() == 2 => [o[0], o[1]],
                _ => continue,
            };

            let (pa, pb) = (owners[0], owners[1]);
            let (poly_a, poly_b) = match (polys[pa].as_ref(), polys[pb].as_ref()) {
                (Some(a), Some(b)) => (a.clone(), b.clone()),
                _ => continue,
            };

            if let Some(merged_poly) = try_merge(vertices, &poly_a, &poly_b, key) {
                // Remove old edges from map
                remove_poly_edges(&mut edge_map, &poly_a, pa);
                remove_poly_edges(&mut edge_map, &poly_b, pb);

                // Insert new polygon
                let new_idx = pa;
                polys[pa] = Some(merged_poly.clone());
                polys[pb] = None;

                // Add new polygon's edges to map
                for i in 0..merged_poly.len() {
                    let j = (i + 1) % merged_poly.len();
                    let ek = edge_key(merged_poly[i], merged_poly[j]);
                    edge_map.entry(ek).or_default().push(new_idx);
                }

                merged = true;
                break; // restart scan
            }
        }
    }

    polys.into_iter().flatten().collect()
}

/// Try to merge two polygons along a shared edge. Returns the merged polygon
/// if the result is convex, or None if it would be concave.
fn try_merge(
    vertices: &[Vec2],
    poly_a: &[usize],
    poly_b: &[usize],
    shared_edge: (usize, usize),
) -> Option<Vec<usize>> {
    let (ea, eb) = shared_edge;

    // Find shared edge position in poly_a (as consecutive pair)
    let a_len = poly_a.len();
    let edge_in_a = (0..a_len).find(|&i| {
        let j = (i + 1) % a_len;
        edge_key(poly_a[i], poly_a[j]) == (ea, eb)
    })?;
    let a_end = (edge_in_a + 1) % a_len;

    // Find shared edge position in poly_b
    let b_len = poly_b.len();
    let edge_in_b = (0..b_len).find(|&i| {
        let j = (i + 1) % b_len;
        edge_key(poly_b[i], poly_b[j]) == (ea, eb)
    })?;

    // Build merged polygon:
    // Walk poly_a: include all vertices from after shared-edge-end,
    // around back to shared-edge-start (inclusive).
    // Then walk poly_b: include non-shared vertices between the
    // shared edge endpoints.
    let mut result = Vec::with_capacity(a_len + b_len - 2);

    // poly_a: from vertex after shared edge's second endpoint,
    // around to shared edge's first endpoint (inclusive)
    {
        let mut ai = (a_end + 1) % a_len;
        loop {
            result.push(poly_a[ai]);
            if ai == edge_in_a {
                break;
            }
            ai = (ai + 1) % a_len;
        }
    }

    // poly_b: walk from after shared edge's second endpoint to
    // before shared edge's first endpoint (non-shared vertices only)
    {
        let b_end = (edge_in_b + 1) % b_len;
        let mut bi = (b_end + 1) % b_len;
        while bi != edge_in_b {
            result.push(poly_b[bi]);
            bi = (bi + 1) % b_len;
        }
    }

    // Include poly_a's shared edge second endpoint to close the seam
    result.push(poly_a[a_end]);

    if result.len() < 3 {
        return None;
    }

    if is_convex(vertices, &result) {
        Some(result)
    } else {
        None
    }
}

/// Check if a polygon (given as vertex indices) is convex.
fn is_convex(vertices: &[Vec2], indices: &[usize]) -> bool {
    let n = indices.len();
    if n < 3 {
        return false;
    }
    for i in 0..n {
        let a = vertices[indices[i]];
        let b = vertices[indices[(i + 1) % n]];
        let c = vertices[indices[(i + 2) % n]];
        if (b - a).perp_dot(c - b) < -f32::EPSILON {
            return false;
        }
    }
    true
}

/// Canonical edge key (min, max).
#[inline]
fn edge_key(a: usize, b: usize) -> (usize, usize) {
    if a <= b { (a, b) } else { (b, a) }
}

/// Remove a polygon's edges from the edge map.
fn remove_poly_edges(
    edge_map: &mut std::collections::HashMap<(usize, usize), Vec<usize>>,
    poly: &[usize],
    poly_idx: usize,
) {
    for i in 0..poly.len() {
        let j = (i + 1) % poly.len();
        let key = edge_key(poly[i], poly[j]);
        if let Some(owners) = edge_map.get_mut(&key) {
            owners.retain(|&x| x != poly_idx);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn triangle_passthrough() {
        let verts = vec![Vec2::ZERO, Vec2::new(1.0, 0.0), Vec2::new(0.5, 1.0)];
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 1);
    }

    #[test]
    fn square_two_triangles() {
        let verts = vec![
            Vec2::ZERO,
            Vec2::new(1.0, 0.0),
            Vec2::new(1.0, 1.0),
            Vec2::new(0.0, 1.0),
        ];
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 2);
    }

    #[test]
    fn pentagon() {
        // Regular pentagon (CCW)
        let verts: Vec<Vec2> = (0..5)
            .map(|i| {
                let angle = std::f32::consts::TAU * i as f32 / 5.0;
                Vec2::new(angle.cos(), angle.sin())
            })
            .collect();
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 3); // n-2 triangles
    }

    #[test]
    fn concave_l_shape() {
        // L-shaped polygon (6 vertices, CCW)
        let verts = vec![
            Vec2::new(0.0, 0.0),
            Vec2::new(2.0, 0.0),
            Vec2::new(2.0, 1.0),
            Vec2::new(1.0, 1.0),
            Vec2::new(1.0, 2.0),
            Vec2::new(0.0, 2.0),
        ];
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 4); // 6-2 = 4

        // All triangles should have positive area
        for (a, b, c) in &tris {
            let va = verts[*a];
            let vb = verts[*b];
            let vc = verts[*c];
            let area = (vb - va).perp_dot(vc - va);
            assert!(area > 0.0, "degenerate triangle: ({a},{b},{c})");
        }
    }

    #[test]
    fn cw_polygon_handled() {
        // CW square — should still triangulate correctly
        let verts = vec![
            Vec2::ZERO,
            Vec2::new(0.0, 1.0),
            Vec2::new(1.0, 1.0),
            Vec2::new(1.0, 0.0),
        ];
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 2);
    }

    #[test]
    fn degenerate_too_few() {
        assert!(triangulate(&[]).is_empty());
        assert!(triangulate(&[Vec2::ZERO]).is_empty());
        assert!(triangulate(&[Vec2::ZERO, Vec2::ONE]).is_empty());
    }

    #[test]
    fn triangulate_points_returns_vertices() {
        let verts = vec![
            Vec2::ZERO,
            Vec2::new(1.0, 0.0),
            Vec2::new(1.0, 1.0),
            Vec2::new(0.0, 1.0),
        ];
        let tris = triangulate_points(&verts);
        assert_eq!(tris.len(), 2);
        // Each triangle should have 3 vertices from the original set
        for tri in &tris {
            for v in tri {
                assert!(verts.contains(v));
            }
        }
    }

    #[test]
    fn all_indices_valid() {
        let verts = vec![
            Vec2::new(0.0, 0.0),
            Vec2::new(3.0, 0.0),
            Vec2::new(3.0, 1.0),
            Vec2::new(2.0, 1.0),
            Vec2::new(2.0, 2.0),
            Vec2::new(0.0, 2.0),
        ];
        let tris = triangulate(&verts);
        for (a, b, c) in &tris {
            assert!(*a < verts.len());
            assert!(*b < verts.len());
            assert!(*c < verts.len());
        }
    }

    #[test]
    fn large_convex_polygon() {
        // 20-gon
        let verts: Vec<Vec2> = (0..20)
            .map(|i| {
                let angle = std::f32::consts::TAU * i as f32 / 20.0;
                Vec2::new(angle.cos() * 10.0, angle.sin() * 10.0)
            })
            .collect();
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 18); // n-2
    }

    // --- Merge convex tests ---

    #[test]
    fn merge_square_triangles() {
        // Two triangles forming a square should merge into one quad
        let verts = vec![
            Vec2::ZERO,
            Vec2::new(1.0, 0.0),
            Vec2::new(1.0, 1.0),
            Vec2::new(0.0, 1.0),
        ];
        let tris = triangulate(&verts);
        let merged = merge_convex(&verts, &tris);

        // Should merge into 1 convex polygon (the original square)
        assert_eq!(merged.len(), 1);
        assert_eq!(merged[0].len(), 4);
    }

    #[test]
    fn merge_concave_stays_split() {
        // L-shape: triangles shouldn't all merge (result would be concave)
        let verts = vec![
            Vec2::new(0.0, 0.0),
            Vec2::new(2.0, 0.0),
            Vec2::new(2.0, 1.0),
            Vec2::new(1.0, 1.0),
            Vec2::new(1.0, 2.0),
            Vec2::new(0.0, 2.0),
        ];
        let tris = triangulate(&verts);
        let merged = merge_convex(&verts, &tris);

        // Should have fewer polygons than triangles but more than 1
        assert!(merged.len() < tris.len());
        assert!(!merged.is_empty());

        // All resulting polygons should be convex
        for poly in &merged {
            assert!(is_convex(&verts, poly), "non-convex merged polygon");
        }
    }

    #[test]
    fn merge_empty() {
        let merged = merge_convex(&[], &[]);
        assert!(merged.is_empty());
    }

    #[test]
    fn merge_single_triangle() {
        let verts = vec![Vec2::ZERO, Vec2::new(1.0, 0.0), Vec2::new(0.5, 1.0)];
        let tris = vec![(0, 1, 2)];
        let merged = merge_convex(&verts, &tris);
        assert_eq!(merged.len(), 1);
        assert_eq!(merged[0].len(), 3);
    }

    #[test]
    fn merge_convex_polygon_fully_merges() {
        // Regular hexagon → 4 triangles → should merge back to ≤2 convex polygons
        let verts: Vec<Vec2> = (0..6)
            .map(|i| {
                let angle = std::f32::consts::TAU * i as f32 / 6.0;
                Vec2::new(angle.cos(), angle.sin())
            })
            .collect();
        let tris = triangulate(&verts);
        assert_eq!(tris.len(), 4);

        let merged = merge_convex(&verts, &tris);
        // Hexagon is convex, so should merge significantly
        assert!(merged.len() <= 2);
    }
}

//! 3D navigation volumes — voxel-based pathfinding for flying/swimming agents.

use std::cmp::Ordering;
use std::collections::BinaryHeap;

use hisab::Vec3;
use serde::{Deserialize, Serialize};

#[cfg(feature = "logging")]
use tracing::instrument;

/// A position in the voxel grid.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
pub struct VoxelPos {
    pub x: i32,
    pub y: i32,
    pub z: i32,
}

impl VoxelPos {
    #[must_use]
    pub fn new(x: i32, y: i32, z: i32) -> Self {
        Self { x, y, z }
    }

    /// Chebyshev distance (diagonal movement in 3D).
    #[inline]
    #[must_use]
    pub fn chebyshev_distance(self, other: VoxelPos) -> i32 {
        let dx = (self.x - other.x).abs();
        let dy = (self.y - other.y).abs();
        let dz = (self.z - other.z).abs();
        dx.max(dy).max(dz)
    }

    /// Octile-like 3D distance heuristic.
    #[inline]
    #[must_use]
    pub fn distance_3d(self, other: VoxelPos) -> f32 {
        let dx = (self.x - other.x).abs() as f32;
        let dy = (self.y - other.y).abs() as f32;
        let dz = (self.z - other.z).abs() as f32;
        let mut sorted = [dx, dy, dz];
        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap_or(Ordering::Equal));
        // smallest + (sqrt(2)-1)*middle + (sqrt(3)-sqrt(2))*largest... simplified:
        sorted[2]
            + (std::f32::consts::SQRT_2 - 1.0) * sorted[1]
            + (3.0f32.sqrt() - std::f32::consts::SQRT_2) * sorted[0]
    }
}

/// A 3D navigation volume (voxel grid).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct NavVolume {
    width: usize,
    height: usize,
    depth: usize,
    cell_size: f32,
    /// Bit-packed navigability (1 = navigable).
    navigable: Vec<u64>,
    /// Per-cell cost multiplier.
    costs: Vec<f32>,
}

impl NavVolume {
    /// Create a new volume where all cells are navigable.
    #[must_use]
    pub fn new(width: usize, height: usize, depth: usize, cell_size: f32) -> Self {
        let len = width * height * depth;
        let bitset_len = len.div_ceil(64);
        Self {
            width,
            height,
            depth,
            cell_size,
            navigable: vec![u64::MAX; bitset_len],
            costs: vec![1.0; len],
        }
    }

    #[must_use]
    pub fn width(&self) -> usize {
        self.width
    }
    #[must_use]
    pub fn height(&self) -> usize {
        self.height
    }
    #[must_use]
    pub fn depth(&self) -> usize {
        self.depth
    }
    #[must_use]
    pub fn cell_size(&self) -> f32 {
        self.cell_size
    }

    /// Set whether a cell is navigable.
    pub fn set_navigable(&mut self, x: i32, y: i32, z: i32, nav: bool) {
        if let Some(idx) = self.index(x, y, z) {
            let word = idx / 64;
            let bit = idx % 64;
            if nav {
                self.navigable[word] |= 1u64 << bit;
            } else {
                self.navigable[word] &= !(1u64 << bit);
            }
        }
    }

    /// Check if a cell is navigable.
    #[inline]
    #[must_use]
    pub fn is_navigable(&self, x: i32, y: i32, z: i32) -> bool {
        self.index(x, y, z)
            .map(|idx| (self.navigable[idx / 64] >> (idx % 64)) & 1 == 1)
            .unwrap_or(false)
    }

    /// Set the traversal cost for a cell.
    pub fn set_cost(&mut self, x: i32, y: i32, z: i32, cost: f32) {
        if let Some(idx) = self.index(x, y, z) {
            self.costs[idx] = cost;
        }
    }

    /// Get the traversal cost of a cell.
    #[must_use]
    pub fn cost(&self, x: i32, y: i32, z: i32) -> f32 {
        self.index(x, y, z)
            .map(|i| self.costs[i])
            .unwrap_or(f32::INFINITY)
    }

    /// Convert voxel position to world position (center of cell).
    #[must_use]
    pub fn voxel_to_world(&self, pos: VoxelPos) -> Vec3 {
        Vec3::new(
            (pos.x as f32 + 0.5) * self.cell_size,
            (pos.y as f32 + 0.5) * self.cell_size,
            (pos.z as f32 + 0.5) * self.cell_size,
        )
    }

    /// Convert world position to voxel position.
    #[must_use]
    pub fn world_to_voxel(&self, world: Vec3) -> VoxelPos {
        VoxelPos::new(
            (world.x / self.cell_size).floor() as i32,
            (world.y / self.cell_size).floor() as i32,
            (world.z / self.cell_size).floor() as i32,
        )
    }

    /// Find a path using 3D A*.
    ///
    /// Supports 26-connected neighbors (cardinal + diagonal + vertical).
    #[cfg_attr(feature = "logging", instrument(skip(self)))]
    #[must_use]
    pub fn find_path(&self, start: VoxelPos, goal: VoxelPos) -> Option<Vec<VoxelPos>> {
        if !self.is_navigable(start.x, start.y, start.z)
            || !self.is_navigable(goal.x, goal.y, goal.z)
        {
            return None;
        }
        if start == goal {
            return Some(vec![start]);
        }

        let len = self.width * self.height * self.depth;
        let mut g_score = vec![f32::INFINITY; len];
        let mut came_from: Vec<Option<usize>> = vec![None; len];
        let mut closed = vec![false; len];
        let mut open = BinaryHeap::new();

        let start_idx = self.index(start.x, start.y, start.z)?;
        let goal_idx = self.index(goal.x, goal.y, goal.z)?;

        g_score[start_idx] = 0.0;
        open.push(VoxelNode {
            idx: start_idx,
            f_score: start.distance_3d(goal),
        });

        while let Some(current) = open.pop() {
            if current.idx == goal_idx {
                return Some(self.reconstruct_path(&came_from, goal_idx));
            }
            if closed[current.idx] {
                continue;
            }
            closed[current.idx] = true;

            let cx = (current.idx % self.width) as i32;
            let cy = ((current.idx / self.width) % self.height) as i32;
            let cz = (current.idx / (self.width * self.height)) as i32;

            // 26-connected neighbors
            for dz in -1..=1i32 {
                for dy in -1..=1i32 {
                    for dx in -1..=1i32 {
                        if dx == 0 && dy == 0 && dz == 0 {
                            continue;
                        }
                        let nx = cx + dx;
                        let ny = cy + dy;
                        let nz = cz + dz;
                        if !self.is_navigable(nx, ny, nz) {
                            continue;
                        }

                        let n_idx = match self.index(nx, ny, nz) {
                            Some(i) => i,
                            None => continue,
                        };
                        if closed[n_idx] {
                            continue;
                        }

                        let move_dist = match dx.abs() + dy.abs() + dz.abs() {
                            1 => 1.0,
                            2 => std::f32::consts::SQRT_2,
                            _ => 3.0f32.sqrt(), // 3D diagonal
                        };
                        let tentative_g = g_score[current.idx] + move_dist * self.costs[n_idx];

                        if tentative_g < g_score[n_idx] {
                            came_from[n_idx] = Some(current.idx);
                            g_score[n_idx] = tentative_g;
                            let np = VoxelPos::new(nx, ny, nz);
                            let h = np.distance_3d(goal);
                            open.push(VoxelNode {
                                idx: n_idx,
                                f_score: tentative_g + h,
                            });
                        }
                    }
                }
            }
        }

        None
    }

    #[inline]
    fn index(&self, x: i32, y: i32, z: i32) -> Option<usize> {
        if x >= 0
            && y >= 0
            && z >= 0
            && (x as usize) < self.width
            && (y as usize) < self.height
            && (z as usize) < self.depth
        {
            Some(z as usize * self.width * self.height + y as usize * self.width + x as usize)
        } else {
            None
        }
    }

    fn reconstruct_path(&self, came_from: &[Option<usize>], goal_idx: usize) -> Vec<VoxelPos> {
        let mut path = Vec::new();
        let mut current = goal_idx;
        let plane = self.width * self.height;
        loop {
            let x = (current % self.width) as i32;
            let y = ((current / self.width) % self.height) as i32;
            let z = (current / plane) as i32;
            path.push(VoxelPos::new(x, y, z));
            match came_from[current] {
                Some(p) => current = p,
                None => break,
            }
        }
        path.reverse();
        path
    }
}

#[derive(Clone, Copy)]
struct VoxelNode {
    idx: usize,
    f_score: f32,
}

impl PartialEq for VoxelNode {
    fn eq(&self, o: &Self) -> bool {
        self.f_score == o.f_score
    }
}

impl Eq for VoxelNode {}

impl PartialOrd for VoxelNode {
    fn partial_cmp(&self, o: &Self) -> Option<Ordering> {
        Some(self.cmp(o))
    }
}

impl Ord for VoxelNode {
    fn cmp(&self, o: &Self) -> Ordering {
        o.f_score
            .partial_cmp(&self.f_score)
            .unwrap_or(Ordering::Equal)
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn basic_3d_path() {
        let vol = NavVolume::new(10, 10, 10, 1.0);
        let path = vol.find_path(VoxelPos::new(0, 0, 0), VoxelPos::new(5, 5, 5));
        assert!(path.is_some());
        let path = path.unwrap();
        assert_eq!(*path.first().unwrap(), VoxelPos::new(0, 0, 0));
        assert_eq!(*path.last().unwrap(), VoxelPos::new(5, 5, 5));
    }

    #[test]
    fn same_start_goal() {
        let vol = NavVolume::new(5, 5, 5, 1.0);
        let path = vol.find_path(VoxelPos::new(2, 2, 2), VoxelPos::new(2, 2, 2));
        assert_eq!(path, Some(vec![VoxelPos::new(2, 2, 2)]));
    }

    #[test]
    fn blocked_path() {
        let mut vol = NavVolume::new(3, 1, 1, 1.0);
        // Block the middle cell
        vol.set_navigable(1, 0, 0, false);
        let path = vol.find_path(VoxelPos::new(0, 0, 0), VoxelPos::new(2, 0, 0));
        // 1D grid with blocked middle: no path
        assert!(path.is_none());
    }

    #[test]
    fn vertical_movement() {
        let vol = NavVolume::new(1, 1, 5, 1.0);
        let path = vol.find_path(VoxelPos::new(0, 0, 0), VoxelPos::new(0, 0, 4));
        assert!(path.is_some());
        let path = path.unwrap();
        assert_eq!(path.len(), 5); // straight line through z
        for (i, pos) in path.iter().enumerate() {
            assert_eq!(pos.x, 0);
            assert_eq!(pos.y, 0);
            assert_eq!(pos.z, i as i32);
        }
    }

    #[test]
    fn not_navigable_start_goal() {
        let mut vol = NavVolume::new(5, 5, 5, 1.0);
        vol.set_navigable(0, 0, 0, false);
        // Start not navigable
        assert!(
            vol.find_path(VoxelPos::new(0, 0, 0), VoxelPos::new(4, 4, 4))
                .is_none()
        );

        let mut vol2 = NavVolume::new(5, 5, 5, 1.0);
        vol2.set_navigable(4, 4, 4, false);
        // Goal not navigable
        assert!(
            vol2.find_path(VoxelPos::new(0, 0, 0), VoxelPos::new(4, 4, 4))
                .is_none()
        );
    }

    #[test]
    fn world_voxel_conversion_roundtrip() {
        let vol = NavVolume::new(10, 10, 10, 2.0);
        let pos = VoxelPos::new(3, 5, 7);
        let world = vol.voxel_to_world(pos);
        let back = vol.world_to_voxel(world);
        assert_eq!(back, pos);
    }

    #[test]
    fn serde_roundtrip() {
        let mut vol = NavVolume::new(4, 4, 4, 0.5);
        vol.set_navigable(1, 1, 1, false);
        vol.set_cost(2, 2, 2, 3.0);

        let json = serde_json::to_string(&vol).unwrap();
        let deserialized: NavVolume = serde_json::from_str(&json).unwrap();
        assert_eq!(deserialized.width(), 4);
        assert_eq!(deserialized.height(), 4);
        assert_eq!(deserialized.depth(), 4);
        assert!(!deserialized.is_navigable(1, 1, 1));
        assert!(deserialized.is_navigable(0, 0, 0));
        assert!((deserialized.cost(2, 2, 2) - 3.0).abs() < f32::EPSILON);
    }
}
